fn parse_frontmatter_value(content: &str, key: &str) -> Option<String> {
    let stripped = content.strip_prefix("---")?;
    let end = stripped.find("---")?;
    let frontmatter = &stripped[..end];
    frontmatter.lines().find_map(|line| {
        let trimmed = line.trim();
        let prefix = format!("{key}:");
        trimmed
            .strip_prefix(&prefix)
            .map(|value| {
                value
                    .trim()
                    .trim_matches('"')
                    .trim_matches('\'')
                    .to_string()
            })
            .filter(|value| !value.is_empty())
    })
}

fn sanitize_shell_snippet_line(raw: &str) -> String {
    raw.trim()
        .trim_start_matches("$ ")
        .trim_start_matches("PS> ")
        .trim_start_matches("> ")
        .trim()
        .to_string()
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum InstallSectionPreference {
    Neutral,
    Preferred,
    Other,
}

fn is_external_cli_skill_candidate(content: &str) -> bool {
    let lower = content.to_ascii_lowercase();
    lower.contains("install & update") || lower.contains("## install")
}

fn classify_install_section_preference(lower_heading: &str) -> InstallSectionPreference {
    let mentions_windows = lower_heading.contains("windows");
    let mentions_unix = lower_heading.contains("linux")
        || lower_heading.contains("macos")
        || lower_heading.contains("mac os")
        || lower_heading.contains("unix");
    if !(mentions_windows || mentions_unix) {
        return InstallSectionPreference::Neutral;
    }

    let preferred = if cfg!(windows) {
        mentions_windows
    } else {
        mentions_unix
    };
    if preferred {
        InstallSectionPreference::Preferred
    } else {
        InstallSectionPreference::Other
    }
}

fn line_looks_like_cross_platform_install_command(lower: &str) -> bool {
    [
        "npm ",
        "npx ",
        "pnpm ",
        "yarn ",
        "pip ",
        "pip3 ",
        "pipx ",
        "python -m pip ",
        "python3 -m pip ",
        "uv tool ",
        "uvx ",
        "cargo install ",
        "go install ",
        "dotnet tool install ",
        "gem install ",
    ]
    .iter()
    .any(|prefix| lower.starts_with(prefix))
}

fn line_looks_like_windows_install_command(lower: &str) -> bool {
    [
        "irm ",
        "iwr ",
        "invoke-webrequest ",
        "powershell ",
        "pwsh ",
        "cmd ",
        "winget ",
        "scoop ",
        "choco ",
    ]
    .iter()
    .any(|prefix| lower.starts_with(prefix))
        || lower.contains("powershell")
}

fn line_looks_like_unix_install_command(lower: &str) -> bool {
    let lower = lower.strip_prefix("sudo ").unwrap_or(lower);
    [
        "curl ",
        "wget ",
        "bash ",
        "sh ",
        "apt ",
        "apt-get ",
        "yum ",
        "dnf ",
        "apk ",
        "pacman ",
        "zypper ",
        "./",
        "chmod ",
    ]
    .iter()
    .any(|prefix| lower.starts_with(prefix))
        || lower.contains("| bash")
        || lower.contains("| sh")
}

fn line_looks_like_platform_install_command(lower: &str) -> bool {
    line_looks_like_cross_platform_install_command(lower)
        || if cfg!(windows) {
            line_looks_like_windows_install_command(lower)
        } else {
            line_looks_like_unix_install_command(lower)
        }
}

fn external_cli_skill_missing_platform_install_message() -> &'static str {
    if cfg!(windows) {
        "This CLI skill is missing a compatible Windows install command or required `name` frontmatter. Add a Windows or PowerShell command under its Install section."
    } else {
        "This CLI skill is missing a compatible Linux/macOS install command or required `name` frontmatter. Add a shell command under its Install section."
    }
}

fn select_platform_install_command_from_block(block: &str) -> Option<String> {
    let mut section_preference = InstallSectionPreference::Neutral;
    let mut fallback: Option<String> = None;
    for raw_line in block.lines() {
        let line = sanitize_shell_snippet_line(raw_line);
        if line.is_empty() {
            continue;
        }
        let lower = line.to_ascii_lowercase();
        if lower.starts_with('#') {
            section_preference = classify_install_section_preference(&lower);
            continue;
        }

        match section_preference {
            InstallSectionPreference::Preferred => return Some(line),
            InstallSectionPreference::Other => continue,
            InstallSectionPreference::Neutral => {}
        }

        if fallback.is_none() && line_looks_like_platform_install_command(&lower) {
            fallback = Some(line.clone());
        }
    }

    fallback
}

fn extract_install_command_from_skill_markdown(content: &str) -> Option<String> {
    let re = Regex::new(r"(?s)```[^\n`]*\n(.*?)```").ok()?;
    for cap in re.captures_iter(content) {
        let block = cap.get(1).map(|value| value.as_str()).unwrap_or_default();
        if let Some(command) = select_platform_install_command_from_block(block) {
            return Some(command);
        }
    }
    None
}

fn extract_verify_command_from_skill_markdown(content: &str, executable_name: &str) -> String {
    if let Ok(re) = Regex::new(r#"(?is)verify:\s*`([^`]+)`"#) {
        if let Some(command) = re
            .captures(content)
            .and_then(|cap| cap.get(1).map(|value| value.as_str().trim().to_string()))
            .filter(|value| !value.is_empty())
        {
            return command;
        }
    }
    format!("{} --version", executable_name)
}

fn has_explicit_verify_command_in_skill_markdown(content: &str) -> bool {
    Regex::new(r#"(?is)verify:\s*`([^`]+)`"#)
        .ok()
        .is_some_and(|re| re.is_match(content))
}

fn shellish_split(command: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut current = String::new();
    let mut in_single = false;
    let mut in_double = false;

    for ch in command.chars() {
        match ch {
            '\'' if !in_double => {
                in_single = !in_single;
            }
            '"' if !in_single => {
                in_double = !in_double;
            }
            c if c.is_whitespace() && !in_single && !in_double => {
                if !current.is_empty() {
                    out.push(std::mem::take(&mut current));
                }
            }
            _ => current.push(ch),
        }
    }

    if !current.is_empty() {
        out.push(current);
    }
    out
}

fn detect_external_cli_skill_spec(content: &str) -> Option<ExternalCliSkillSpec> {
    if !is_external_cli_skill_candidate(content) {
        return None;
    }

    let install_command = extract_install_command_from_skill_markdown(content)?;
    let name = sanitize_skill_name(&parse_frontmatter_value(content, "name")?);
    if name.is_empty() {
        return None;
    }
    let description = parse_frontmatter_value(content, "description")
        .unwrap_or_else(|| format!("Installed CLI skill '{}'", name));
    let version =
        parse_frontmatter_value(content, "version").unwrap_or_else(|| "1.0.0".to_string());
    let verify_command = extract_verify_command_from_skill_markdown(content, &name);
    let executable_name = shellish_split(&verify_command)
        .into_iter()
        .next()
        .map(|value| value.trim_matches('`').to_string())
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| name.clone());

    Some(ExternalCliSkillSpec {
        name,
        description,
        version,
        install_command,
        verify_command,
        executable_name,
    })
}

fn normalize_preference_subject(subject: &str) -> Option<String> {
    let cleaned = subject
        .trim()
        .trim_matches(|c: char| {
            matches!(
                c,
                '"' | '\'' | '`' | '.' | ',' | ';' | ':' | '!' | '?' | '(' | ')' | '[' | ']'
            )
        })
        .trim();
    if cleaned.is_empty() {
        return None;
    }

    let lower = cleaned.to_ascii_lowercase();
    if lower.starts_with("http://") || lower.starts_with("https://") {
        return None;
    }
    let without_article = lower
        .strip_prefix("the ")
        .or_else(|| lower.strip_prefix("a "))
        .or_else(|| lower.strip_prefix("an "))
        .unwrap_or(&lower)
        .trim();
    if without_article.is_empty() || without_article.len() > 64 {
        return None;
    }
    let token_count = without_article.split_whitespace().count();
    if token_count == 0 || token_count > 6 {
        return None;
    }

    Some(
        cleaned
            .trim_start_matches(|c: char| c.is_whitespace())
            .trim_matches(|c: char| matches!(c, '"' | '\'' | '`'))
            .to_string(),
    )
}

fn preference_subject_slug(subject: &str) -> String {
    let mut out = String::with_capacity(subject.len());
    let mut prev_sep = false;
    for ch in subject.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
            prev_sep = false;
        } else if !prev_sep {
            out.push('_');
            prev_sep = true;
        }
    }
    out.trim_matches('_').to_string()
}

fn extract_stable_user_preferences(message: &str) -> Vec<(String, String)> {
    let splitter = regex::Regex::new(r"(?i)\s*(?:\band\b|\bbut\b|[;\n]+)\s*").ok();
    let clauses: Vec<&str> = if let Some(re) = splitter.as_ref() {
        re.split(message).collect()
    } else {
        vec![message]
    };

    let positive_prefixes = [
        "i love ",
        "i really love ",
        "i like ",
        "i really like ",
        "i prefer ",
        "i'm into ",
        "i am into ",
    ];
    let positive_followup_prefixes = ["love ", "really love ", "like ", "really like ", "prefer "];
    let negative_prefixes = [
        "i hate ",
        "i really hate ",
        "i dislike ",
        "i don't like ",
        "i do not like ",
        "i can't stand ",
    ];
    let negative_followup_prefixes = [
        "hate ",
        "really hate ",
        "dislike ",
        "don't like ",
        "do not like ",
        "can't stand ",
    ];

    let mut seen = HashSet::new();
    let mut out = Vec::new();
    for clause in clauses {
        let trimmed = clause.trim();
        if trimmed.is_empty() {
            continue;
        }
        let lower = trimmed.to_ascii_lowercase();
        let sentiment = if let Some(prefix) = positive_prefixes
            .iter()
            .find(|prefix| lower.starts_with(**prefix))
        {
            Some(("likes", *prefix))
        } else if let Some(prefix) = positive_followup_prefixes
            .iter()
            .find(|prefix| lower.starts_with(**prefix))
        {
            Some(("likes", *prefix))
        } else if let Some(prefix) = negative_prefixes
            .iter()
            .find(|prefix| lower.starts_with(**prefix))
        {
            Some(("dislikes", *prefix))
        } else {
            negative_followup_prefixes
                .iter()
                .find(|prefix| lower.starts_with(**prefix))
                .map(|prefix| ("dislikes", *prefix))
        };
        let Some((sentiment_key, prefix)) = sentiment else {
            continue;
        };
        let subject = trimmed[prefix.len()..].trim();
        let Some(normalized_subject) = normalize_preference_subject(subject) else {
            continue;
        };
        let slug = preference_subject_slug(&normalized_subject);
        if slug.is_empty() {
            continue;
        }
        let key = format!("{}_{}", sentiment_key, slug);
        if !seen.insert(key.clone()) {
            continue;
        }
        out.push((key, normalized_subject));
    }
    out
}

fn normalize_user_name_candidate(raw: &str) -> Option<String> {
    let cleaned = raw
        .trim()
        .trim_matches(|c: char| matches!(c, '"' | '\'' | '`'))
        .trim_end_matches(['.', '!', '?'])
        .trim();
    if cleaned.is_empty() || cleaned.len() > 64 {
        return None;
    }

    let tokens: Vec<&str> = cleaned.split_whitespace().collect();
    if tokens.is_empty() || tokens.len() > 4 {
        return None;
    }
    if !tokens.iter().all(|token| {
        token
            .chars()
            .all(|ch| ch.is_alphabetic() || matches!(ch, '\'' | '-' | '.'))
    }) {
        return None;
    }

    let normalized = if cleaned.chars().any(|ch| ch.is_uppercase()) {
        cleaned.to_string()
    } else {
        tokens
            .iter()
            .map(|token| {
                let mut chars = token.chars();
                match chars.next() {
                    Some(first) => format!(
                        "{}{}",
                        first.to_uppercase(),
                        chars.as_str().to_ascii_lowercase()
                    ),
                    None => String::new(),
                }
            })
            .collect::<Vec<_>>()
            .join(" ")
    };

    Some(normalized)
}

fn extract_explicit_user_identity_facts(message: &str) -> Vec<(String, String)> {
    let patterns = [
        r"(?i)\bmy name is\s+([^\n,;.!?]+)",
        r"(?i)\byou can call me\s+([^\n,;.!?]+)",
        r"(?i)\bcall me\s+([^\n,;.!?]+)",
        r"(?i)\bi go by\s+([^\n,;.!?]+)",
    ];

    let mut out = Vec::new();
    let mut seen = HashSet::new();
    for pattern in patterns {
        let Ok(re) = regex::Regex::new(pattern) else {
            continue;
        };
        for caps in re.captures_iter(message) {
            let Some(candidate) = caps.get(1).map(|m| m.as_str()) else {
                continue;
            };
            let Some(name) = normalize_user_name_candidate(candidate) else {
                continue;
            };
            if seen.insert(name.to_ascii_lowercase()) {
                out.push(("user_name".to_string(), name));
            }
        }
    }

    out
}

fn format_saved_user_preference_for_prompt(
    pref: &crate::storage::entities::user_preference::Model,
) -> String {
    let value = safe_truncate(&pref.value, 160);
    match pref.key.as_str() {
        "rule_require_explicit_approval_before_side_effects" => {
            "- hard rule: require explicit approval before side-effecting actions".to_string()
        }
        "rule_show_plan_before_side_effects" => {
            "- hard rule: show the plan before side-effecting actions".to_string()
        }
        "user_name" => format!("- name: {}", value),
        key if key.starts_with("likes_") => format!("- likes: {}", value),
        key if key.starts_with("dislikes_") => format!("- dislikes: {}", value),
        _ => format!("- {}: {}", pref.key, value),
    }
}

fn user_preference_prompt_priority(key: &str) -> u8 {
    match key {
        "rule_require_explicit_approval_before_side_effects" => 0,
        "rule_show_plan_before_side_effects" => 1,
        "user_name" => 2,
        _ => 3,
    }
}

fn parse_boolish_user_preference(value: &str) -> bool {
    matches!(
        value.trim().to_ascii_lowercase().as_str(),
        "1" | "true" | "yes" | "on" | "required"
    )
}

fn normalize_user_fact_key(raw: &str) -> Option<String> {
    let key = raw
        .trim()
        .to_ascii_lowercase()
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '_' {
                ch
            } else {
                '_'
            }
        })
        .collect::<String>()
        .trim_matches('_')
        .to_string();
    if key.is_empty() || key.len() > 80 {
        return None;
    }
    Some(key)
}

fn normalize_user_fact_value(raw: &str) -> Option<String> {
    let value = raw
        .trim()
        .trim_matches(|c: char| matches!(c, '"' | '\'' | '`'));
    if value.is_empty() || value.len() > 160 {
        return None;
    }
    Some(value.to_string())
}

fn parse_skill_run_intent(
    message: &str,
    actions: &[crate::actions::ActionDef],
) -> Option<SkillRunIntent> {
    use crate::actions::ActionSource;

    let mut skill_names: Vec<String> = actions
        .iter()
        .filter(|a| a.source != ActionSource::System)
        .map(|a| a.name.to_ascii_lowercase())
        .collect();
    if skill_names.is_empty() {
        return None;
    }

    // Prefer longest names first so "my-skill-pro" wins over "my-skill".
    skill_names.sort_by_key(|value| std::cmp::Reverse(value.len()));
    skill_names.dedup();

    let mut canonical_by_lower: HashMap<String, String> = HashMap::new();
    for action in actions {
        if action.source != ActionSource::System {
            canonical_by_lower.insert(action.name.to_ascii_lowercase(), action.name.clone());
        }
    }

    let trimmed = message.trim();
    if trimmed.is_empty() {
        return None;
    }

    if let Some(rest) = trimmed.strip_prefix("/run ") {
        let mut parts = rest.trim().splitn(2, char::is_whitespace);
        let raw_name = parts.next().unwrap_or("").trim();
        if raw_name.is_empty() {
            return None;
        }
        let normalized = sanitize_skill_name(raw_name);
        let canonical = canonical_by_lower
            .get(&normalized)
            .cloned()
            .unwrap_or(normalized);
        let query = parts
            .next()
            .map(|s| s.trim().to_string())
            .unwrap_or_default();
        return Some(SkillRunIntent {
            skill_name: canonical,
            query,
        });
    }

    let lower = trimmed
        .to_ascii_lowercase()
        .replace("calender", "calendar")
        .replace('_', "-");
    let has_run_verb = ["run ", "call ", "use ", "invoke ", "execute ", "start "]
        .iter()
        .any(|v| lower.contains(v));
    if !has_run_verb {
        return None;
    }

    for skill in &skill_names {
        let patterns = [
            format!("run {}", skill),
            format!("call {}", skill),
            format!("use {}", skill),
            format!("invoke {}", skill),
            format!("execute {}", skill),
            format!("start {}", skill),
            format!("run the {} skill", skill),
            format!("call the {} skill", skill),
            format!("use the {} skill", skill),
        ];
        if !patterns.iter().any(|p| lower.contains(p)) {
            continue;
        }

        let Some(name_pos) = lower.find(skill) else {
            continue;
        };
        let after_idx = name_pos.saturating_add(skill.len());
        let mut query = trimmed
            .get(after_idx..)
            .unwrap_or("")
            .trim_start_matches(|c: char| c.is_whitespace() || ",:-".contains(c))
            .to_string();
        for prefix in ["and ", "to "] {
            if query.to_ascii_lowercase().starts_with(prefix) {
                query = query[prefix.len()..].trim_start().to_string();
            }
        }

        let canonical = canonical_by_lower
            .get(skill)
            .cloned()
            .unwrap_or_else(|| skill.clone());
        return Some(SkillRunIntent {
            skill_name: canonical,
            query,
        });
    }

    None
}

fn tokenize_lower(text: &str) -> Vec<String> {
    text.to_lowercase()
        .split(|c: char| !c.is_alphanumeric())
        .filter(|w| w.len() >= 3)
        .map(|w| w.to_string())
        .collect()
}

fn keyword_overlap_score(text: &str, query_tokens: &[String]) -> usize {
    if query_tokens.is_empty() {
        return 0;
    }
    let hay = text.to_ascii_lowercase();
    query_tokens
        .iter()
        .filter(|token| hay.contains(token.as_str()))
        .count()
}

fn moltbook_action_kind(sub_action: &str) -> &'static str {
    match sub_action {
        "feed" | "search" | "status" | "me" => "read",
        "create_post" | "comment" | "upvote_post" => "write",
        "register" => "setup",
        _ => "other",
    }
}

fn push_labeled_url(
    urls: &mut Vec<serde_json::Value>,
    seen: &mut HashSet<String>,
    label: &str,
    url: &str,
) {
    if !url.starts_with("http://") && !url.starts_with("https://") {
        return;
    }
    let key = format!("{}|{}", label, url);
    if !seen.insert(key) {
        return;
    }
    urls.push(serde_json::json!({
        "label": label,
        "url": url
    }));
}

fn collect_moltbook_urls(
    sub_action: &str,
    args: &serde_json::Value,
    result: Option<&serde_json::Value>,
) -> Vec<serde_json::Value> {
    let mut urls: Vec<serde_json::Value> = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();
    let base_api = "https://www.moltbook.com/api/v1";

    match sub_action {
        "register" => {
            push_labeled_url(
                &mut urls,
                &mut seen,
                "API register",
                "https://www.moltbook.com/api/v1/agents/register",
            );
            if let Some(claim_url) = result
                .and_then(|r| r.get("claim_url"))
                .and_then(|v| v.as_str())
            {
                push_labeled_url(&mut urls, &mut seen, "Claim URL", claim_url);
            }
        }
        "status" => {
            push_labeled_url(
                &mut urls,
                &mut seen,
                "API status",
                "https://www.moltbook.com/api/v1/agents/status",
            );
        }
        "me" => {
            push_labeled_url(
                &mut urls,
                &mut seen,
                "API me",
                "https://www.moltbook.com/api/v1/agents/me",
            );
        }
        "feed" => {
            let sort = args.get("sort").and_then(|v| v.as_str()).unwrap_or("new");
            let limit = args
                .get("limit")
                .and_then(|v| v.as_u64())
                .unwrap_or(10)
                .min(25);
            let feed_url = format!("{}/feed?sort={}&limit={}", base_api, sort, limit);
            push_labeled_url(&mut urls, &mut seen, "API feed", &feed_url);
            if let Some(posts) = result
                .and_then(|r| r.get("posts"))
                .and_then(|v| v.as_array())
            {
                for (idx, post) in posts.iter().take(10).enumerate() {
                    if let Some(post_id) = post.get("id").and_then(|v| v.as_str()) {
                        let api_url = format!("{}/posts/{}", base_api, post_id);
                        push_labeled_url(
                            &mut urls,
                            &mut seen,
                            &format!("Read API #{}", idx + 1),
                            &api_url,
                        );
                    }
                    if let Some(content_url) = post.get("url").and_then(|v| v.as_str()) {
                        push_labeled_url(
                            &mut urls,
                            &mut seen,
                            &format!("Read URL #{}", idx + 1),
                            content_url,
                        );
                    }
                }
            }
        }
        "search" => {
            let query = args
                .get("query")
                .and_then(|v| v.as_str())
                .unwrap_or_default();
            let limit = args
                .get("limit")
                .and_then(|v| v.as_u64())
                .unwrap_or(10)
                .min(25);
            let search_url = format!(
                "{}/search?q={}&limit={}",
                base_api,
                urlencoding::encode(query),
                limit
            );
            push_labeled_url(&mut urls, &mut seen, "API search", &search_url);
        }
        "create_post" => {
            push_labeled_url(
                &mut urls,
                &mut seen,
                "API create_post",
                "https://www.moltbook.com/api/v1/posts",
            );
            if let Some(post_id) = result
                .and_then(|r| r.get("post"))
                .and_then(|p| p.get("id"))
                .and_then(|v| v.as_str())
            {
                let api_url = format!("{}/posts/{}", base_api, post_id);
                push_labeled_url(&mut urls, &mut seen, "Created post API", &api_url);
            }
        }
        "comment" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                let comment_url = format!("{}/posts/{}/comments", base_api, post_id);
                push_labeled_url(&mut urls, &mut seen, "API comment", &comment_url);
                let post_url = format!("{}/posts/{}", base_api, post_id);
                push_labeled_url(&mut urls, &mut seen, "Comment target post API", &post_url);
            }
        }
        "upvote_post" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                let upvote_url = format!("{}/posts/{}/upvote", base_api, post_id);
                push_labeled_url(&mut urls, &mut seen, "API upvote", &upvote_url);
                let post_url = format!("{}/posts/{}", base_api, post_id);
                push_labeled_url(&mut urls, &mut seen, "Upvote target post API", &post_url);
            }
        }
        _ => {}
    }

    urls
}

fn compact_preview_text(value: &str, max_chars: usize) -> String {
    let compact = value.split_whitespace().collect::<Vec<_>>().join(" ");
    safe_truncate(compact.trim(), max_chars)
}

fn json_preview_value(value: &serde_json::Value, max_chars: usize) -> Option<String> {
    match value {
        serde_json::Value::Null => None,
        serde_json::Value::String(text) => {
            let compact = compact_preview_text(text, max_chars);
            if compact.is_empty() {
                None
            } else {
                Some(compact)
            }
        }
        other => Some(safe_truncate(&other.to_string(), max_chars)),
    }
}

fn maybe_insert_json_preview(
    map: &mut serde_json::Map<String, serde_json::Value>,
    key: &str,
    value: Option<&serde_json::Value>,
    max_chars: usize,
) {
    if let Some(preview) = value.and_then(|v| json_preview_value(v, max_chars)) {
        map.insert(key.to_string(), serde_json::json!(preview));
    }
}

fn maybe_insert_text_preview(
    map: &mut serde_json::Map<String, serde_json::Value>,
    key: &str,
    value: Option<&str>,
    max_chars: usize,
) {
    let Some(value) = value.map(str::trim).filter(|value| !value.is_empty()) else {
        return;
    };
    map.insert(
        key.to_string(),
        serde_json::json!(compact_preview_text(value, max_chars)),
    );
}

fn build_moltbook_trace_request_detail(
    sub_action: &str,
    args: &serde_json::Value,
) -> (String, Option<String>) {
    let mut data = serde_json::Map::new();
    data.insert("action".to_string(), serde_json::json!(sub_action));
    maybe_insert_text_preview(
        &mut data,
        "submolt",
        args.get("submolt").and_then(|v| v.as_str()),
        60,
    );
    maybe_insert_text_preview(
        &mut data,
        "post_id",
        args.get("post_id").and_then(|v| v.as_str()),
        80,
    );
    maybe_insert_text_preview(
        &mut data,
        "query_preview",
        args.get("query").and_then(|v| v.as_str()),
        140,
    );
    maybe_insert_text_preview(
        &mut data,
        "title_preview",
        args.get("title").and_then(|v| v.as_str()),
        140,
    );
    maybe_insert_text_preview(
        &mut data,
        "content_preview",
        args.get("content").and_then(|v| v.as_str()),
        220,
    );
    if let Some(limit) = args.get("limit").and_then(|v| v.as_u64()) {
        data.insert("limit".to_string(), serde_json::json!(limit));
    }
    if let Some(sort) = args.get("sort").and_then(|v| v.as_str()) {
        data.insert("sort".to_string(), serde_json::json!(sort));
    }

    let detail = match sub_action {
        "feed" => {
            let sort = args.get("sort").and_then(|v| v.as_str()).unwrap_or("new");
            let limit = args.get("limit").and_then(|v| v.as_u64()).unwrap_or(10);
            format!("Fetching Moltbook feed (sort={}, limit={})", sort, limit)
        }
        "search" => {
            if let Some(query) = args.get("query").and_then(|v| v.as_str()) {
                format!(
                    "Searching Moltbook for \"{}\"",
                    compact_preview_text(query, 120)
                )
            } else {
                "Searching Moltbook".to_string()
            }
        }
        "create_post" => {
            let title = args
                .get("title")
                .and_then(|v| v.as_str())
                .map(|value| compact_preview_text(value, 90))
                .filter(|value| !value.is_empty());
            let submolt = args
                .get("submolt")
                .and_then(|v| v.as_str())
                .map(|value| value.trim().to_string())
                .filter(|value| !value.is_empty());
            match (title, submolt) {
                (Some(title), Some(submolt)) => {
                    format!("Creating Moltbook post \"{}\" in /{}", title, submolt)
                }
                (Some(title), None) => format!("Creating Moltbook post \"{}\"", title),
                (None, Some(submolt)) => format!("Creating Moltbook post in /{}", submolt),
                (None, None) => "Creating Moltbook post".to_string(),
            }
        }
        "comment" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                format!("Commenting on Moltbook post {}", safe_truncate(post_id, 60))
            } else {
                "Commenting on Moltbook post".to_string()
            }
        }
        "upvote_post" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                format!("Upvoting Moltbook post {}", safe_truncate(post_id, 60))
            } else {
                "Upvoting a Moltbook post".to_string()
            }
        }
        "register" => "Registering the agent with Moltbook".to_string(),
        "status" => "Checking Moltbook connection status".to_string(),
        "me" => "Loading Moltbook profile".to_string(),
        _ => format!("Running Moltbook {}", humanize_tool_name(sub_action)),
    };

    let data = if data.len() > 1 {
        Some(serde_json::to_string_pretty(&serde_json::Value::Object(data)).unwrap_or_default())
    } else {
        None
    };

    (detail, data)
}

fn build_moltbook_trace_result_step(
    sub_action: &str,
    args: &serde_json::Value,
    result: Option<&serde_json::Value>,
    error: Option<&str>,
) -> (String, String, String, Option<String>) {
    let action_label = humanize_tool_name(sub_action);
    let mut data = serde_json::Map::new();
    data.insert("action".to_string(), serde_json::json!(sub_action));
    maybe_insert_text_preview(
        &mut data,
        "query_preview",
        args.get("query").and_then(|v| v.as_str()),
        140,
    );
    maybe_insert_text_preview(
        &mut data,
        "title_preview",
        args.get("title").and_then(|v| v.as_str()),
        140,
    );
    maybe_insert_text_preview(
        &mut data,
        "content_preview",
        args.get("content").and_then(|v| v.as_str()),
        220,
    );
    maybe_insert_text_preview(
        &mut data,
        "submolt",
        args.get("submolt").and_then(|v| v.as_str()),
        60,
    );
    maybe_insert_text_preview(
        &mut data,
        "post_id",
        args.get("post_id").and_then(|v| v.as_str()),
        80,
    );

    if let Some(error_text) = error {
        data.insert(
            "error".to_string(),
            serde_json::json!(compact_preview_text(error_text, 280)),
        );
        let detail = format!(
            "{} failed: {}",
            action_label,
            compact_preview_text(error_text, 180)
        );
        return (
            format!("Moltbook failed: {}", action_label),
            detail,
            "error".to_string(),
            Some(
                serde_json::to_string_pretty(&serde_json::Value::Object(data)).unwrap_or_default(),
            ),
        );
    }

    let detail = match sub_action {
        "feed" => {
            let count = result
                .and_then(|value| value.get("posts"))
                .and_then(|value| value.as_array())
                .map(|posts| posts.len())
                .unwrap_or(0);
            data.insert("post_count".to_string(), serde_json::json!(count));
            format!(
                "Fetched {} Moltbook post{} from the feed",
                count,
                if count == 1 { "" } else { "s" }
            )
        }
        "search" => {
            let count = result
                .and_then(|value| value.get("posts"))
                .and_then(|value| value.as_array())
                .map(|posts| posts.len())
                .unwrap_or(0);
            data.insert("post_count".to_string(), serde_json::json!(count));
            if let Some(query) = args.get("query").and_then(|v| v.as_str()) {
                format!(
                    "Search returned {} post{} for \"{}\"",
                    count,
                    if count == 1 { "" } else { "s" },
                    compact_preview_text(query, 120)
                )
            } else {
                format!(
                    "Search returned {} Moltbook post{}",
                    count,
                    if count == 1 { "" } else { "s" }
                )
            }
        }
        "create_post" => {
            let result_post_id = result
                .and_then(|value| value.get("post"))
                .and_then(|value| value.get("id"))
                .and_then(|value| value.as_str());
            maybe_insert_text_preview(&mut data, "result_post_id", result_post_id, 80);
            if let Some(title) = args.get("title").and_then(|v| v.as_str()) {
                format!(
                    "Created Moltbook post \"{}\"",
                    compact_preview_text(title, 100)
                )
            } else if let Some(post_id) = result_post_id {
                format!("Created Moltbook post {}", safe_truncate(post_id, 80))
            } else {
                "Created a Moltbook post".to_string()
            }
        }
        "comment" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                format!(
                    "Posted a comment on Moltbook post {}",
                    safe_truncate(post_id, 80)
                )
            } else {
                "Posted a Moltbook comment".to_string()
            }
        }
        "upvote_post" => {
            if let Some(post_id) = args.get("post_id").and_then(|v| v.as_str()) {
                format!("Upvoted Moltbook post {}", safe_truncate(post_id, 80))
            } else {
                "Upvoted a Moltbook post".to_string()
            }
        }
        "status" => {
            maybe_insert_json_preview(
                &mut data,
                "status",
                result.and_then(|value| value.get("status")),
                80,
            );
            "Loaded Moltbook status".to_string()
        }
        "register" => {
            maybe_insert_json_preview(
                &mut data,
                "claim_url",
                result.and_then(|value| value.get("claim_url")),
                200,
            );
            "Registered the Moltbook agent".to_string()
        }
        "me" => {
            maybe_insert_json_preview(
                &mut data,
                "username",
                result.and_then(|value| value.get("username")),
                80,
            );
            "Loaded Moltbook profile details".to_string()
        }
        _ => {
            maybe_insert_json_preview(&mut data, "result_preview", result, 260);
            format!("Completed Moltbook {}", action_label)
        }
    };

    (
        format!("Moltbook completed: {}", action_label),
        detail,
        "success".to_string(),
        Some(serde_json::to_string_pretty(&serde_json::Value::Object(data)).unwrap_or_default()),
    )
}

fn action_is_execution_capable(action: &crate::actions::ActionDef) -> bool {
    let hay = format!(
        "{} {} {}",
        action.name,
        action.description,
        action.capabilities.join(" ")
    )
    .to_lowercase();
    [
        "deploy", "execute", "run", "send", "create", "update", "delete", "restart", "stop",
        "schedule", "watch", "generate",
    ]
    .iter()
    .any(|k| hay.contains(k))
}

fn best_execution_intent_score(text: &str, actions: &[crate::actions::ActionDef]) -> f32 {
    let mut best = 0.0_f32;
    for action in actions {
        if !action_is_execution_capable(action) {
            continue;
        }
        best = best.max(action_intent_score(text, action));
    }
    best
}

fn contains_phrase_boundary(text: &str, needle: &str) -> bool {
    let haystack = text.to_ascii_lowercase();
    let needle = needle.trim().to_ascii_lowercase();
    if needle.is_empty() {
        return false;
    }

    haystack.match_indices(&needle).any(|(idx, _)| {
        let before = haystack[..idx].chars().next_back();
        let after = haystack[idx + needle.len()..].chars().next();
        let is_boundary = |ch: Option<char>| ch.is_none_or(|value| !value.is_ascii_alphanumeric());
        is_boundary(before) && is_boundary(after)
    })
}

fn is_workspace_modification_request(text: &str) -> bool {
    let edit_verbs = [
        "add", "update", "modify", "change", "rename", "remove", "fix", "refactor", "rewire",
        "edit", "delete", "move", "restyle", "redesign", "wire",
    ];
    let workspace_terms = [
        "file",
        "files",
        "codebase",
        "repo",
        "repository",
        "component",
        "components",
        "route",
        "routes",
        "endpoint",
        "endpoints",
        "frontend",
        "backend",
        "framework",
        "agentark",
        "console",
        "system",
        "server",
        "runtime",
        "script",
        "scripts",
        "readme",
        "docker",
        "container",
        "project",
        "workspace",
        "module",
        "page",
        "screen",
        "api",
    ];

    let path_like = [
        ".rs",
        ".tsx",
        ".ts",
        ".js",
        ".jsx",
        ".py",
        ".md",
        ".toml",
        "src/",
        "src\\",
        "frontend/",
        "frontend\\",
    ];
    let workspace_hit = workspace_terms
        .iter()
        .any(|needle| contains_phrase_boundary(text, needle));
    let path_hit = path_like
        .iter()
        .any(|needle| contains_phrase_boundary(text, needle));

    if !(workspace_hit || path_hit) {
        return false;
    }

    edit_verbs
        .iter()
        .any(|needle| contains_phrase_boundary(text, needle))
}

fn request_looks_like_fix_or_debug(text: &str) -> bool {
    [
        "fix",
        "debug",
        "repair",
        "broken",
        "bug",
        "issue",
        "stuck",
        "doesn't work",
        "doesnt work",
        "not working",
        "isn't working",
        "isnt working",
        "fails",
        "failure",
        "empty",
        "not pulling",
        "no paper",
        "no papers",
        "refresh",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle))
}

fn request_explicitly_prefers_shell(text: &str) -> bool {
    [
        "shell",
        "terminal",
        "bash",
        "zsh",
        "powershell",
        "command line",
        "cli",
        "run this command",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle))
}

fn request_mentions_repo_source(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    lower.contains("github.com/")
        || lower.contains("gitlab.com/")
        || lower.contains("bitbucket.org/")
        || lower.contains(".git")
        || ((contains_phrase_boundary(text, "repo")
            || contains_phrase_boundary(text, "repository"))
            && [
                "deploy",
                "run",
                "launch",
                "host",
                "integrate",
                "pull",
                "clone",
                "install",
            ]
            .iter()
            .any(|needle| contains_phrase_boundary(text, needle)))
}

fn request_describes_runtime_web_artifact(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    let build_marker = [
        "build", "create", "deploy", "launch", "publish", "ship", "spin up", "run it", "run this",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));
    let web_surface_marker = [
        "html page",
        "web page",
        "static html",
        "static page",
        "static site",
        "microsite",
        "single-page app",
        "single page app",
        "single-page site",
        "single page site",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    let has_interval = contains_phrase_boundary(text, "every")
        && ["second", "seconds", "minute", "minutes", "hour", "hours"]
            .iter()
            .any(|unit| contains_phrase_boundary(text, unit));
    let runtime_behavior_marker = has_interval
        || lower.contains("refresh")
        || lower.contains("auto-refresh")
        || lower.contains("auto refresh")
        || lower.contains("auto-update")
        || lower.contains("auto update")
        || lower.contains("fetch")
        || lower.contains("pull")
        || lower.contains("latest papers")
        || lower.contains("latest data")
        || lower.contains("live data");

    build_marker && web_surface_marker && runtime_behavior_marker
}

fn has_app_deploy_intent(text: &str, actions: &[crate::actions::ActionDef]) -> bool {
    if is_workspace_modification_request(text) {
        return false;
    }
    if has_action_intent_adaptive(text, actions, "app_deploy") {
        return true;
    }
    if request_describes_runtime_web_artifact(text) {
        return true;
    }
    if request_mentions_repo_source(text)
        && [
            "deploy",
            "run",
            "launch",
            "host",
            "integrate",
            "install",
            "spin up",
        ]
        .iter()
        .any(|needle| contains_phrase_boundary(text, needle))
    {
        return true;
    }
    let build_marker = [
        "build", "create", "deploy", "launch", "publish", "ship", "spin up", "run it", "run this",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));
    let app_marker = [
        "app",
        "dashboard",
        "site",
        "website",
        "service",
        "portal",
        "monitor",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));
    let exposure_marker = [
        "live",
        "public",
        "hosted",
        "url",
        "link",
        "read-only",
        "readonly",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));
    let landing_page_marker = [
        "landing page",
        "landing-page",
        "homepage",
        "home page",
        "marketing site",
        "marketing page",
        "single-page site",
        "single page site",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));

    (build_marker && app_marker && exposure_marker) || (build_marker && landing_page_marker)
}

fn has_schedule_task_intent(text: &str, actions: &[crate::actions::ActionDef]) -> bool {
    if is_workspace_modification_request(text) {
        return false;
    }
    if has_action_intent_adaptive(text, actions, "schedule_task") {
        return true;
    }
    let has_interval = contains_phrase_boundary(text, "every")
        && ["second", "minute", "hour", "day", "week"]
            .iter()
            .any(|unit| contains_phrase_boundary(text, unit));
    let has_schedule_marker = [
        "schedule",
        "scheduled",
        "recurring",
        "auto-updating",
        "auto updating",
        "repeat",
        "repeatedly",
        "poll",
        "monitor",
        "watch",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));
    let has_execution_marker = [
        "run", "refresh", "update", "fetch", "check", "monitor", "poll", "watch",
    ]
    .iter()
    .any(|needle| contains_phrase_boundary(text, needle));

    (has_interval || has_schedule_marker) && has_execution_marker
}

