    async fn process_message_internal(
        &self,
        message: &str,
        channel: &str,
        conversation_id: Option<&str>,
        project_id: Option<&str>,
        context: MessageProcessingContext,
    ) -> Result<ProcessedMessage> {
        let MessageProcessingContext {
            trace_override,
            token_tx,
            request_hints,
            user_message_already_recorded,
        } = context;
        let start_time = chrono::Utc::now();
        let trace_ref =
            trace_override.unwrap_or_else(|| Arc::new(RwLock::new(ExecutionTrace::default())));
        let deep_research_requested = request_hints.deep_research;
        // Track last user activity for idle detection
        *self.last_activity.write().await = Some(start_time);
        tracing::info!(
            "Processing message from {} ({} chars)",
            channel,
            message.len()
        );
        let early_safe_message = crate::security::redact_secret_input(message).text;
        let (resolved_conversation_id, is_new_conversation) = self
            .resolve_conversation_id(channel, conversation_id, project_id, &early_safe_message)
            .await;
        let conversation_key = resolved_conversation_id.clone();

        // Chat-safe secret save flow for channels that don't have channel-specific secret handling.
        // Telegram/WhatsApp enforce their own pairing/allowlist checks before storing secrets.
        if channel != "telegram" && channel != "whatsapp" {
            if let Some((key, value)) = crate::core::secrets::parse_set_secret_command(message) {
                crate::core::secrets::store_user_secret(
                    &self.config_dir,
                    Some(&self.data_dir),
                    &key,
                    &value,
                )?;
                let followup = self.on_secret_saved_followup(&conversation_key).await;
                let mut response = format!(
                    "Saved secret '{}' (stored encrypted). This value was not sent to the LLM.",
                    key
                );
                if let Some(f) = followup {
                    response.push_str("\n\n");
                    response.push_str(&f);
                }
                let persisted_user_message = format!("set secret {}=[REDACTED]", key);
                return self
                    .persist_immediate_exchange(
                        &persisted_user_message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "secret_save",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }

            if let Some(key) = crate::core::secrets::parse_use_current_llm_key_command(message) {
                let llm_env = self.app_model_env_vars();
                if let Some(value) = llm_env.get(&key).cloned().filter(|v| !v.trim().is_empty()) {
                    crate::core::secrets::store_user_secret(
                        &self.config_dir,
                        Some(&self.data_dir),
                        &key,
                        &value,
                    )?;
                    let followup = self.on_secret_saved_followup(&conversation_key).await;
                    let mut response = format!(
                        "Linked '{}' to the currently configured model credential (stored encrypted). You can override it anytime with set secret {}=VALUE.",
                        key, key
                    );
                    if let Some(f) = followup {
                        response.push_str("\n\n");
                        response.push_str(&f);
                    }
                    let persisted_user_message = format!("use current llm key for {}", key);
                    return self
                        .persist_immediate_exchange(
                            &persisted_user_message,
                            &response,
                            ImmediateExchangeContext {
                                channel,
                                conversation_key: &conversation_key,
                                is_new_conversation,
                                project_id,
                                model_used: "secret_save",
                                user_message_already_recorded,
                            },
                        )
                        .await;
                }

                let mut available_keys: Vec<String> = llm_env
                    .iter()
                    .filter_map(|(k, v)| {
                        if v.trim().is_empty() {
                            None
                        } else if k.ends_with("_API_KEY")
                            || k.ends_with("_BASE_URL")
                            || k == "LLM_MODEL"
                            || k == "LLM_PROVIDER"
                        {
                            Some(k.clone())
                        } else {
                            None
                        }
                    })
                    .collect();
                available_keys.sort();
                let available = if available_keys.is_empty() {
                    "none".to_string()
                } else {
                    available_keys.join(", ")
                };
                let response = format!(
                    "I can't map '{}' from the current model settings. Available model-backed keys: {}. You can set it manually with: set secret {}=VALUE",
                    key, available, key
                );
                let persisted_user_message = format!("use current llm key for {}", key);
                return self
                    .persist_immediate_exchange(
                        &persisted_user_message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "secret_save",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }
        }

        if let Some(model_hint) = parse_use_model_command(message) {
            let normalized = normalize_model_match_token(&model_hint);
            if matches!(
                normalized.as_str(),
                "default" | "auto" | "system" | "settings" | "primary"
            ) {
                self.set_user_selected_model_slot_id_local(None);
                let _ = self.storage.delete(USER_SELECTED_MODEL_SLOT_KEY).await;
                return self
                    .persist_immediate_exchange(
                        &early_safe_message,
                        "Cleared model override. I will use the configured model routing from Settings.",
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "model_override",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }

            if let Some(candidate) = self.resolve_model_hint_candidate(&model_hint) {
                self.set_user_selected_model_slot_id_local(Some(candidate.slot_id.clone()));
                let _ = self
                    .storage
                    .set(USER_SELECTED_MODEL_SLOT_KEY, candidate.slot_id.as_bytes())
                    .await;
                let response = format!(
                    "Model override saved. I will use '{}' ({}) until you change it.",
                    candidate.slot_label,
                    candidate.client.model_name()
                );
                return self
                    .persist_immediate_exchange(
                        &early_safe_message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "model_override",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }

            let available = self.available_model_selection_descriptions().join(", ");
            let response = format!(
                "I couldn't find a configured model matching '{}'. Available models: {}",
                model_hint, available
            );
            return self
                .persist_immediate_exchange(
                    &early_safe_message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "model_override",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        // Fast-path tool registration so newly wired integration tools are visible to the LLM
        // immediately on the next turn without restart.
        if let Some((tool_name, integration_id)) = parse_register_tool_alias_command(message) {
            if self.integrations.get(&integration_id).is_none() {
                let available = self.integrations.ids().join(", ");
                let response = format!(
                    "Integration '{}' is not registered. Available integrations: {}",
                    integration_id, available
                );
                return self
                    .persist_immediate_exchange(
                        &early_safe_message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "tool_alias",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }
            self.register_tool_integration_alias(&tool_name, &integration_id)
                .await?;
            let response = format!(
                "Registered tool alias: '{}' -> '{}'. It is now available to the agent immediately.",
                tool_name, integration_id
            );
            return self
                .persist_immediate_exchange(
                    &early_safe_message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "tool_alias",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        // Check if user has a browser session waiting for their input
        if let Some((session_id, _screenshot, _question)) =
            self.browser_sessions.get_waiting_session("")
        {
            // Forward the user's message as their response to the browser session
            if self
                .browser_sessions
                .provide_user_response(&session_id, message)
            {
                tracing::info!(
                    "Forwarded user message to waiting browser session={}",
                    &session_id[..8]
                );
                // Brief ack - the browser loop handles the rest
                return self
                    .persist_immediate_exchange(
                        &early_safe_message,
                        "Received, continuing the browser task...",
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "browser_session",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }
        }

        // Security check: Detect prompt injection and leakage attempts
        let sanitized = self.security.sanitize_input(message);
        if !sanitized.is_safe {
            if let Some(ref injection_type) = sanitized.injection_type {
                self.security_events
                    .injection_attempts
                    .fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                tracing::warn!(
                    "Security: Detected {:?} attempt from {}",
                    injection_type,
                    channel
                );
                // Proactive notification - alert user via preferred channel (non-blocking)
                let alert_msg = format!(
                    "Security Alert: {:?} detected from {} channel. The attempt was blocked.",
                    injection_type, channel
                );
                self.emit_notification("Security Alert", &alert_msg, "error", "security")
                    .await;
                self.notify_preferred_channel(&alert_msg).await;
                let response = crate::security::get_safe_response(injection_type).to_string();
                return self
                    .persist_immediate_exchange(
                        &early_safe_message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "security_guard",
                            user_message_already_recorded,
                        },
                    )
                    .await;
            }
        }
        let sanitized_message = sanitized.text;
        let secret_redaction = crate::security::redact_secret_input(&sanitized_message);
        if secret_redaction.had_secret() {
            tracing::warn!(
                "Security: redacted likely secret input from channel={} ({:?})",
                channel,
                secret_redaction.redactions
            );
        }
        let message_storage = secret_redaction.text.clone();
        let message = message_storage.as_str();

        let context_followup = self
            .has_context_dependent_followup(&conversation_key, message)
            .await;
        let profile_nudge = self
            .maybe_profile_nudge(channel, message, context_followup)
            .await;
        let pending_actions = self.pending_conversation_actions(&conversation_key).await;
        let pending_action_resolution = self
            .classify_pending_conversation_action_resolution(
                message,
                Some(&conversation_key),
                &pending_actions,
            )
            .await;

        if secret_redaction.is_mostly_secret_payload() {
            let mut response = crate::security::get_secret_input_block_response(
                &secret_redaction
                    .primary_kind()
                    .unwrap_or(crate::security::SecretInputType::ApiKeyOrToken),
            )
            .to_string();
            if let Some(nudge) = profile_nudge.as_ref() {
                response.push_str("\n\n");
                response.push_str(nudge);
            }
            return self
                .persist_immediate_exchange(
                    message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "secret_redaction_guard",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        if let Some(mut response) = build_shared_link_memory_ack(message) {
            if let Some(nudge) = profile_nudge.as_ref() {
                response.push_str("\n\n");
                response.push_str(nudge);
            }
            return self
                .persist_immediate_exchange(
                    message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "link_capture_fast_path",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        if !chat_model_is_configured(&self.config) {
            return self
                .persist_immediate_exchange(
                    message,
                    "No AI model is configured yet. Open Settings > Models and add at least one model before using chat.",
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "no_model_config",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        if let Some(resolution) = pending_action_resolution.clone() {
            let resolved_action = pending_actions
                .iter()
                .find(|action| action.key == resolution.action_key)
                .cloned();
            match (
                resolution.decision,
                resolved_action.map(|action| action.kind),
            ) {
                (
                    PendingConversationActionDecision::Approve,
                    Some(PendingConversationActionKind::ForceImportSkill),
                ) => {
                    if let Some(pending_import) =
                        self.take_pending_skill_import(&conversation_key).await
                    {
                        let mut response = match self
                            .import_skill_from_chat_url(&pending_import.source_url, true)
                            .await
                        {
                            Ok(outcome) => {
                                if !outcome.missing_required_envs.is_empty() {
                                    self.remember_pending_secret_followup(
                                        &conversation_key,
                                        PendingSecretFollowupKind::EnableSkill {
                                            action_name: outcome.skill_name.clone(),
                                        },
                                    )
                                    .await;
                                } else {
                                    self.clear_pending_secret_followup(&conversation_key).await;
                                }
                                outcome.response
                            }
                            Err(e) => format!("I couldn't force-import that skill yet: {}", e),
                        };
                        if let Some(nudge) = profile_nudge.as_ref() {
                            response.push_str("\n\n");
                            response.push_str(nudge);
                        }
                        return self
                            .persist_immediate_exchange(
                                message,
                                &response,
                                ImmediateExchangeContext {
                                    channel,
                                    conversation_key: &conversation_key,
                                    is_new_conversation,
                                    project_id,
                                    model_used: "skill_import_force",
                                    user_message_already_recorded,
                                },
                            )
                            .await;
                    }
                }
                (
                    PendingConversationActionDecision::Reject,
                    Some(PendingConversationActionKind::ForceImportSkill),
                ) => {
                    let response = if let Some(pending_import) =
                        self.take_pending_skill_import(&conversation_key).await
                    {
                        format!(
                            "Understood. I won't import skill '{}' from that blocked definition.",
                            pending_import.skill_name
                        )
                    } else {
                        "Understood. I cleared the pending blocked skill import request."
                            .to_string()
                    };
                    return self
                        .persist_immediate_exchange(
                            message,
                            &response,
                            ImmediateExchangeContext {
                                channel,
                                conversation_key: &conversation_key,
                                is_new_conversation,
                                project_id,
                                model_used: "pending_action_resolution",
                                user_message_already_recorded,
                            },
                        )
                        .await;
                }
                _ => {}
            }
        }

        // Multi-turn onboarding: start/cancel integration connect flows without engaging the LLM.
        if let Some(flow_response) = self
            .maybe_handle_integration_connect_flow(&conversation_key, message)
            .await
        {
            // Persist this exchange so the web UI + mobile channels retain context across refreshes.
            {
                let mut history = self.conversation_history.write().await;
                let conversation_history = history
                    .entry(conversation_key.clone())
                    .or_insert_with(Vec::new);
                conversation_history.push(ConversationMessage {
                    role: "user".to_string(),
                    content: message.to_string(),
                    _timestamp: chrono::Utc::now(),
                });
                conversation_history.push(ConversationMessage {
                    role: "assistant".to_string(),
                    content: flow_response.clone(),
                    _timestamp: chrono::Utc::now(),
                });
                if conversation_history.len() > 10 {
                    conversation_history.drain(0..conversation_history.len() - 10);
                }
            }
            if !conversation_key.is_empty() {
                let now = chrono::Utc::now().to_rfc3339();
                let user_msg = crate::storage::entities::message::Model {
                    id: uuid::Uuid::new_v4().to_string(),
                    conversation_id: conversation_key.clone(),
                    role: "user".to_string(),
                    content: message.to_string(),
                    timestamp: now.clone(),
                    model_used: None,
                    trace_id: None,
                };
                let _ = self
                    .encrypted_storage
                    .insert_message_encrypted(&user_msg)
                    .await;
                self.capture_user_memory_hints(
                    message,
                    channel,
                    Some(&conversation_key),
                    project_id,
                )
                .await;
                let asst_msg = crate::storage::entities::message::Model {
                    id: uuid::Uuid::new_v4().to_string(),
                    conversation_id: conversation_key.clone(),
                    role: "assistant".to_string(),
                    content: flow_response.clone(),
                    timestamp: chrono::Utc::now().to_rfc3339(),
                    model_used: Some("connect_flow".to_string()),
                    trace_id: None,
                };
                let _ = self
                    .encrypted_storage
                    .insert_message_encrypted(&asst_msg)
                    .await;
            }
            *self.last_conversation_id.write().await = Some(conversation_key.clone());
            *self.last_conversation_title.write().await = None;
            let user_outcome = self
                .build_response_heuristic_outcome(&flow_response, &[], &[], None)
                .unwrap_or_else(|| {
                    self.execution_supervisor
                        .build_success_outcome(&flow_response, &[], &[])
                });
            let run_status = Self::execution_run_status_for_outcome(&user_outcome);
            return Ok(ProcessedMessage {
                response: flow_response,
                conversation_id: Some(conversation_key),
                conversation_title: None,
                run_id: None,
                run_status: Some(run_status.as_str().to_string()),
                trace_id: None,
                degradation: Vec::new(),
                attempted_models: Vec::new(),
                user_outcome: Some(user_outcome),
            });
        }

        // Chat-native skill install from URL (works across web/telegram/whatsapp channels).
        if let Some(skill_url) = parse_skill_install_url_request(message) {
            let mut response = match self.import_skill_from_chat_url(&skill_url, false).await {
                Ok(outcome) => {
                    if outcome.blocked_by_security {
                        self.remember_pending_skill_import(
                            &conversation_key,
                            &skill_url,
                            &outcome.skill_name,
                        )
                        .await;
                    } else {
                        self.clear_pending_skill_import(&conversation_key).await;
                        if !outcome.missing_required_envs.is_empty() {
                            self.remember_pending_secret_followup(
                                &conversation_key,
                                PendingSecretFollowupKind::EnableSkill {
                                    action_name: outcome.skill_name.clone(),
                                },
                            )
                            .await;
                        } else {
                            self.clear_pending_secret_followup(&conversation_key).await;
                        }
                    }
                    outcome.response
                }
                Err(e) => format!("I couldn't install that skill yet: {}", e),
            };
            if let Some(nudge) = profile_nudge.as_ref() {
                response.push_str("\n\n");
                response.push_str(nudge);
            }
            return self
                .persist_immediate_exchange(
                    message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "skill_import",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        // Chat-native skill run shortcut for custom/bundled skills:
        // e.g. "run calendar-helper and schedule 9am meeting tomorrow".
        let mut enabled_actions = self
            .runtime
            .list_enabled_actions()
            .await
            .unwrap_or_default();
        self.append_dynamic_integration_actions(&mut enabled_actions)
            .await;
        if let Some(intent) = parse_skill_run_intent(message, &enabled_actions) {
            let mut response = match self
                .run_named_skill_chat_shortcut(
                    &intent.skill_name,
                    &intent.query,
                    Some(&conversation_key),
                )
                .await
            {
                Ok(out) => out,
                Err(e) => format!("I couldn't run skill '{}': {}", intent.skill_name, e),
            };
            if let Some(nudge) = profile_nudge.as_ref() {
                response.push_str("\n\n");
                response.push_str(nudge);
            }
            return self
                .persist_immediate_exchange(
                    message,
                    &response,
                    ImmediateExchangeContext {
                        channel,
                        conversation_key: &conversation_key,
                        is_new_conversation,
                        project_id,
                        model_used: "skill_shortcut",
                        user_message_already_recorded,
                    },
                )
                .await;
        }

        let mem0_scope =
            self.mem0_scope_for_request(channel, Some(&resolved_conversation_id), project_id);
        self.remember_mem0_scope(&mem0_scope).await;

        // Initialize execution trace
        let trace_id = {
            let trace = trace_ref.read().await;
            let seeded = trace.id.trim();
            if seeded.is_empty() {
                uuid::Uuid::new_v4().to_string()
            } else {
                seeded.to_string()
            }
        };
        {
            let mut trace = trace_ref.write().await;
            *trace = ExecutionTrace {
                id: trace_id.clone(),
                message: message.to_string(),
                channel: channel.to_string(),
                started_at: Some(start_time),
                completed_at: None,
                steps: vec![],
                proof_id: None,
                response: None,
                model: None,
                input_tokens: 0,
                output_tokens: 0,
                total_tokens: 0,
                cost_usd: 0.0,
                complexity: None,
                plan: None,
            };
            trace.steps.push(ExecutionStep {
                icon: "[msg]".to_string(),
                title: "Message Received".to_string(),
                detail: format!("Channel: {} | Length: {} chars", channel, message.len()),
                step_type: "info".to_string(),
                data: Some(safe_truncate(message, 100)),
                timestamp: start_time,
                duration_ms: None,
            });
        }
        let deadline_at = if deep_research_requested {
            Some((start_time + chrono::Duration::minutes(20)).to_rfc3339())
        } else {
            Some((start_time + chrono::Duration::minutes(10)).to_rfc3339())
        };
        let mut execution_run = crate::core::ExecutionRun::new(
            "chat",
            Some(trace_id.clone()),
            Some(trace_id.clone()),
            Some(conversation_key.clone()),
            Some(channel.to_string()),
            Some(early_safe_message.clone()),
            deadline_at,
        );
        let mut execution_checkpoint_seq = 1u32;
        let mut tool_attempt_sequence = 1u32;
        let mut degradation_notes: Vec<crate::core::DegradationNote> = Vec::new();
        let mut attempted_models: Vec<crate::core::ModelAttemptRecord> = Vec::new();
        let mut attempt_records: Vec<crate::core::AttemptRecord> = Vec::new();
        self.persist_execution_run(
            &execution_run,
            Some(&mut execution_checkpoint_seq),
            Some(serde_json::json!({
                "message_preview": safe_truncate(&early_safe_message, 200),
                "channel": channel,
                "conversation_id": conversation_key.clone(),
            })),
        )
        .await;

        if operational::message_looks_like_correction(message) {
            let payload = serde_json::json!({
                "signal": "user_correction",
                "message_preview": safe_truncate(message, 180),
            });
            self.log_operational_event(operational::OperationalEvent {
                event_type: "user_correction",
                channel,
                success: true,
                outcome: "detected",
                trace_id: Some(&trace_id),
                conversation_id: Some(&conversation_key),
                tool_name: None,
                latency_ms: None,
                arguments: None,
                payload: Some(&payload),
                strategy_version: None,
                policy_version: None,
                prompt_version: Some("system_prompt_v2"),
                model_slot: None,
            })
            .await;
            if !conversation_key.is_empty() {
                self.persist_learning_correction(&conversation_key, message)
                    .await;
            }
        }

        // 0. Memory extraction is handled after the response is generated, and
        // relevant memory can be pulled on demand through the action catalog.
        {
            let memory_status = if self.mem0.is_available() {
                "Memory available on demand"
            } else {
                "Memory pending (no model pool)"
            };
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[mem]".to_string(),
                title: "Memory Layer".to_string(),
                detail: format!(
                    "{} | Scope: {} | Channel: {}",
                    memory_status, mem0_scope, channel
                ),
                step_type: "info".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        // 2. Add to conversation history
        {
            let mut history = self.conversation_history.write().await;
            let conversation_history = history
                .entry(conversation_key.clone())
                .or_insert_with(Vec::new);
            if !user_message_already_recorded {
                conversation_history.push(ConversationMessage {
                    role: "user".to_string(),
                    content: message.to_string(),
                    _timestamp: chrono::Utc::now(),
                });
            }
            // Keep only last 10 messages per conversation (cost optimization)
            if conversation_history.len() > 10 {
                conversation_history.drain(0..conversation_history.len() - 10);
            }
        }

        // Persist user message to DB immediately so it survives LLM failures
        if !user_message_already_recorded && !conversation_key.is_empty() {
            let user_msg = crate::storage::entities::message::Model {
                id: uuid::Uuid::new_v4().to_string(),
                conversation_id: conversation_key.clone(),
                role: "user".to_string(),
                content: message.to_string(),
                timestamp: chrono::Utc::now().to_rfc3339(),
                model_used: None,
                trace_id: None,
            };
            if let Err(e) = self
                .encrypted_storage
                .insert_message_encrypted(&user_msg)
                .await
            {
                tracing::warn!("Failed to persist user message early: {}", e);
            }
            self.capture_user_memory_hints(message, channel, Some(&conversation_key), project_id)
                .await;
        }

        if let Some(resolution) = pending_action_resolution.clone() {
            let resolved_action = pending_actions
                .iter()
                .find(|action| action.key == resolution.action_key)
                .cloned();
            if resolved_action.as_ref().is_some_and(|action| {
                matches!(
                    action.kind,
                    PendingConversationActionKind::ResumeResilienceFollowup
                )
            }) {
                match resolution.decision {
                    PendingConversationActionDecision::Approve => {
                        let Some(pending_followup) = self
                            .load_pending_resilience_followup(&conversation_key)
                            .await
                        else {
                            return self
                                .persist_immediate_exchange(
                                    message,
                                    "The previously blocked request is no longer available. Please restate what you want me to continue.",
                                    ImmediateExchangeContext {
                                        channel,
                                        conversation_key: &conversation_key,
                                        is_new_conversation,
                                        project_id,
                                        model_used: "pending_resume",
                                        user_message_already_recorded: true,
                                    },
                                )
                                .await;
                        };
                        let Some(resume_message) = Self::build_pending_resilience_resume_message(
                            &pending_followup,
                            message,
                        ) else {
                            return self
                                .persist_immediate_exchange(
                                    message,
                                    "I still need the missing clarification before I can resume that request. Reply with the missing detail and I’ll continue.",
                                    ImmediateExchangeContext {
                                        channel,
                                        conversation_key: &conversation_key,
                                        is_new_conversation,
                                        project_id,
                                        model_used: "pending_resume",
                                        user_message_already_recorded: true,
                                    },
                                )
                                .await;
                        };
                        self.clear_pending_resilience_followup(&conversation_key)
                            .await;
                        {
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[resume]".to_string(),
                                title: "Blocked Request Resume".to_string(),
                                detail: format!(
                                    "Resuming pending request from {} state",
                                    pending_followup.request_state.as_str()
                                ),
                                step_type: "info".to_string(),
                                data: Some(safe_truncate(&pending_followup.assistant_message, 240)),
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                        }
                        return Box::pin(self.process_message_internal(
                            &resume_message,
                            channel,
                            Some(&conversation_key),
                            project_id,
                            MessageProcessingContext {
                                trace_override: Some(trace_ref.clone()),
                                token_tx: token_tx.clone(),
                                request_hints,
                                user_message_already_recorded: true,
                            },
                        ))
                        .await;
                    }
                    PendingConversationActionDecision::Reject => {
                        self.clear_pending_resilience_followup(&conversation_key)
                            .await;
                        return self
                            .persist_immediate_exchange(
                                message,
                                "Understood. I cleared the previously blocked request and won’t resume it unless you ask again.",
                                ImmediateExchangeContext {
                                    channel,
                                    conversation_key: &conversation_key,
                                    is_new_conversation,
                                    project_id,
                                    model_used: "pending_resume",
                                    user_message_already_recorded: true,
                                },
                            )
                            .await;
                    }
                }
            }
        }

        if context_followup {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[ctx]".to_string(),
                title: "Conversation Continuation".to_string(),
                detail:
                    "Detected a short follow-up that depends on earlier turns; bypassing smalltalk shortcuts."
                        .to_string(),
                step_type: "info".to_string(),
                data: Some(safe_truncate(message, 120)),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        if deep_research_requested {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[research]".to_string(),
                title: "Deep Research Mode".to_string(),
                detail: "User explicitly enabled deep research mode; biasing toward the research capability and bypassing cheap chat shortcuts.".to_string(),
                step_type: "info".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        if !deep_research_requested {
            if let Some(outcome) = self
                .maybe_build_user_fact_fast_path(channel, message, &conversation_key, project_id)
                .await
            {
                for (key, value, confidence) in &outcome.facts {
                    if let Err(e) = self
                        .storage
                        .upsert_user_preference(key, value, *confidence, Some(channel), None)
                        .await
                    {
                        tracing::warn!(
                            "Failed to persist user fact fast-path '{}' => '{}': {}",
                            key,
                            value,
                            e
                        );
                    }
                }

                let mut response = outcome.response;
                if let Some(nudge) = profile_nudge.as_ref() {
                    response.push_str("\n\n");
                    response.push_str(nudge);
                }
                return self
                    .persist_immediate_exchange(
                        message,
                        &response,
                        ImmediateExchangeContext {
                            channel,
                            conversation_key: &conversation_key,
                            is_new_conversation,
                            project_id,
                            model_used: "user_fact_fast_path",
                            user_message_already_recorded: true,
                        },
                    )
                    .await;
            }
        }

        // Fast-path greetings: skip heavy routing/tooling/extra LLM calls.
        if !deep_research_requested
            && !context_followup
            && self.classify_smalltalk_intent(channel, message).await
        {
            let (profile_name, onboarding_complete, missing_profile_fields) = {
                let profile = self.user_profile.read().await;
                (
                    profile.name.clone(),
                    profile.onboarding_complete,
                    Self::missing_profile_fields(&profile),
                )
            };
            let conversation_count = if is_new_conversation {
                self.storage
                    .count_conversations(project_id, &[], None)
                    .await
                    .unwrap_or(2)
            } else {
                2
            };
            let introductory =
                !onboarding_complete && is_new_conversation && conversation_count <= 1;

            let mut response = Self::render_fast_greeting_response(
                profile_name.as_deref(),
                introductory,
                &missing_profile_fields,
            );
            if !introductory {
                if let Some(nudge) = profile_nudge.as_ref() {
                    response.push_str("\n\n");
                    response.push_str(nudge);
                }
            }
            let model_name = "fast_greeting".to_string();
            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[zap]".to_string(),
                    title: "Greeting Fast Path".to_string(),
                    detail: if introductory {
                        "Detected first-contact smalltalk; returned onboarding greeting"
                            .to_string()
                    } else {
                        "Detected simple smalltalk; returned immediate response".to_string()
                    },
                    step_type: "success".to_string(),
                    data: Some(safe_truncate(message, 80)),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
                trace.steps.push(ExecutionStep {
                    icon: "[llm]".to_string(),
                    title: "LLM Response Received".to_string(),
                    detail: format!("Response length: {} chars | Tool calls: 0", response.len()),
                    step_type: "success".to_string(),
                    data: None,
                    timestamp: chrono::Utc::now(),
                    duration_ms: Some(0),
                });
            }
            {
                let mut history = self.conversation_history.write().await;
                if let Some(conversation_history) = history.get_mut(&conversation_key) {
                    conversation_history.push(ConversationMessage {
                        role: "assistant".to_string(),
                        content: response.clone(),
                        _timestamp: chrono::Utc::now(),
                    });
                }
            }

            {
                let mut trace = trace_ref.write().await;
                let end_time = chrono::Utc::now();
                let total_duration = if let Some(start) = trace.started_at {
                    (end_time - start).num_milliseconds() as u64
                } else {
                    0
                };
                trace.completed_at = Some(end_time);
                trace.response = Some(response.clone());
                trace.steps.push(ExecutionStep {
                    icon: "[ok]".to_string(),
                    title: "Response Complete".to_string(),
                    detail: format!(
                        "Total time: {}ms | Response: {} chars",
                        total_duration,
                        response.len()
                    ),
                    step_type: "success".to_string(),
                    data: None,
                    timestamp: end_time,
                    duration_ms: Some(total_duration),
                });
            }
            self.persist_completed_trace(&trace_ref).await;

            let mut conversation_title: Option<String> = None;
            {
                let conv_id = conversation_key.clone();
                *self.last_conversation_id.write().await = Some(conv_id.clone());
                *self.last_conversation_title.write().await = None;

                if !conv_id.is_empty() {
                    let asst_msg = crate::storage::entities::message::Model {
                        id: uuid::Uuid::new_v4().to_string(),
                        conversation_id: conv_id.clone(),
                        role: "assistant".to_string(),
                        content: response.clone(),
                        timestamp: chrono::Utc::now().to_rfc3339(),
                        model_used: Some(model_name),
                        trace_id: Some(trace_id.clone()),
                    };
                    if let Err(e) = self
                        .encrypted_storage
                        .insert_message_encrypted(&asst_msg)
                        .await
                    {
                        tracing::warn!("Failed to persist greeting assistant message: {}", e);
                    }

                    if is_new_conversation {
                        let title = "Initial greeting exchange".to_string();
                        let _ = self
                            .storage
                            .update_conversation(&conv_id, Some(&title), Some(2), None)
                            .await;
                        *self.last_conversation_title.write().await = Some(title.clone());
                        conversation_title = Some(title);
                    }
                }
            }

            let user_outcome = self
                .build_response_heuristic_outcome(&response, &[], &[], None)
                .unwrap_or_else(|| {
                    self.execution_supervisor
                        .build_success_outcome(&response, &[], &[])
                });
            let run_status = Self::execution_run_status_for_outcome(&user_outcome);
            return Ok(ProcessedMessage {
                response,
                conversation_id: Some(conversation_key),
                conversation_title,
                run_id: None,
                run_status: Some(run_status.as_str().to_string()),
                trace_id: None,
                degradation: Vec::new(),
                attempted_models: Vec::new(),
                user_outcome: Some(user_outcome),
            });
        }

        let relevant_memories: Vec<crate::memory::MemoryEntry> = Vec::new();

        // 4. Search documents for RAG context (if any exist)
        let doc_context = match self.search_documents(message, 3, project_id).await {
            Ok(hits) if !hits.is_empty() => {
                let ctx: String = hits
                    .iter()
                    .enumerate()
                    .map(|(i, hit)| {
                        let preview = safe_truncate(&hit.content, 300);
                        let chunk_label = hit
                            .chunk_index
                            .map(|chunk_index| format!(" | chunk {}", chunk_index + 1))
                            .unwrap_or_default();
                        format!(
                            "{}. {} [doc:{} | relevance: {:.2} | match: {}{}] {}",
                            i + 1,
                            hit.filename,
                            hit.document_id,
                            hit.score,
                            hit.match_reason,
                            chunk_label,
                            preview
                        )
                    })
                    .collect::<Vec<_>>()
                    .join("\n");
                {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "\u{1F4C4}".to_string(),
                        title: "Document Search".to_string(),
                        detail: format!("Found {} relevant document chunks", hits.len()),
                        step_type: "success".to_string(),
                        data: Some(ctx.clone()),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                }
                Some(ctx)
            }
            _ => None,
        };

        // 4b. Build context for LLM
        let mut system_prompt = match self.build_system_prompt(&relevant_memories).await {
            Ok(prompt) => prompt,
            Err(err) => {
                let error_text = format!("Failed to build system prompt: {}", err);
                self.finalize_failed_trace(&trace_ref, "System Prompt Failed", &error_text, None)
                    .await;
                return Err(err);
            }
        };
        let prompt_version = "system_prompt_v2".to_string();
        let mut strategy_version: Option<String> = None;
        let mut strategy_task_type: Option<String> = None;

        if let Some((strategy_block, version, task_type)) =
            self.build_strategy_prompt_block_for_message(message).await
        {
            system_prompt.push_str("\n\n");
            system_prompt.push_str(&strategy_block);
            strategy_version = Some(version.clone());
            strategy_task_type = Some(task_type.clone());

            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[plan]".to_string(),
                title: "Strategy Injection".to_string(),
                detail: format!(
                    "Applied strategy profile '{}' for task '{}'",
                    version, task_type
                ),
                step_type: "info".to_string(),
                data: Some(safe_truncate(&strategy_block, 260)),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }
        if strategy_version.is_none() {
            strategy_version = self.active_strategy_version_for_message(message).await;
        }

        let user_execution_constraints = self.load_user_execution_constraints(project_id).await;
        let current_turn_is_explicit_approval = self
            .classify_explicit_approval_signal(message, Some(&conversation_key))
            .await;
        if let Some(constraint_block) = Self::build_user_execution_constraints_context(
            &user_execution_constraints,
            current_turn_is_explicit_approval,
        ) {
            system_prompt.push_str("\n\n");
            system_prompt.push_str(&constraint_block);
            system_prompt.push('\n');
        }

        if let Some(saved_user_facts) = self.build_saved_user_facts_context(project_id).await {
            system_prompt.push_str("\n\n");
            system_prompt.push_str(&saved_user_facts);
            system_prompt.push('\n');
        }

        if let Some(product_help_context) = self
            .build_agentark_product_help_context(message, project_id)
            .await
        {
            system_prompt.push_str("\n\n");
            system_prompt.push_str(&product_help_context);
            system_prompt.push('\n');

            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[docs]".to_string(),
                title: "Product Help Context".to_string(),
                detail: "Injected bundled AgentArk help context for a product how-to request."
                    .to_string(),
                step_type: "info".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        // Append document context if available
        if let Some(ref doc_ctx) = doc_context {
            system_prompt.push_str(
                "\n\n## Relevant Document Excerpts\nUse these for answering if relevant:\n",
            );
            system_prompt.push_str(doc_ctx);
            system_prompt.push('\n');
        }

        tracing::info!(
            "System prompt built: {}chars, doc_context={}",
            system_prompt.len(),
            if doc_context.is_some() { "yes" } else { "no" }
        );

        // 5. Build packed conversation context (recent turns + salient older turns + digest).
        let packed_context = self
            .build_packed_conversation_context(&conversation_key, message)
            .await;
        let conversation_history = packed_context.history.clone();
        if let Some(digest) = packed_context
            .digest
            .as_ref()
            .filter(|s| !s.trim().is_empty())
        {
            system_prompt.push_str("\n\n## Earlier Conversation Recap\n");
            system_prompt.push_str(digest);
            system_prompt.push('\n');
        }
        let packed_chars = packed_context.used_chars
            + packed_context.digest.as_ref().map(|d| d.len()).unwrap_or(0);
        {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "\u{1F9FE}".to_string(),
                title: "Context Packing".to_string(),
                detail: format!(
                    "Loaded {} messages, packed {} ({} chars, ~{} tokens, digest={}, compacted={}, refreshed={})",
                    packed_context.total_loaded,
                    conversation_history.len(),
                    packed_chars,
                    Self::estimate_tokens_from_chars(packed_chars),
                    if packed_context.used_digest {
                        "yes"
                    } else {
                        "no"
                    },
                    packed_context.compacted_messages,
                    if packed_context.digest_refreshed {
                        "yes"
                    } else {
                        "no"
                    },
                ),
                step_type: "info".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        // 6. Get available actions
        let mut all_actions = match self.runtime.list_enabled_actions().await {
            Ok(actions) => actions,
            Err(err) => {
                let error_text = format!("Failed to list enabled actions: {}", err);
                self.finalize_failed_trace(
                    &trace_ref,
                    "Action Discovery Failed",
                    &error_text,
                    None,
                )
                .await;
                return Err(err);
            }
        };
        self.append_dynamic_integration_actions(&mut all_actions)
            .await;
        let direct_app_deploy_intent = has_app_deploy_intent(message, &all_actions);
        let direct_schedule_task_intent = has_schedule_task_intent(message, &all_actions);
        let mut recent_artifact = self.load_recent_artifact_context(&conversation_key).await;
        // If no artifact context exists, check if the user mentions a deployed app by name
        // and synthesize one so the full app-context pipeline activates.
        if recent_artifact.is_none() {
            let deployed_apps = self.app_registry.list().await;
            if let Some(recovered) =
                recover_recent_app_artifact_from_history(&conversation_history, &deployed_apps)
            {
                tracing::info!(
                    "Recovered deployed app '{}' (id={}) from recent conversation history",
                    recovered.title,
                    recovered.artifact_id
                );
                self.persist_last_deployed_app_context(
                    &conversation_key,
                    &recovered.artifact_id,
                    &recovered.title,
                    &recovered.url,
                )
                .await;
                recent_artifact = Some(recovered);
            } else {
                let msg_lower = message.to_ascii_lowercase();
                for app in &deployed_apps {
                    let id = app.get("id").and_then(|v| v.as_str()).unwrap_or("");
                    let title = app.get("title").and_then(|v| v.as_str()).unwrap_or("");
                    if id.is_empty() || title.is_empty() {
                        continue;
                    }
                    if msg_lower.contains(&title.to_ascii_lowercase()) {
                        tracing::info!(
                            "Auto-matched deployed app '{}' (id={}) from user message",
                            title,
                            id
                        );
                        let local_url = format!("http://localhost:8990/apps/{}/", id);
                        let public_base: Option<String> = self
                            .storage
                            .get("public_base_url")
                            .await
                            .ok()
                            .flatten()
                            .and_then(|bytes| String::from_utf8(bytes).ok())
                            .filter(|s| !s.trim().is_empty());
                        let url_summary = if let Some(base) = public_base {
                            format!(
                                "Local: {} | Public: {}/apps/{}/",
                                local_url,
                                base.trim_end_matches('/'),
                                id
                            )
                        } else {
                            local_url.clone()
                        };
                        self.persist_last_deployed_app_context(
                            &conversation_key,
                            id,
                            title,
                            &local_url,
                        )
                        .await;
                        recent_artifact = Some(ConversationArtifactContext {
                            artifact_type: "app".to_string(),
                            artifact_id: id.to_string(),
                            title: title.to_string(),
                            summary: String::new(),
                            url: url_summary,
                            related_actions: vec![
                                "app_inspect".to_string(),
                                "app_restart".to_string(),
                                "file_read".to_string(),
                                "file_write".to_string(),
                            ],
                            updated_at: chrono::Utc::now().to_rfc3339(),
                        });
                        break;
                    }
                }
            }
        }
        let continuation_score = continuation_message_score(message, &conversation_history);
        let recent_artifact_age_secs = recent_artifact
            .as_ref()
            .and_then(|ctx| chrono::DateTime::parse_from_rfc3339(&ctx.updated_at).ok())
            .map(|dt| (chrono::Utc::now() - dt.with_timezone(&chrono::Utc)).num_seconds())
            .unwrap_or(i64::MAX);
        // Generic signal: conversation has a deployed app that's still relevant.
        // When true, inject app context into the LLM prompt and skip clarification —
        // let the LLM understand intent instead of keyword heuristics.
        let has_recent_artifact_context = recent_artifact.is_some()
            && recent_artifact_age_secs <= APP_FOLLOWUP_CONTEXT_MAX_AGE_SECS;
        let artifact_reference = recent_artifact
            .as_ref()
            .map(|ctx| artifact_reference_score(message, ctx))
            .unwrap_or(0.0);
        let artifact_related_action_names: HashSet<String> = recent_artifact
            .as_ref()
            .map(|ctx| ctx.related_actions.iter().cloned().collect())
            .unwrap_or_default();
        let competing_intent =
            best_competing_intent_score(message, &all_actions, &artifact_related_action_names);
        let recent_artifact_prompt_context = recent_artifact
            .as_ref()
            .filter(|_| has_recent_artifact_context);
        let request_shape = self
            .assess_request_shape_with_llm(
                channel,
                message,
                &conversation_history,
                &all_actions,
                recent_artifact_prompt_context,
                request_hints,
            )
            .await;
        let use_recent_artifact_context = should_apply_recent_artifact_context(
            message,
            &all_actions,
            recent_artifact.as_ref(),
            has_recent_artifact_context,
            continuation_score,
            artifact_reference,
            competing_intent,
        );
        let boosted_action_names: HashSet<String> = if use_recent_artifact_context {
            artifact_related_action_names.clone()
        } else {
            HashSet::new()
        };
        tracing::info!(
            "artifact_context_check: recent_artifact={}, recent_age_secs={}, has_recent_artifact_context={}, conv_key={}",
            recent_artifact.is_some(),
            recent_artifact_age_secs,
            use_recent_artifact_context,
            &conversation_key,
        );

        if let Some(artifact_ctx) = recent_artifact_prompt_context {
            system_prompt.push_str(
                "\n\n## Recent Artifact Context\n\
This conversation recently produced or modified an artifact.\n",
            );
            system_prompt.push_str(&format!(
                "Artifact type: `{}`\nArtifact title: '{}'\nArtifact id: `{}`.\n",
                safe_truncate(&artifact_ctx.artifact_type, 48),
                safe_truncate(&artifact_ctx.title, 120),
                safe_truncate(&artifact_ctx.artifact_id, 48)
            ));
            if !artifact_ctx.url.trim().is_empty() {
                system_prompt.push_str(&format!(
                    "Artifact URL: `{}`.\n",
                    safe_truncate(&artifact_ctx.url, 220)
                ));
            }
            if !artifact_ctx.summary.trim().is_empty() {
                system_prompt.push_str(&format!(
                    "Artifact summary: {}.\n",
                    safe_truncate(&artifact_ctx.summary, 220)
                ));
            }
            if !artifact_ctx.related_actions.is_empty() {
                system_prompt.push_str(&format!(
                    "Related actions: {}.\n",
                    artifact_ctx.related_actions.join(", ")
                ));
            }
            if artifact_ctx.artifact_type.eq_ignore_ascii_case("app") {
                let app_root = format!("/app/data/apps/{}", artifact_ctx.artifact_id);
                system_prompt.push_str(&format!("Deployed app workspace root: `{}`.\n", app_root));
                system_prompt.push_str(
                    "When the user wants to debug or fix this app, do not ask whether the app exists. Prefer `app_inspect` first if you need metadata or file inventory, then use `file_read` and `file_write` on that app root. After changing a deployed app, prefer `app_restart` to apply the update, then validate it with the safest available direct check such as logs, refreshed data, a screenshot tool, or `http_get` when available. If one validation tool is blocked, switch to another instead of retrying the blocked tool. Only prefer editing this existing deployed app when the user is clearly asking to fix, debug, or change it. Do not use `app_deploy` for a fix/debug follow-up on an existing deployed app unless the user explicitly asks to rebuild, replace, or redeploy it from scratch. If the user asks to build, create, deploy, or spin up an app without explicitly targeting this existing one, treat that as a fresh deployment instead. When you materially repurpose an existing app, include the new title in `app_restart` so the Apps list and links stay accurate.\n\
When linking the user to this app, always use the full URL from the Artifact URL field above (e.g. http://localhost:8990/apps/...). Never use a bare relative path like /apps/.../ — always provide a clickable absolute URL.\n",
                );
                system_prompt.push_str(
                    "If the user follows up with a short change request that omits the app name, assume they usually mean this deployed app unless they clearly switch topics or ask to build a different one.\n",
                );
            } else {
                system_prompt.push_str(
                    "If the user refers back to this artifact with short follow-ups like `this file`, `that doc`, `that event`, `it`, `delete it`, `update it`, or `download it`, treat this artifact as the default target unless they clearly switch topics. Do not claim you lost context just because the follow-up is brief. Prefer the related actions above first, and when no dedicated verb-specific action exists, use the related schema/help/command-style actions to discover the correct integration operation and execute it against this artifact id. If more than one artifact plausibly matches, ask a brief confirmation before making a destructive or irreversible change.\n",
                );
            }
            system_prompt.push_str(
                "If the user is clearly continuing work on this artifact, prefer the related actions. If they switched topics or are asking about AgentArk/workspace behavior itself, ignore this context.\n",
              );
        }
        if let Some(shape) = request_shape.as_ref() {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[shape]".to_string(),
                title: "Request Shape".to_string(),
                detail: format!(
                    "{} -> {} ({:.2} confidence)",
                    shape.shape, shape.execution_mode, shape.confidence
                ),
                step_type: if shape.should_confirm {
                    "warning".to_string()
                } else {
                    "info".to_string()
                },
                data: Some(format!(
                    "{}{}",
                    shape.reasoning,
                    if let Some(question) = shape.confirmation_question.as_ref() {
                        format!(" | confirmation_question={}", question)
                    } else {
                        String::new()
                    }
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }
        let mut preferred_action_names = boosted_action_names.clone();
        if let Some(shape) = request_shape.as_ref() {
            preferred_action_names.extend(shape.preferred_actions.iter().cloned());
        }
        if deep_research_requested
            && all_actions
                .iter()
                .any(|action| action.name.eq_ignore_ascii_case("research"))
        {
            preferred_action_names.insert("research".to_string());
        }
        augment_preferred_action_names_for_direct_execution(
            message,
            &all_actions,
            &mut preferred_action_names,
        );
        let confident_context_fast_path = request_shape
            .as_ref()
            .map(|shape| {
                !shape.should_confirm
                    && shape.confidence >= 0.86
                    && (context_followup || use_recent_artifact_context)
                    && matches!(shape.shape.as_str(), "conversation" | "inspection" | "app")
            })
            .unwrap_or(false);
        let skip_llm_action_selector = confident_context_fast_path
            && (context_followup || recent_artifact_prompt_context.is_some());
        let llm_selected_actions = if skip_llm_action_selector {
            None
        } else {
            self.select_actions_for_message_with_llm(
                channel,
                message,
                &all_actions,
                recent_artifact_prompt_context,
                request_shape.as_ref(),
                request_hints,
            )
            .await
        };
        let mut available_actions = llm_selected_actions.clone().unwrap_or_else(|| {
            select_actions_for_message(message, &all_actions, &preferred_action_names)
        });
        pin_preferred_actions(
            &mut available_actions,
            &all_actions,
            &preferred_action_names,
            10,
        );
        ensure_fresh_app_build_actions(
            &mut available_actions,
            &all_actions,
            MAX_SHORTLISTED_ACTIONS,
        );
        ensure_live_app_companion_actions(
            &mut available_actions,
            &all_actions,
            MAX_SHORTLISTED_ACTIONS,
        );
        if is_workspace_modification_request(message)
            && !direct_app_deploy_intent
            && !direct_schedule_task_intent
        {
            ensure_workspace_repair_actions(
                &mut available_actions,
                &all_actions,
                MAX_SHORTLISTED_ACTIONS,
            );
        }
        remove_shell_from_shortlist_for_live_app_requests(
            &mut available_actions,
            message,
            direct_app_deploy_intent,
            direct_schedule_task_intent,
        );
        if !boosted_action_names.is_empty() {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[ctx]".to_string(),
                title: "Recent Artifact Context".to_string(),
                detail: "Boosted related actions from the recent conversation artifact."
                    .to_string(),
                step_type: "info".to_string(),
                data: Some(format!(
                    "continuation_score={:.2}, artifact_reference={:.2}, competing_intent={:.2}, related_actions={}",
                    continuation_score,
                    artifact_reference,
                    competing_intent,
                    boosted_action_names
                        .iter()
                        .cloned()
                        .collect::<Vec<_>>()
                        .join(", ")
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }
        if let Some(selected) = llm_selected_actions.as_ref() {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[sel]".to_string(),
                title: "Action Selector".to_string(),
                detail: "Used the LLM to shortlist relevant actions from the full catalog."
                    .to_string(),
                step_type: "info".to_string(),
                data: Some(format!(
                    "selected_actions={}",
                    selected
                        .iter()
                        .map(|action| action.name.clone())
                        .collect::<Vec<_>>()
                        .join(", ")
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        } else if skip_llm_action_selector {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[zap]".to_string(),
                title: "Action Selector Fast Path".to_string(),
                detail:
                    "Skipped the action-selector model call for a high-confidence contextual follow-up."
                        .to_string(),
                step_type: "success".to_string(),
                data: Some(format!(
                    "context_followup={} | recent_artifact={} | shape={} | confidence={:.2}",
                    context_followup,
                    recent_artifact_prompt_context.is_some(),
                    request_shape
                        .as_ref()
                        .map(|shape| shape.shape.as_str())
                        .unwrap_or("unknown"),
                    request_shape
                        .as_ref()
                        .map(|shape| shape.confidence)
                        .unwrap_or(0.0)
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }
        system_prompt.push_str("\n\n");
        if let Some(shape) = request_shape.as_ref() {
            system_prompt.push_str("## Request Shape Assessment\n");
            system_prompt.push_str(&format!(
                "- Shape: {}\n- Execution mode: {}\n- Confidence: {:.2}\n- Planner reasoning: {}\n",
                shape.shape, shape.execution_mode, shape.confidence, shape.reasoning
            ));
            if !shape.preferred_actions.is_empty() {
                system_prompt.push_str(&format!(
                    "- Preferred actions suggested by the planner: {}\n",
                    shape
                        .preferred_actions
                        .iter()
                        .map(|name| format!("`{}`", name))
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            if shape.should_confirm {
                system_prompt.push_str(
                    "- The planner judged the request shape ambiguous enough that a short confirmation may be appropriate before execution.\n",
                );
            }
            system_prompt.push('\n');
        }
        system_prompt.push_str(&Self::build_runtime_access_summary(&available_actions));
        // Inject deployed app names so the model recognizes them without asking
        let deployed_apps = self.app_registry.list().await;
        tracing::info!(
            "Deployed apps for prompt injection: {} apps found",
            deployed_apps.len()
        );
        if !deployed_apps.is_empty() {
            let app_summaries: Vec<String> = deployed_apps
                .iter()
                .filter_map(|app| {
                    let id = app.get("id").and_then(|v| v.as_str()).unwrap_or("");
                    let title = app.get("title").and_then(|v| v.as_str()).unwrap_or(id);
                    if id.is_empty() {
                        return None;
                    }
                    let status = if app.get("port").and_then(|v| v.as_u64()).is_some() {
                        "running"
                    } else {
                        "static"
                    };
                    Some(format!("\"{}\" (id={}, {})", title, id, status))
                })
                .collect();
            if !app_summaries.is_empty() {
                system_prompt.push_str(&format!(
                    "\n- Deployed apps you manage: {}. When the user mentions an app by name, use `app_inspect` immediately — do NOT ask for a repo link or tech stack.\n",
                    app_summaries.join(", ")
                ));
            }
        }
        system_prompt.push('\n');
        system_prompt.push_str(&Self::build_action_catalog_prompt(&available_actions));
        let specialized_app_guidance =
            build_specialized_app_prompt_guidance(message, direct_app_deploy_intent);
        if !specialized_app_guidance.is_empty() {
            system_prompt.push('\n');
            system_prompt.push_str(&specialized_app_guidance);
            system_prompt.push('\n');
        }

        // Self-tune: inject learned preferences into prompt
        let self_tune_block =
            crate::core::self_tune::build_self_tune_prompt_block(&self.storage).await;
        if !self_tune_block.is_empty() {
            system_prompt.push_str(&self_tune_block);
        }

        let app_deploy_intent = direct_app_deploy_intent;
        let schedule_task_intent =
            direct_schedule_task_intent || boosted_action_names.contains("schedule_task");
        if app_deploy_intent {
            if let Some(tx) = token_tx.as_ref() {
                let _ = tx.try_send(StreamEvent::ToolProgress {
                    name: "app_deploy".to_string(),
                    content: "Preparing deployment plan and generating project files.".to_string(),
                    payload: None,
                });
            }
        }
        if schedule_task_intent {
            if let Some(tx) = token_tx.as_ref() {
                let _ = tx.try_send(StreamEvent::ToolProgress {
                    name: "schedule_task".to_string(),
                    content: "Preparing recurring execution after deployment.".to_string(),
                    payload: None,
                });
            }
        }
        if deep_research_requested {
            system_prompt.push_str(
                "\n## Explicit Research Mode\nThe user explicitly enabled deep research mode. Prefer the `research` capability or ask one short clarifying question if the research scope is unclear. Do not fall back to the cheap conversational path when source-backed research is still needed.\n",
            );
        }
        let duplicate_suppression_actions = all_actions
            .iter()
            .filter(|action| action_declares_duplicate_suppression(action))
            .map(|action| action.name.trim().to_ascii_lowercase())
            .collect::<std::collections::HashSet<_>>();
        let request_latched_actions = all_actions
            .iter()
            .filter(|action| {
                action_declares_duplicate_suppression(action)
                    && action_latches_request_after_accept(action)
            })
            .map(|action| action.name.trim().to_ascii_lowercase())
            .collect::<std::collections::HashSet<_>>();

        // 7. Routing decision
        let shape_allows_local_fast_path = request_shape
            .as_ref()
            .map(|shape| {
                shape.shape == "conversation" && !shape.should_confirm && shape.confidence >= 0.82
            })
            .unwrap_or(false);
        let local_routing_fast_path = (!context_followup
            && shape_allows_local_fast_path
            && should_use_local_routing_fast_path(message))
            || confident_context_fast_path;
        let routing_start = std::time::Instant::now();
        let (routing_decision, routing_mode) = if local_routing_fast_path {
            (
                self.classify_complexity_fallback(message, &all_actions)
                    .await,
                if confident_context_fast_path {
                    "context_fast_path"
                } else {
                    "local_fast_path"
                },
            )
        } else {
            (self.route_query(message, &all_actions).await, "llm_router")
        };
        let routing_ms = routing_start.elapsed().as_millis() as u64;
        let policy_version = self
            .active_routing_policy_version_for_message(message)
            .await;
        if local_routing_fast_path {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[zap]".to_string(),
                title: "Routing Fast Path".to_string(),
                detail: if confident_context_fast_path {
                    "High-confidence contextual follow-up routed from the semantic planner result (skipped router model call)."
                        .to_string()
                } else {
                    "Short conversational request routed from the semantic planner result (skipped router model call)."
                        .to_string()
                },
                step_type: "success".to_string(),
                data: Some(format!(
                    "mode={} | complexity={:?} | clarify={}",
                    routing_mode, routing_decision.complexity, routing_decision.should_clarify
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: Some(routing_ms),
            });
        }
        tracing::debug!(
            "Routing (mode={}): {:?} complexity, delegation={}, agents={} ({}ms)",
            routing_mode,
            routing_decision.complexity,
            routing_decision.needs_delegation,
            routing_decision.sub_agents.len(),
            routing_ms
        );
        self.advance_execution_run(
            &mut execution_run,
            &mut execution_checkpoint_seq,
            crate::core::ExecutionRunStatus::Routing,
            serde_json::json!({
                "mode": routing_mode,
                "complexity": format!("{:?}", routing_decision.complexity),
                "needs_delegation": routing_decision.needs_delegation,
                "confidence": routing_decision.confidence,
            }),
        )
        .await;
        self.log_operational_event(operational::OperationalEvent {
            event_type: "routing_decision",
            channel,
            success: true,
            outcome: "ok",
            trace_id: Some(&trace_id),
            conversation_id: Some(&conversation_key),
            tool_name: None,
            latency_ms: Some(routing_ms),
            arguments: None,
            payload: Some(&serde_json::json!({
                "complexity": format!("{:?}", routing_decision.complexity),
                "needs_delegation": routing_decision.needs_delegation,
                "sub_agents": routing_decision.sub_agents.len(),
                "confidence": routing_decision.confidence,
                "should_clarify": routing_decision.should_clarify,
                "mode": routing_mode,
                "reasoning": safe_truncate(&routing_decision.reasoning, 300),
                "strategy_task_type": strategy_task_type,
            })),
            strategy_version: strategy_version.as_deref(),
            policy_version: Some(policy_version.as_str()),
            prompt_version: Some(prompt_version.as_str()),
            model_slot: None,
        })
        .await;

        // 7b. Smart model routing
        let model_role = self.select_model_role(message, &routing_decision.complexity);
        let execution_request = self.execution_request_for_message(
            channel,
            &conversation_key,
            &model_role,
            &early_safe_message,
        );
        let mut selected_llm = self.llm_for_role(&model_role).clone();
        let mut model_slot_label = Self::model_role_label(&model_role).to_string();
        let mut model_selection_detail = format!(
            "Using {} model ({})",
            model_slot_label,
            selected_llm.model_name()
        );
        let user_selected_candidate = self.user_selected_llm_candidate();
        if let Some(candidate) = user_selected_candidate.as_ref() {
            selected_llm = candidate.client.clone();
            model_slot_label = Self::model_role_label(&candidate.role).to_string();
            model_selection_detail = format!(
                "Using user-selected model '{}' ({})",
                candidate.slot_label,
                selected_llm.model_name()
            );
        }

        // App deploy should be predictable: bypass smart-routing and use the normal
        // primary model unless the user explicitly selected a different slot.
        if app_deploy_intent && user_selected_candidate.is_none() {
            selected_llm = self.llm_for_role(&ModelRole::Primary).clone();
            model_slot_label = Self::model_role_label(&ModelRole::Primary).to_string();
            model_selection_detail = format!(
                "Using Primary model for app deploy ({})",
                selected_llm.model_name()
            );
        }

        let mut effective_model_slot_label = model_slot_label.clone();
        let mut effective_model_name = selected_llm.model_name().to_string();
        let main_execution_candidates = if app_deploy_intent && user_selected_candidate.is_none() {
            self.llm_candidates_for_role(&ModelRole::Primary)
        } else {
            self.llm_candidates_for_role(&model_role)
        };
        let main_execution_candidates = self
            .reorder_candidates_with_failover(
                main_execution_candidates,
                Some(conversation_key.as_str()),
            )
            .await;
        self.advance_execution_run(
            &mut execution_run,
            &mut execution_checkpoint_seq,
            crate::core::ExecutionRunStatus::ModelSelection,
            serde_json::json!({
                "selected_model": selected_llm.model_name(),
                "slot_label": model_slot_label.clone(),
                "candidate_count": main_execution_candidates.len(),
            }),
        )
        .await;

        {
            let mut trace = trace_ref.write().await;
            let (complexity_str, complexity_desc) = if routing_decision.needs_delegation {
                let agent_types: Vec<String> = routing_decision
                    .sub_agents
                    .iter()
                    .map(|s| s.agent_type.clone())
                    .collect();
                (
                    format!("{:?}", routing_decision.complexity),
                    format!(
                        "Auto-spawning {} agents: {}",
                        agent_types.len(),
                        agent_types.join(", ")
                    ),
                )
            } else {
                match routing_decision.complexity {
                    QueryComplexity::Simple => {
                        ("Simple".to_string(), "Direct LLM response".to_string())
                    }
                    QueryComplexity::Medium => {
                        ("Medium".to_string(), "Parallel Thinking".to_string())
                    }
                    QueryComplexity::Complex => (
                        "Complex".to_string(),
                        "Direct LLM (no delegation needed)".to_string(),
                    ),
                }
            };
            trace.steps.push(ExecutionStep {
                icon: "\u{1F3AF}".to_string(),
                title: "LLM Routing Decision".to_string(),
                detail: format!("{} \u{2192} {}", complexity_str, complexity_desc),
                step_type: "thinking".to_string(),
                data: Some(format!(
                    "{} | Confidence: {:.2} | Clarify: {} | Actions: {}",
                    routing_decision.reasoning,
                    routing_decision.confidence,
                    routing_decision.should_clarify,
                    available_actions.len()
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: Some(routing_ms),
            });

            trace.steps.push(ExecutionStep {
                icon: "\u{1F9ED}".to_string(),
                title: "Model Selection".to_string(),
                detail: model_selection_detail,
                step_type: "info".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        // 8. Execute based on routing decision
        let llm_start = std::time::Instant::now();

        let execution_intent = has_execution_intent(message, &available_actions);
        let execution_intent_score = best_execution_intent_score(message, &available_actions);
        let self_contained_brief = is_detailed_execution_brief(message, &available_actions);
        let msg_word_count = message.split_whitespace().count();
        let ambiguous_request = is_ambiguous_user_request(message, &available_actions);
        let document_answer_ready = should_skip_clarification_for_document_context(
            message,
            doc_context.is_some(),
            execution_intent,
        );
        let capability_fast_path_response = maybe_answer_short_capability_question(
            message,
            &available_actions,
            &preferred_action_names,
        );
        let clear_execution_request = execution_intent
            && !ambiguous_request
            && (self_contained_brief || execution_intent_score >= 0.65 || msg_word_count >= 40);
        let request_shape_confirmation = request_shape.as_ref().filter(|shape| {
            shape.should_confirm
                && !self_contained_brief
                && !clear_execution_request
                && recent_artifact_prompt_context.is_none()
        });
        let force_ambiguity_clarification = routing_decision.should_clarify
            && ambiguous_request
            && !context_followup
            && recent_artifact_prompt_context.is_none();
        let needs_clarification = if self_contained_brief
            || clear_execution_request
            || document_answer_ready
            || (!boosted_action_names.is_empty() && use_recent_artifact_context)
        {
            false
        } else {
            request_shape_confirmation.is_some()
                || force_ambiguity_clarification
                || (routing_decision.should_clarify
                    && recent_artifact_prompt_context.is_none()
                    && routing_decision.confidence < 0.78
                    && (ambiguous_request || !execution_intent))
        };

        if routing_decision.should_clarify && (self_contained_brief || clear_execution_request) {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "\u{2705}".to_string(),
                title: "Autopilot Proceed".to_string(),
                detail:
                    "Request is detailed enough to execute directly with defaults and validation."
                        .to_string(),
                step_type: "success".to_string(),
                data: Some(format!(
                    "confidence={:.2}, execution_score={:.2}",
                    routing_decision.confidence, execution_intent_score
                )),
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        if routing_decision.should_clarify && document_answer_ready {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "\u{1F4C4}".to_string(),
                title: "Document Context Ready".to_string(),
                detail:
                    "Indexed document context matched the request, so AgentArk answered directly."
                        .to_string(),
                step_type: "success".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: None,
            });
        }

        let mut llm_result = if let Some(capability_response) = capability_fast_path_response {
            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "\u{1F50E}".to_string(),
                    title: "Capability Answer".to_string(),
                    detail: "Answered directly from the live scoped action catalog.".to_string(),
                    step_type: "success".to_string(),
                    data: Some(capability_response.clone()),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }
            super::llm::LlmResponse {
                content: capability_response,
                tool_calls: vec![],
                reasoning: None,
                usage: None,
                provider: "internal".to_string(),
                model: "".to_string(),
            }
        } else if needs_clarification {
            let clarification = request_shape_confirmation
                .and_then(|shape| shape.confirmation_question.clone())
                .or_else(|| routing_decision.clarification_question.clone())
                .unwrap_or_else(|| {
                    "I can do that. Do you want me to execute it now or first show a plan?"
                        .to_string()
                });

            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "\u{2753}".to_string(),
                    title: "Clarification Needed".to_string(),
                    detail: "Routing confidence is below execution threshold".to_string(),
                    step_type: "warning".to_string(),
                    data: Some(clarification.clone()),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }

            super::llm::LlmResponse {
                content: clarification,
                tool_calls: vec![],
                reasoning: None,
                usage: None,
                provider: "internal".to_string(),
                model: "".to_string(),
            }
        } else {
            // Get specialist references for the task router
            let specialists = self.swarm.as_ref().map(|s| s.specialists.clone());

            let should_generate_execution_plan = execution_intent
                && !ambiguous_request
                && (routing_decision.complexity == QueryComplexity::Complex
                    || app_deploy_intent
                    || schedule_task_intent);

            // ── Planning phase: generate a structured plan before execution ──
            if should_generate_execution_plan {
                self.advance_execution_run(
                    &mut execution_run,
                    &mut execution_checkpoint_seq,
                    crate::core::ExecutionRunStatus::Planning,
                    serde_json::json!({
                        "deep_research": deep_research_requested,
                        "app_deploy_intent": app_deploy_intent,
                        "schedule_task_intent": schedule_task_intent,
                    }),
                )
                .await;
                if let Some(tx) = token_tx.as_ref() {
                    let _ = tx.try_send(StreamEvent::Thinking(
                        "Writing execution plan...".to_string(),
                    ));
                }

                let (plan_system, plan_user) =
                    Self::build_planning_prompt(message, &available_actions);
                let plan_start = std::time::Instant::now();
                let mut steps = Vec::new();
                let mut plan_warning: Option<String> = None;

                match run_timed_llm_call_with_heartbeat(
                    &selected_llm,
                    &plan_system,
                    &plan_user,
                    &[],
                    &[],
                    &[],
                    token_tx.clone(),
                    PLANNING_LLM_TIMEOUT_SECS,
                    "Writing execution plan",
                    false,
                    "llm",
                )
                .await
                {
                    TimedLlmCallOutcome::Success(plan_response) => {
                        self.record_llm_usage(channel, "planning", &plan_response)
                            .await;
                        steps = normalize_plan_for_observable_progress(
                            parse_plan_steps_from_llm_content(
                                &plan_response.content,
                                &available_actions,
                            ),
                        );
                        if steps.is_empty() {
                            plan_warning = Some(
                                "Planner returned an invalid checklist, so I switched to a fast fallback plan."
                                    .to_string(),
                            );
                        }
                    }
                    TimedLlmCallOutcome::Error(err) => {
                        tracing::warn!("Planning failed: {}", err);
                        plan_warning = Some(
                            "Planning failed on the model, so I switched to a fast fallback plan."
                                .to_string(),
                        );
                    }
                    TimedLlmCallOutcome::TimedOut => {
                        tracing::warn!(
                            "Planning timed out after {} seconds; using fast fallback plan",
                            PLANNING_LLM_TIMEOUT_SECS
                        );
                        plan_warning = Some(format!(
                            "Planning was slow, so I switched to a fast fallback plan after {} seconds.",
                            PLANNING_LLM_TIMEOUT_SECS
                        ));
                    }
                }

                if steps.is_empty() {
                    steps = build_fast_fallback_execution_plan(
                        message,
                        app_deploy_intent,
                        schedule_task_intent,
                    );
                }

                if !steps.is_empty() {
                    let plan_ms = plan_start.elapsed().as_millis() as u64;

                    {
                        let mut trace = trace_ref.write().await;
                        trace.plan = Some(steps.clone());
                        trace.steps.push(ExecutionStep {
                            icon: "\u{1F4CB}".to_string(),
                            title: "Execution Plan".to_string(),
                            detail: format!("{} steps planned", steps.len()),
                            step_type: "plan".to_string(),
                            data: Some(serde_json::to_string(&steps).unwrap_or_default()),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(plan_ms),
                        });
                        if let Some(note) = plan_warning.as_ref() {
                            trace.steps.push(ExecutionStep {
                                icon: "[fallback]".to_string(),
                                title: "Plan Fallback Used".to_string(),
                                detail: note.clone(),
                                step_type: "warning".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: Some(plan_ms),
                            });
                        }
                        mark_execution_plan_started(&mut trace);
                    }

                    if let Some(tx) = token_tx.as_ref() {
                        if let Some(note) = plan_warning.as_ref() {
                            let _ = tx.try_send(StreamEvent::Thinking(note.clone()));
                        }
                        let _ = tx.try_send(StreamEvent::PlanGenerated {
                            steps: steps.clone(),
                        });
                        if let Some(first_step) = steps.first() {
                            let _ = tx.try_send(StreamEvent::PlanStepUpdate {
                                step_id: first_step.id,
                                status: PlanStepStatus::Running,
                                detail: Some("Execution started".to_string()),
                            });
                        }
                    }

                    let plan_text = steps
                        .iter()
                        .map(|s| format!("{}. {} - {}", s.id, s.title, s.description))
                        .collect::<Vec<_>>()
                        .join("\n");
                    system_prompt.push_str(&format!(
                        "\n\n## Execution Plan\n\
                        Follow this plan step-by-step. Execute each step using the appropriate tool call.\n\
                        {}\n\
                        After completing each step, proceed to the next. \
                        Report the final result after the last step.",
                        plan_text
                    ));
                }
            }

            tracing::info!(
                "Task router executing: needs_delegation={}, complexity={:?}",
                routing_decision.needs_delegation,
                routing_decision.complexity
            );
            let router_start = std::time::Instant::now();
            let router_heartbeat = start_stream_heartbeat(
                token_tx.as_ref(),
                "Coordinating execution strategy",
                selected_llm.model_name(),
            );
            let router_result = match self
                .task_router
                .execute(
                    &routing_decision,
                    super::task_router::TaskRouterExecuteContext {
                        message,
                        system_prompt: &system_prompt,
                        model_pool: &self.model_pool,
                        primary_llm: &selected_llm,
                        specialists: &specialists,
                        memories: &relevant_memories,
                        actions: &available_actions,
                        trace: &trace_ref,
                    },
                )
                .await
            {
                Ok(result) => {
                    stop_stream_heartbeat(router_heartbeat);
                    result
                }
                Err(err) => {
                    stop_stream_heartbeat(router_heartbeat);
                    let error_text = format!("Task router execution failed: {}", err);
                    tracing::warn!("{}", error_text);
                    degradation_notes.push(crate::core::DegradationNote {
                        kind: "delegation".to_string(),
                        summary: "task-router fallback".to_string(),
                        detail: Some(safe_truncate(&error_text, 400)),
                    });
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                                icon: "[warn]".to_string(),
                                title: "Task Router Fallback".to_string(),
                                detail:
                                    "Delegation failed before completion; falling back to direct execution."
                                        .to_string(),
                                step_type: "warning".to_string(),
                                data: Some(safe_truncate(&error_text, 280)),
                                timestamp: chrono::Utc::now(),
                                duration_ms: Some(router_start.elapsed().as_millis() as u64),
                            });
                    }
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "delegation".to_string(),
                                content:
                                    "Delegation path degraded; continuing with a direct execution fallback."
                                        .to_string(),
                                payload: Some(serde_json::json!({
                                    "kind": "delegation_fallback",
                                    "reason": safe_truncate(&error_text, 220),
                                })),
                            });
                    }
                    super::task_router::TaskRouterResult::Direct
                }
            };
            let router_result = if app_deploy_intent {
                match router_result {
                    super::task_router::TaskRouterResult::UseParallelThinking => {
                        tracing::info!(
                            "App deploy request bypassing parallel thinking and using the direct execution path"
                        );
                        {
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[app]".to_string(),
                                title: "App Deploy Fast Path".to_string(),
                                detail:
                                    "Bypassing parallel reasoning so deployment can proceed directly to tool planning."
                                        .to_string(),
                                step_type: "info".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                        }
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content:
                                    "Skipping parallel reasoning and switching to direct deploy planning."
                                        .to_string(),
                                payload: Some(serde_json::json!({
                                    "kind": "deploy_fast_path",
                                    "reason": "app_deploy_bypass_parallel"
                                })),
                            });
                        }
                        super::task_router::TaskRouterResult::Direct
                    }
                    other => other,
                }
            } else {
                router_result
            };

            tracing::info!(
                "Task router done in {}ms → {:?}",
                router_start.elapsed().as_millis(),
                match &router_result {
                    super::task_router::TaskRouterResult::Delegated(_) => "Delegated",
                    super::task_router::TaskRouterResult::UseParallelThinking => "ParallelThinking",
                    super::task_router::TaskRouterResult::Direct => "Direct",
                }
            );
            match router_result {
                super::task_router::TaskRouterResult::Delegated(result) => {
                    if !result.degradation.is_empty() {
                        degradation_notes.extend(result.degradation.iter().cloned());
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[agents]".to_string(),
                            title: "Delegation Degraded".to_string(),
                            detail: format!(
                                "Delegated execution completed with status={}",
                                result.delegation_status.as_str()
                            ),
                            step_type: "warning".to_string(),
                            data: result
                                .degradation
                                .iter()
                                .filter_map(|note| note.detail.clone())
                                .next(),
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    // Auto-spawned agents completed - preserve tool calls for execution.
                    result.final_response.clone()
                }
                super::task_router::TaskRouterResult::UseParallelThinking => {
                    // Medium complexity - use parallel thinking
                    tracing::info!("Using Parallel Thinking for improved reasoning");
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "\u{1F500}".to_string(),
                            title: "Parallel Thinking Started".to_string(),
                            detail: "Exploring multiple reasoning paths".to_string(),
                            step_type: "thinking".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    let llm_candidates = &main_execution_candidates;
                    let mut parallel_errors: Vec<String> = Vec::new();
                    let mut result_opt: Option<crate::core::parallel::ParallelResult> = None;
                    for (idx, candidate) in llm_candidates.iter().enumerate() {
                        let attempt_start = std::time::Instant::now();
                        if idx > 0 {
                            if let Some(tx) = token_tx.as_ref() {
                                let _ = tx.try_send(StreamEvent::ToolProgress {
                                    name: "llm".to_string(),
                                    content: format!(
                                        "Parallel-thinking self-heal: switching to {} ({})",
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    ),
                                    payload: Some(serde_json::json!({
                                        "kind": "model_fallback",
                                        "slot_id": candidate.slot_id,
                                        "slot_label": candidate.slot_label,
                                        "model": candidate.client.model_name(),
                                        "attempt": idx + 1,
                                        "phase": "parallel_thinking"
                                    })),
                                });
                            }
                        }
                        let llm_arc = Arc::new(candidate.client.clone());
                        let parallel_heartbeat = start_stream_heartbeat(
                            token_tx.as_ref(),
                            "Exploring reasoning paths",
                            candidate.client.model_name(),
                        );
                        match self
                            .parallel_controller
                            .think_with_llm(
                                llm_arc,
                                &system_prompt,
                                message,
                                &relevant_memories,
                                &available_actions,
                            )
                            .await
                        {
                            Ok(result) => {
                                stop_stream_heartbeat(parallel_heartbeat);
                                self.record_model_attempt(
                                    &mut attempted_models,
                                    &mut attempt_records,
                                    candidate,
                                    true,
                                    None,
                                    idx > 0,
                                    attempt_start.elapsed().as_millis() as u64,
                                    Some(conversation_key.as_str()),
                                )
                                .await;
                                selected_llm = candidate.client.clone();
                                effective_model_slot_label =
                                    Self::model_role_label(&candidate.role).to_string();
                                effective_model_name = candidate.client.model_name().to_string();
                                if idx > 0 {
                                    let mut trace = trace_ref.write().await;
                                    trace.steps.push(ExecutionStep {
                                        icon: "[ok]".to_string(),
                                        title: "Parallel Self-Heal Recovered".to_string(),
                                        detail: format!(
                                            "Recovered with {} ({})",
                                            candidate.slot_label,
                                            candidate.client.model_name()
                                        ),
                                        step_type: "success".to_string(),
                                        data: None,
                                        timestamp: chrono::Utc::now(),
                                        duration_ms: None,
                                    });
                                }
                                result_opt = Some(result);
                                break;
                            }
                            Err(e) => {
                                stop_stream_heartbeat(parallel_heartbeat);
                                let failure_text = e.to_string();
                                self.record_model_attempt(
                                    &mut attempted_models,
                                    &mut attempt_records,
                                    candidate,
                                    false,
                                    Some(failure_text.as_str()),
                                    idx > 0,
                                    attempt_start.elapsed().as_millis() as u64,
                                    Some(conversation_key.as_str()),
                                )
                                .await;
                                let err_msg = format!(
                                    "{} ({}) failed: {}",
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    failure_text
                                );
                                tracing::warn!(
                                    "Parallel thinking model attempt failed: {}",
                                    err_msg
                                );
                                parallel_errors.push(err_msg);
                            }
                        }
                    }
                    let Some(result) = result_opt else {
                        let mut failure_outcome = self.execution_supervisor.build_failure_outcome(
                            &execution_request,
                            &attempt_records,
                            &degradation_notes,
                        );
                        enrich_supervisor_outcome_with_model_failures(
                            &mut failure_outcome.user_outcome,
                        );
                        let response = failure_outcome.user_outcome.message.clone();
                        if !conversation_key.is_empty() {
                            let err_msg = crate::storage::entities::message::Model {
                                id: uuid::Uuid::new_v4().to_string(),
                                conversation_id: conversation_key.clone(),
                                role: "assistant".to_string(),
                                content: response.clone(),
                                timestamp: chrono::Utc::now().to_rfc3339(),
                                model_used: Some("error".to_string()),
                                trace_id: Some(trace_id.clone()),
                            };
                            if let Err(error) = self
                                .encrypted_storage
                                .insert_message_encrypted(&err_msg)
                                .await
                            {
                                tracing::warn!(
                                    "Failed to persist supervised parallel outcome: {}",
                                    error
                                );
                            }
                        }
                        let run_status =
                            Self::execution_run_status_for_outcome(&failure_outcome.user_outcome);
                        let run_status_text = run_status.as_str().to_string();
                        let run_id = execution_run.id.clone();
                        self.finalize_supervised_user_outcome(
                            &trace_ref,
                            &mut execution_run,
                            &mut execution_checkpoint_seq,
                            message,
                            channel,
                            Some(&conversation_key),
                            project_id,
                            Some(prompt_version.as_str()),
                            strategy_version.as_deref(),
                            Some(policy_version.as_str()),
                            Some(effective_model_slot_label.as_str()),
                            &response,
                            &failure_outcome.user_outcome,
                            &degradation_notes,
                        )
                        .await;
                        return Ok(ProcessedMessage {
                            response,
                            conversation_id: Some(conversation_key.clone()),
                            conversation_title: None,
                            run_id: Some(run_id),
                            run_status: Some(run_status_text),
                            trace_id: Some(trace_id.clone()),
                            degradation: degradation_notes.clone(),
                            attempted_models: attempted_models.clone(),
                            user_outcome: Some(failure_outcome.user_outcome),
                        });
                    };

                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "\u{2705}".to_string(),
                            title: "Parallel Thinking Complete".to_string(),
                            detail: format!(
                                "{} paths explored, {:.1}% cost savings",
                                result.path_results.len(),
                                result.cost_savings_percent()
                            ),
                            step_type: "success".to_string(),
                            data: Some(format!("Confidence: {:.2}", result.confidence())),
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }

                    result.final_response.clone()
                }
                super::task_router::TaskRouterResult::Direct => {
                    // Simple/direct - single LLM call with conversation history
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "\u{1F916}".to_string(),
                            title: "LLM Request".to_string(),
                            detail: "Direct query to language model".to_string(),
                            step_type: "thinking".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    tracing::info!("Starting main LLM call (streaming={})", token_tx.is_some());
                    let main_llm_start = std::time::Instant::now();
                    let llm_candidates = &main_execution_candidates;
                    let mut model_errors: Vec<String> = Vec::new();
                    let mut main_resp_opt: Option<super::llm::LlmResponse> = None;

                    for (idx, candidate) in llm_candidates.iter().enumerate() {
                        let attempt_start = std::time::Instant::now();
                        if idx > 0 {
                            if let Some(tx) = token_tx.as_ref() {
                                let _ = tx.try_send(StreamEvent::ToolProgress {
                                    name: "llm".to_string(),
                                    content: format!(
                                        "Self-heal: switching to {} ({})",
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    ),
                                    payload: Some(serde_json::json!({
                                        "kind": "model_fallback",
                                        "slot_id": candidate.slot_id,
                                        "slot_label": candidate.slot_label,
                                        "model": candidate.client.model_name(),
                                        "attempt": idx + 1,
                                    })),
                                });
                            }
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[retry]".to_string(),
                                title: "LLM Self-Heal Retry".to_string(),
                                detail: format!(
                                    "Retrying with {} ({})",
                                    candidate.slot_label,
                                    candidate.client.model_name()
                                ),
                                step_type: "warning".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                        }

                        let attempt = if let Some(tx) = token_tx.clone() {
                            let tx_for_fallback = tx.clone();
                            match candidate
                                .client
                                .chat_with_history_stream(
                                    &system_prompt,
                                    message,
                                    &conversation_history,
                                    &relevant_memories,
                                    &available_actions,
                                    tx,
                                )
                                .await
                            {
                                Ok(resp) => Ok(resp),
                                Err(stream_err) => {
                                    tracing::warn!(
                                        "Streaming failed for model {} after {}ms, trying non-streaming fallback: {}",
                                        candidate.client.model_name(),
                                        main_llm_start.elapsed().as_millis(),
                                        stream_err
                                    );

                                    let heartbeat_tx = tx_for_fallback.clone();
                                    let heartbeat_model = candidate.client.model_name().to_string();
                                    let heartbeat_flag = std::sync::Arc::new(
                                        std::sync::atomic::AtomicBool::new(false),
                                    );
                                    let hb_flag_clone = heartbeat_flag.clone();

                                    // Spawn heartbeat: emit Thinking events every 5s so UI shows activity
                                    let heartbeat_handle = tokio::spawn(async move {
                                        let mut elapsed_secs = 0u64;
                                        loop {
                                            tokio::time::sleep(std::time::Duration::from_secs(5))
                                                .await;
                                            if hb_flag_clone
                                                .load(std::sync::atomic::Ordering::Relaxed)
                                            {
                                                break;
                                            }
                                            elapsed_secs += 5;
                                            let status = format!(
                                                "Model {} is generating ({}s elapsed)...",
                                                heartbeat_model, elapsed_secs
                                            );
                                            if heartbeat_tx
                                                .try_send(StreamEvent::Thinking(status))
                                                .is_err()
                                            {
                                                break;
                                            }
                                        }
                                    });

                                    // Retry the non-streaming fallback up to 2 attempts
                                    let mut non_stream_result = None;
                                    let mut last_non_stream_err = None;
                                    for ns_attempt in 0..2u32 {
                                        if ns_attempt > 0 {
                                            tracing::warn!(
                                                "Non-streaming fallback retry {}/2 for model {}",
                                                ns_attempt + 1,
                                                candidate.client.model_name(),
                                            );
                                            tokio::time::sleep(std::time::Duration::from_secs(1))
                                                .await;
                                        }
                                        match candidate
                                            .client
                                            .chat_with_history(
                                                &system_prompt,
                                                message,
                                                &conversation_history,
                                                &relevant_memories,
                                                &available_actions,
                                            )
                                            .await
                                        {
                                            Ok(resp) => {
                                                non_stream_result = Some(resp);
                                                break;
                                            }
                                            Err(e) => {
                                                tracing::warn!(
                                                    "Non-streaming fallback attempt {} failed: {}",
                                                    ns_attempt + 1,
                                                    e,
                                                );
                                                last_non_stream_err = Some(e);
                                            }
                                        }
                                    }

                                    // Stop heartbeat
                                    heartbeat_flag
                                        .store(true, std::sync::atomic::Ordering::Relaxed);
                                    heartbeat_handle.abort();

                                    // Simulate streaming: emit response as chunked tokens for progressive UI delivery
                                    if let Some(ref resp) = non_stream_result {
                                        let text = &resp.content;
                                        if !text.is_empty() {
                                            // Emit in ~200-char chunks for smooth progressive rendering
                                            let mut pos = 0;
                                            while pos < text.len() {
                                                let end = (pos + 200).min(text.len());
                                                // Snap to nearest newline or space to avoid splitting words
                                                let snap = if end < text.len() {
                                                    text[pos..end]
                                                        .rfind('\n')
                                                        .or_else(|| text[pos..end].rfind(' '))
                                                        .map(|i| pos + i + 1)
                                                        .unwrap_or(end)
                                                } else {
                                                    end
                                                };
                                                let chunk = &text[pos..snap];
                                                let _ = tx_for_fallback.try_send(
                                                    StreamEvent::Token(chunk.to_string()),
                                                );
                                                pos = snap;
                                                // Small yield to let the SSE event flush to the client
                                                tokio::task::yield_now().await;
                                            }
                                        }
                                    }

                                    match non_stream_result {
                                        Some(resp) => Ok(resp),
                                        None => Err(anyhow::anyhow!(
                                            "stream={} | non_stream={}",
                                            stream_err,
                                            last_non_stream_err.unwrap_or_else(|| anyhow::anyhow!(
                                                "no attempts made"
                                            ))
                                        )),
                                    }
                                }
                            }
                        } else {
                            candidate
                                .client
                                .chat_with_history(
                                    &system_prompt,
                                    message,
                                    &conversation_history,
                                    &relevant_memories,
                                    &available_actions,
                                )
                                .await
                        };

                        match attempt {
                            Ok(resp) => {
                                self.record_model_attempt(
                                    &mut attempted_models,
                                    &mut attempt_records,
                                    candidate,
                                    true,
                                    None,
                                    idx > 0,
                                    attempt_start.elapsed().as_millis() as u64,
                                    Some(conversation_key.as_str()),
                                )
                                .await;
                                selected_llm = candidate.client.clone();
                                effective_model_slot_label =
                                    Self::model_role_label(&candidate.role).to_string();
                                effective_model_name = candidate.client.model_name().to_string();
                                if idx > 0 {
                                    let mut trace = trace_ref.write().await;
                                    trace.steps.push(ExecutionStep {
                                        icon: "[ok]".to_string(),
                                        title: "LLM Self-Heal Recovered".to_string(),
                                        detail: format!(
                                            "Recovered with {} ({})",
                                            candidate.slot_label,
                                            candidate.client.model_name()
                                        ),
                                        step_type: "success".to_string(),
                                        data: None,
                                        timestamp: chrono::Utc::now(),
                                        duration_ms: None,
                                    });
                                }
                                main_resp_opt = Some(resp);
                                break;
                            }
                            Err(e) => {
                                let error_string = e.to_string();
                                self.record_model_attempt(
                                    &mut attempted_models,
                                    &mut attempt_records,
                                    candidate,
                                    false,
                                    Some(error_string.as_str()),
                                    idx > 0,
                                    attempt_start.elapsed().as_millis() as u64,
                                    Some(conversation_key.as_str()),
                                )
                                .await;
                                let err_msg = format!(
                                    "{} ({}) failed: {}",
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    error_string
                                );
                                tracing::warn!("Main LLM attempt failed: {}", err_msg);
                                model_errors.push(err_msg);
                            }
                        }
                    }

                    let Some(main_resp) = main_resp_opt else {
                        let mut failure_outcome = self.execution_supervisor.build_failure_outcome(
                            &execution_request,
                            &attempt_records,
                            &degradation_notes,
                        );
                        enrich_supervisor_outcome_with_model_failures(
                            &mut failure_outcome.user_outcome,
                        );
                        let response = failure_outcome.user_outcome.message.clone();
                        if !conversation_key.is_empty() {
                            let err_msg = crate::storage::entities::message::Model {
                                id: uuid::Uuid::new_v4().to_string(),
                                conversation_id: conversation_key.clone(),
                                role: "assistant".to_string(),
                                content: response.clone(),
                                timestamp: chrono::Utc::now().to_rfc3339(),
                                model_used: Some("error".to_string()),
                                trace_id: Some(trace_id.clone()),
                            };
                            if let Err(error) = self
                                .encrypted_storage
                                .insert_message_encrypted(&err_msg)
                                .await
                            {
                                tracing::warn!(
                                    "Failed to persist supervised main-model outcome: {}",
                                    error
                                );
                            }
                        }
                        let run_status =
                            Self::execution_run_status_for_outcome(&failure_outcome.user_outcome);
                        let run_status_text = run_status.as_str().to_string();
                        let run_id = execution_run.id.clone();
                        self.finalize_supervised_user_outcome(
                            &trace_ref,
                            &mut execution_run,
                            &mut execution_checkpoint_seq,
                            message,
                            channel,
                            Some(&conversation_key),
                            project_id,
                            Some(prompt_version.as_str()),
                            strategy_version.as_deref(),
                            Some(policy_version.as_str()),
                            Some(effective_model_slot_label.as_str()),
                            &response,
                            &failure_outcome.user_outcome,
                            &degradation_notes,
                        )
                        .await;
                        return Ok(ProcessedMessage {
                            response,
                            conversation_id: Some(conversation_key.clone()),
                            conversation_title: None,
                            run_id: Some(run_id),
                            run_status: Some(run_status_text),
                            trace_id: Some(trace_id.clone()),
                            degradation: degradation_notes.clone(),
                            attempted_models: attempted_models.clone(),
                            user_outcome: Some(failure_outcome.user_outcome),
                        });
                    };
                    tracing::info!(
                        "Main LLM done ← {}ms, content={}chars, tool_calls={}",
                        main_llm_start.elapsed().as_millis(),
                        main_resp.content.len(),
                        main_resp.tool_calls.len()
                    );
                    main_resp
                }
            }
        };

        let repo_source_requested = request_mentions_repo_source(message);
        let app_deploy_files_missing = |args: &serde_json::Value| -> bool {
            let normalized = Self::normalize_app_deploy_arguments(args);
            let has_files = normalized
                .get("files")
                .and_then(|v| v.as_object())
                .map(|m| m.is_empty())
                .map(|is_empty| !is_empty)
                .unwrap_or(false);
            let has_repo_url = normalized
                .get("repo_url")
                .and_then(|v| v.as_str())
                .is_some_and(|value| !value.trim().is_empty());
            let missing = !(has_files || has_repo_url);
            if missing {
                let raw_keys = args
                    .as_object()
                    .map(|o| o.keys().cloned().collect::<Vec<_>>().join(", "))
                    .unwrap_or_else(|| {
                        format!(
                            "(not object: {})",
                            args.to_string().chars().take(200).collect::<String>()
                        )
                    });
                let raw_snippet: String = args.to_string().chars().take(500).collect();
                tracing::warn!(
                    "app_deploy payload missing source — raw keys: [{}], raw snippet: {}",
                    raw_keys,
                    raw_snippet
                );
            }
            missing
        };
        let file_write_missing_required_fields = |call: &crate::core::llm::ToolCall| -> bool {
            if call.name != "file_write" {
                return false;
            }
            let has_path = call
                .arguments
                .get("path")
                .and_then(|v| v.as_str())
                .or_else(|| call.arguments.get("file_path").and_then(|v| v.as_str()))
                .or_else(|| call.arguments.get("filename").and_then(|v| v.as_str()))
                .is_some_and(|value| !value.trim().is_empty());
            let has_content = call
                .arguments
                .get("content")
                .and_then(|v| v.as_str())
                .or_else(|| call.arguments.get("text").and_then(|v| v.as_str()))
                .or_else(|| call.arguments.get("body").and_then(|v| v.as_str()))
                .is_some_and(|value| !value.is_empty());
            !(has_path && has_content)
        };

        let needs_live_app_file_write_repair = app_deploy_intent
            && !llm_result
                .tool_calls
                .iter()
                .any(|tc| tc.name == "app_deploy")
            && llm_result
                .tool_calls
                .iter()
                .any(file_write_missing_required_fields);

        if needs_live_app_file_write_repair {
            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[fix]".to_string(),
                    title: "Redirecting Broken File Writes".to_string(),
                    detail: if repo_source_requested {
                        "Model emitted invalid file_write calls for a repo deploy request; regenerating a valid repo app_deploy."
                            .to_string()
                    } else {
                        "Model emitted invalid staged file writes for a live app request; regenerating valid file writes before deploy."
                            .to_string()
                    },
                    step_type: "warning".to_string(),
                    data: None,
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }

            if let Some(tx) = token_tx.as_ref() {
                let _ = tx.try_send(StreamEvent::ToolProgress {
                    name: if repo_source_requested {
                        "app_deploy".to_string()
                    } else {
                        "file_write".to_string()
                    },
                    content: if repo_source_requested {
                        "Broken file-write plan detected. Regenerating as a repo deploy."
                            .to_string()
                    } else {
                        "Broken staged file plan detected. Regenerating valid file writes before deploy."
                            .to_string()
                    },
                    payload: Some(serde_json::json!({
                        "kind": "argument_stream",
                        "stage": "payload_repair",
                        "stream_key": if repo_source_requested {
                            "argument-stream:app_deploy"
                        } else {
                            "argument-stream:file_write"
                        },
                    })),
                });
            }

            let response_excerpt: String = llm_result.content.chars().take(1200).collect();
            let repair_prompt = format!(
                "Original user request:\n{}\n\nPrevious assistant response (excerpt):\n{}\n\n\
Your previous response emitted invalid `file_write` tool calls without the required `path` and/or `content`. \
{}\
{}\
{}\
Do not ask the user for JSON.",
                message,
                response_excerpt,
                if repo_source_requested {
                    "For this repo deploy request, stop using `file_write` and stop using `shell`. Retry now by emitting a valid `app_deploy` tool call with `repo_url` (and optionally `repo_ref`, `repo_subdir`, `service_mode`) so AgentArk can clone and deploy the repo. "
                } else {
                    "For this generated live app request, keep `file_write` as the primary path. Retry now by emitting valid `file_write` calls under `/app/data/apps/new/<slug>/...` for the generated source files, then continue to deploy from those staged files. Do not skip the file writes. "
                },
                if repo_source_requested {
                    "If the app needs a runtime, include or infer `entry_command`. ".to_string()
                } else {
                    "After the staged writes, you may emit `app_deploy` without inlining the full codebase again, or let AgentArk recover the deploy from the staged files. ".to_string()
                },
                if schedule_task_intent {
                    "If recurring execution is needed, you may also emit `schedule_task` after deployment. "
                } else {
                    ""
                }
            );

            let repair_prompt = format!(
                "{}\n\nIf the earlier draft looks too large or truncated, rebuild a smaller complete app from scratch. Prefer regular project files over giant inline shell bootstraps or long `python -c` commands.",
                repair_prompt
            );

            let repair_candidates = self.llm_candidates_for_role(&model_role);
            let max_repair_attempts = repair_candidates.len().clamp(1, 3);
            let mut repair_errors: Vec<String> = Vec::new();
            let mut repair_succeeded = false;
            for (idx, candidate) in repair_candidates
                .iter()
                .take(max_repair_attempts)
                .enumerate()
            {
                let attempt = idx + 1;
                if attempt > 1 {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[retry]".to_string(),
                        title: "Retrying Live App Repair".to_string(),
                        detail: format!(
                            "Repair attempt {} of {} with {} ({}).",
                            attempt,
                            max_repair_attempts,
                            candidate.slot_label,
                            candidate.client.model_name()
                        ),
                        step_type: "warning".to_string(),
                        data: None,
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                }

                let repair_outcome = run_timed_llm_call_with_heartbeat(
                    &candidate.client,
                    &system_prompt,
                    &repair_prompt,
                    &conversation_history,
                    &relevant_memories,
                    &available_actions,
                    token_tx.clone(),
                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                    "Repairing broken live app payload",
                    false,
                    "app_deploy",
                )
                .await;

                match repair_outcome {
                    TimedLlmCallOutcome::Success(repaired) => {
                        self.record_llm_usage(channel, "chat_tool_repair", &repaired)
                            .await;
                        let repaired_valid = if repo_source_requested {
                            repaired.tool_calls.iter().any(|tc| {
                                tc.name == "app_deploy" && !app_deploy_files_missing(&tc.arguments)
                            })
                        } else {
                            repaired.tool_calls.iter().any(|tc| {
                                (tc.name == "file_write" && !file_write_missing_required_fields(tc))
                                    || (tc.name == "app_deploy"
                                        && !app_deploy_files_missing(&tc.arguments))
                            })
                        };
                        if repaired_valid {
                            if let Some(tx) = token_tx.as_ref() {
                                let _ = tx.try_send(StreamEvent::ToolProgress {
                                    name: if repo_source_requested {
                                        "app_deploy".to_string()
                                    } else {
                                        "file_write".to_string()
                                    },
                                    content: if repo_source_requested {
                                        "Recovered a valid direct repo deploy plan.".to_string()
                                    } else {
                                        "Recovered a valid staged file plan. Continuing toward deployment.".to_string()
                                    },
                                    payload: Some(serde_json::json!({
                                        "kind": "argument_stream",
                                        "stage": "payload_repair",
                                        "stream_key": if repo_source_requested {
                                            "argument-stream:app_deploy"
                                        } else {
                                            "argument-stream:file_write"
                                        },
                                    })),
                                });
                            }
                            selected_llm = candidate.client.clone();
                            effective_model_slot_label =
                                Self::model_role_label(&candidate.role).to_string();
                            effective_model_name = candidate.client.model_name().to_string();
                            llm_result = repaired;
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "\u{2705}".to_string(),
                                title: "Live App Repair Recovered".to_string(),
                                detail: if repo_source_requested {
                                    "Recovered a valid repo deploy call from broken file_write output."
                                        .to_string()
                                } else {
                                    "Recovered a valid staged file plan from broken file_write output."
                                        .to_string()
                                },
                                step_type: "success".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                            repair_succeeded = true;
                            break;
                        }
                        repair_errors.push(format!(
                            "{} ({}) returned no valid app_deploy payload",
                            candidate.slot_label,
                            candidate.client.model_name()
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} returned no valid deploy payload. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                    TimedLlmCallOutcome::Error(e) => {
                        repair_errors.push(format!(
                            "{} ({}) failed: {}",
                            candidate.slot_label,
                            candidate.client.model_name(),
                            e
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} failed while waiting on model. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                    TimedLlmCallOutcome::TimedOut => {
                        repair_errors.push(format!(
                            "{} ({}) timed out after {}s",
                            candidate.slot_label,
                            candidate.client.model_name(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} timed out while rebuilding the deploy plan. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                }
            }

            if !repair_succeeded {
                let broken_app_deploy = llm_result
                    .tool_calls
                    .iter()
                    .find(|tc| tc.name == "app_deploy" && app_deploy_files_missing(&tc.arguments))
                    .cloned();

                if let Some(broken_call) = broken_app_deploy {
                    let validation_issue = if repo_source_requested {
                        format!(
                            "The current app_deploy payload remained malformed or truncated after {} repair attempt(s). Rebuild it as a valid repo deploy or a smaller complete payload using the original request and surviving metadata as hints.",
                            max_repair_attempts
                        )
                    } else {
                        format!(
                            "The current app_deploy payload remained malformed or truncated after {} repair attempt(s). Rebuild a fresh, compact generated app that still satisfies the original request. Prefer normal project files over giant inline bootstrap commands.",
                            max_repair_attempts
                        )
                    };

                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[self-heal]".to_string(),
                            title: "Trying Deploy Self-Heal".to_string(),
                            detail: "Generic deploy-payload repair did not recover a runnable source bundle; asking the model to reconstruct it from the original request and surviving arguments.".to_string(),
                            step_type: "warning".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }

                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_deploy".to_string(),
                            content:
                                "Primary repair loop exhausted. Trying deploy payload self-heal."
                                    .to_string(),
                            payload: Some(serde_json::json!({
                                "kind": "argument_stream",
                                "stage": "payload_self_heal",
                                "stream_key": "argument-stream:app_deploy",
                            })),
                        });
                    }

                    for (idx, candidate) in repair_candidates
                        .iter()
                        .take(max_repair_attempts)
                        .enumerate()
                    {
                        let attempt = idx + 1;
                        match self
                            .build_app_deploy_self_heal_arguments(
                                &candidate.client,
                                &broken_call.arguments,
                                &validation_issue,
                                Some(message),
                                channel,
                                attempt,
                                max_repair_attempts,
                                token_tx.clone(),
                            )
                            .await
                        {
                            Ok(healed_args) => {
                                if app_deploy_files_missing(&healed_args) {
                                    tracing::warn!(
                                        "app_deploy self-heal attempt {} with {} ({}) returned no valid files payload",
                                        attempt,
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    );
                                    repair_errors.push(format!(
                                        "{} ({}) self-heal returned invalid files payload",
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    ));
                                    if let Some(tx) = token_tx.as_ref() {
                                        let _ = tx.try_send(StreamEvent::ToolProgress {
                                            name: "app_deploy".to_string(),
                                            content: format!(
                                                "Self-heal attempt {} returned an invalid deploy payload. Retrying...",
                                                attempt
                                            ),
                                            payload: None,
                                        });
                                    }
                                    continue;
                                }

                                if let Some(existing_call) = llm_result
                                    .tool_calls
                                    .iter_mut()
                                    .find(|tc| tc.name == "app_deploy")
                                {
                                    existing_call.arguments = healed_args;
                                }
                                selected_llm = candidate.client.clone();
                                effective_model_slot_label =
                                    Self::model_role_label(&candidate.role).to_string();
                                effective_model_name = candidate.client.model_name().to_string();
                                if let Some(tx) = token_tx.as_ref() {
                                    let _ = tx.try_send(StreamEvent::ToolProgress {
                                        name: "app_deploy".to_string(),
                                        content:
                                            "Recovered valid deploy payload. Continuing deployment."
                                                .to_string(),
                                        payload: Some(serde_json::json!({
                                            "kind": "argument_stream",
                                            "stage": "payload_self_heal",
                                            "stream_key": "argument-stream:app_deploy",
                                        })),
                                    });
                                }
                                let mut trace = trace_ref.write().await;
                                trace.steps.push(ExecutionStep {
                                    icon: "\u{2705}".to_string(),
                                    title: "Deploy Payload Self-Healed".to_string(),
                                    detail: "Reconstructed a valid app_deploy payload from the original request and surviving malformed arguments.".to_string(),
                                    step_type: "success".to_string(),
                                    data: None,
                                    timestamp: chrono::Utc::now(),
                                    duration_ms: None,
                                });
                                repair_succeeded = true;
                                break;
                            }
                            Err(e) => {
                                tracing::warn!(
                                    "app_deploy self-heal attempt {} with {} ({}) failed: {}",
                                    attempt,
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    e
                                );
                                repair_errors.push(format!(
                                    "{} ({}) self-heal failed: {}",
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    e
                                ));
                                if let Some(tx) = token_tx.as_ref() {
                                    let _ = tx.try_send(StreamEvent::ToolProgress {
                                        name: "app_deploy".to_string(),
                                        content: format!(
                                            "Self-heal attempt {} failed while reconstructing the deploy payload. Retrying...",
                                            attempt
                                        ),
                                        payload: None,
                                    });
                                }
                            }
                        }
                    }
                }
            }

            if !repair_succeeded {
                // Strip the broken file_write calls — executing them would fail.
                // Surface the error to the conversation so the LLM can self-correct.
                llm_result
                    .tool_calls
                    .retain(|tc| !file_write_missing_required_fields(tc));

                let _user_message = format!(
                    "I wasn't able to deploy the app — the file write calls were missing required fields after {} repair attempt(s). \
                    Please try again and I'll use the correct deployment format.",
                    max_repair_attempts
                );
                let failure_reason = "";
                let stronger_model_hint = "";

                let _user_message = format!(
                    "I wasn't able to deploy the app â€” {}.{}",
                    failure_reason, stronger_model_hint
                );

                let _user_message = format!(
                    "I wasn't able to deploy the app â€” the file write calls were missing required fields after {} repair attempt(s). \
                    Please try again and I'll use the correct deployment format.",
                    max_repair_attempts
                );

                let final_user_message = build_deploy_repair_failure_message(
                    &repair_errors,
                    max_repair_attempts,
                    "the repair attempts timed out while waiting on the model, so I couldn't finish reconstructing the app update",
                    "the model kept emitting incomplete repair payloads, so I couldn't reconstruct a valid app update",
                    format!(
                        "the live app repair payload was still invalid after {} repair attempt(s)",
                        max_repair_attempts
                    ),
                    &[
                        "missing required fields",
                        "returned no valid app_deploy payload",
                        "invalid files payload",
                        "non-json response",
                        "missing `files`",
                        "empty `files`",
                        "did not change files",
                    ],
                );

                if llm_result.content.is_empty() {
                    llm_result.content = final_user_message.clone();
                } else {
                    llm_result
                        .content
                        .push_str(&format!("\n\n{}", final_user_message));
                }

                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[warn]".to_string(),
                    title: "Live App Repair Failed".to_string(),
                    detail: format!(
                        "Stripped broken tool calls after {} failed repair attempt{}. Error surfaced to conversation.",
                        max_repair_attempts,
                        if max_repair_attempts == 1 { "" } else { "s" }
                    ),
                    step_type: "warning".to_string(),
                    data: if repair_errors.is_empty() {
                        None
                    } else {
                        Some(safe_truncate(&repair_errors.join(" | "), 600))
                    },
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }
        }

        let needs_app_deploy_repair = llm_result
            .tool_calls
            .iter()
            .any(|tc| tc.name == "app_deploy" && app_deploy_files_missing(&tc.arguments));

        if needs_app_deploy_repair {
            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[fix]".to_string(),
                    title: "Repairing Deploy Payload".to_string(),
                    detail: if repo_source_requested {
                        "Model emitted app_deploy without a repo source; requesting a corrected repo deploy tool call."
                            .to_string()
                    } else {
                        "Model emitted app_deploy without staged source files; requesting corrected staged file writes."
                            .to_string()
                    },
                    step_type: "warning".to_string(),
                    data: None,
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }

            if let Some(tx) = token_tx.as_ref() {
                let _ = tx.try_send(StreamEvent::ToolProgress {
                    name: if repo_source_requested {
                        "app_deploy".to_string()
                    } else {
                        "file_write".to_string()
                    },
                    content: if repo_source_requested {
                        "Deploy payload is malformed. Regenerating tool arguments."
                            .to_string()
                    } else {
                        "Generated app deploy is missing staged source files. Regenerating file writes."
                            .to_string()
                    },
                    payload: Some(serde_json::json!({
                        "kind": "argument_stream",
                        "stage": "payload_repair",
                        "stream_key": if repo_source_requested {
                            "argument-stream:app_deploy"
                        } else {
                            "argument-stream:file_write"
                        },
                    })),
                });
            }

            let response_excerpt: String = llm_result.content.chars().take(1200).collect();
            let repair_prompt = format!(
                "Original user request:\n{}\n\nPrevious assistant response (excerpt):\n{}\n\n\
Your previous response emitted `app_deploy` without a valid source payload. \
{}\n\n\
{}\n\n\
Do NOT omit the required source fields. Do NOT ask the user for JSON. Emit the tool call now.",
                message,
                response_excerpt,
                if repo_source_requested {
                    "Retry now and emit a SINGLE valid `app_deploy` tool call with `repo_url` (and optionally `repo_ref`, `repo_subdir`, `service_mode`) so AgentArk can clone and deploy the repo."
                } else {
                    "Retry now by emitting valid `file_write` calls under `/app/data/apps/new/<slug>/...` for the generated source files. After the files are staged, you may emit `app_deploy` without inlining the full codebase again, or let AgentArk recover the deploy from the staged files."
                },
                if repo_source_requested {
                    "For repo deploys, do not inline the whole repository as `files` unless the user explicitly asked for a generated-from-scratch app."
                } else {
                    "CRITICAL — the `files` parameter must be a JSON object where each key is a filename and each value is the full file content as a string. Example:\n{\n  \"files\": {\n    \"index.html\": \"<!DOCTYPE html><html><head><title>Demo</title></head><body><h1>Hello</h1></body></html>\",\n    \"style.css\": \"body { font-family: sans-serif; }\"\n  },\n  \"title\": \"Demo App\"\n}\nDo NOT put file content as a top-level string."
                }
            );

            let repair_candidates = self.llm_candidates_for_role(&model_role);
            let max_repair_attempts = repair_candidates.len().clamp(1, 3);
            let mut repair_errors: Vec<String> = Vec::new();
            let mut repair_succeeded = false;
            for (idx, candidate) in repair_candidates
                .iter()
                .take(max_repair_attempts)
                .enumerate()
            {
                let attempt = idx + 1;
                if attempt > 1 {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[retry]".to_string(),
                        title: "Retrying Deploy Payload Repair".to_string(),
                        detail: format!(
                            "Repair attempt {} of {} with {} ({}).",
                            attempt,
                            max_repair_attempts,
                            candidate.slot_label,
                            candidate.client.model_name()
                        ),
                        step_type: "warning".to_string(),
                        data: None,
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_deploy".to_string(),
                            content: format!(
                                "Repair self-heal: switching to {} ({})",
                                candidate.slot_label,
                                candidate.client.model_name()
                            ),
                            payload: Some(serde_json::json!({
                                "kind": "model_fallback",
                                "slot_id": candidate.slot_id,
                                "slot_label": candidate.slot_label,
                                "model": candidate.client.model_name(),
                                "attempt": attempt,
                                "phase": "app_deploy_repair"
                            })),
                        });
                    }
                }

                let repair_outcome = run_timed_llm_call_with_heartbeat(
                    &candidate.client,
                    &system_prompt,
                    &repair_prompt,
                    &conversation_history,
                    &relevant_memories,
                    &available_actions,
                    token_tx.clone(),
                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                    "Regenerating deploy payload",
                    false,
                    "app_deploy",
                )
                .await;

                match repair_outcome {
                    TimedLlmCallOutcome::Success(repaired) => {
                        self.record_llm_usage(channel, "chat_tool_repair", &repaired)
                            .await;
                        let repaired_valid = if repo_source_requested {
                            repaired.tool_calls.iter().any(|tc| {
                                tc.name == "app_deploy" && !app_deploy_files_missing(&tc.arguments)
                            })
                        } else {
                            repaired.tool_calls.iter().any(|tc| {
                                (tc.name == "file_write" && !file_write_missing_required_fields(tc))
                                    || (tc.name == "app_deploy"
                                        && !app_deploy_files_missing(&tc.arguments))
                            })
                        };
                        if repaired_valid {
                            tracing::info!("Repaired malformed app_deploy tool payload");
                            if let Some(tx) = token_tx.as_ref() {
                                let _ = tx.try_send(StreamEvent::ToolProgress {
                                    name: if repo_source_requested {
                                        "app_deploy".to_string()
                                    } else {
                                        "file_write".to_string()
                                    },
                                    content: if repo_source_requested {
                                        "Recovered valid deploy payload. Continuing deployment."
                                            .to_string()
                                    } else {
                                        "Recovered valid staged app files. Continuing deployment."
                                            .to_string()
                                    },
                                    payload: Some(serde_json::json!({
                                        "kind": "argument_stream",
                                        "stage": "payload_repair",
                                        "stream_key": if repo_source_requested {
                                            "argument-stream:app_deploy"
                                        } else {
                                            "argument-stream:file_write"
                                        },
                                    })),
                                });
                            }
                            selected_llm = candidate.client.clone();
                            effective_model_slot_label =
                                Self::model_role_label(&candidate.role).to_string();
                            effective_model_name = candidate.client.model_name().to_string();
                            llm_result = repaired;
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "\u{2705}".to_string(),
                                title: "Deploy Payload Repaired".to_string(),
                                detail: if repo_source_requested {
                                    "Recovered a valid app_deploy call with a deployable source payload."
                                        .to_string()
                                } else {
                                    "Recovered a valid staged file plan for the generated app."
                                        .to_string()
                                },
                                step_type: "success".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                            repair_succeeded = true;
                            break;
                        }
                        tracing::warn!(
                            "app_deploy repair attempt {} with {} ({}) returned no valid files payload",
                            attempt,
                            candidate.slot_label,
                            candidate.client.model_name()
                        );
                        repair_errors.push(format!(
                            "{} ({}) returned invalid files payload",
                            candidate.slot_label,
                            candidate.client.model_name()
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} returned invalid files payload. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                    TimedLlmCallOutcome::Error(e) => {
                        tracing::warn!(
                            "app_deploy repair attempt {} with {} ({}) failed: {}",
                            attempt,
                            candidate.slot_label,
                            candidate.client.model_name(),
                            e
                        );
                        repair_errors.push(format!(
                            "{} ({}) failed: {}",
                            candidate.slot_label,
                            candidate.client.model_name(),
                            e
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} failed while waiting on model. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                    TimedLlmCallOutcome::TimedOut => {
                        tracing::warn!(
                            "app_deploy repair attempt {} with {} ({}) timed out after {}s",
                            attempt,
                            candidate.slot_label,
                            candidate.client.model_name(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                        );
                        repair_errors.push(format!(
                            "{} ({}) timed out after {}s",
                            candidate.slot_label,
                            candidate.client.model_name(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                        ));
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Repair attempt {} timed out while rebuilding the deploy payload. Retrying...",
                                    attempt
                                ),
                                payload: None,
                            });
                        }
                    }
                }
            }

            if !repair_succeeded {
                let broken_app_deploy = llm_result
                    .tool_calls
                    .iter()
                    .find(|tc| tc.name == "app_deploy" && app_deploy_files_missing(&tc.arguments))
                    .cloned();

                if let Some(broken_call) = broken_app_deploy {
                    let validation_issue = if repo_source_requested {
                        format!(
                            "The current app_deploy payload remained malformed or truncated after {} repair attempt(s). Rebuild it as a valid repo deploy or a smaller complete payload using the original request and surviving metadata as hints.",
                            max_repair_attempts
                        )
                    } else {
                        format!(
                            "The current app_deploy payload remained malformed or truncated after {} repair attempt(s). Rebuild a fresh, compact generated app that still satisfies the original request. Prefer normal project files over giant inline bootstrap commands.",
                            max_repair_attempts
                        )
                    };

                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[self-heal]".to_string(),
                            title: "Trying Deploy Self-Heal".to_string(),
                            detail: "Generic deploy-payload repair did not recover a runnable source bundle; asking the model to reconstruct it from the original request and surviving arguments.".to_string(),
                            step_type: "warning".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }

                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_deploy".to_string(),
                            content:
                                "Primary repair loop exhausted. Trying deploy payload self-heal."
                                    .to_string(),
                            payload: Some(serde_json::json!({
                                "kind": "argument_stream",
                                "stage": "payload_self_heal",
                                "stream_key": "argument-stream:app_deploy",
                            })),
                        });
                    }

                    for (idx, candidate) in repair_candidates
                        .iter()
                        .take(max_repair_attempts)
                        .enumerate()
                    {
                        let attempt = idx + 1;
                        match self
                            .build_app_deploy_self_heal_arguments(
                                &candidate.client,
                                &broken_call.arguments,
                                &validation_issue,
                                Some(message),
                                channel,
                                attempt,
                                max_repair_attempts,
                                token_tx.clone(),
                            )
                            .await
                        {
                            Ok(healed_args) => {
                                if app_deploy_files_missing(&healed_args) {
                                    tracing::warn!(
                                        "app_deploy self-heal attempt {} with {} ({}) returned no valid files payload",
                                        attempt,
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    );
                                    repair_errors.push(format!(
                                        "{} ({}) self-heal returned invalid files payload",
                                        candidate.slot_label,
                                        candidate.client.model_name()
                                    ));
                                    if let Some(tx) = token_tx.as_ref() {
                                        let _ = tx.try_send(StreamEvent::ToolProgress {
                                            name: "app_deploy".to_string(),
                                            content: format!(
                                                "Self-heal attempt {} returned an invalid deploy payload. Retrying...",
                                                attempt
                                            ),
                                            payload: None,
                                        });
                                    }
                                    continue;
                                }

                                if let Some(existing_call) = llm_result
                                    .tool_calls
                                    .iter_mut()
                                    .find(|tc| tc.name == "app_deploy")
                                {
                                    existing_call.arguments = healed_args;
                                }
                                selected_llm = candidate.client.clone();
                                effective_model_slot_label =
                                    Self::model_role_label(&candidate.role).to_string();
                                effective_model_name = candidate.client.model_name().to_string();
                                if let Some(tx) = token_tx.as_ref() {
                                    let _ = tx.try_send(StreamEvent::ToolProgress {
                                        name: "app_deploy".to_string(),
                                        content:
                                            "Recovered valid deploy payload. Continuing deployment."
                                                .to_string(),
                                        payload: Some(serde_json::json!({
                                            "kind": "argument_stream",
                                            "stage": "payload_self_heal",
                                            "stream_key": "argument-stream:app_deploy",
                                        })),
                                    });
                                }
                                let mut trace = trace_ref.write().await;
                                trace.steps.push(ExecutionStep {
                                    icon: "\u{2705}".to_string(),
                                    title: "Deploy Payload Self-Healed".to_string(),
                                    detail: "Reconstructed a valid app_deploy payload from the original request and surviving malformed arguments.".to_string(),
                                    step_type: "success".to_string(),
                                    data: None,
                                    timestamp: chrono::Utc::now(),
                                    duration_ms: None,
                                });
                                repair_succeeded = true;
                                break;
                            }
                            Err(e) => {
                                tracing::warn!(
                                    "app_deploy self-heal attempt {} with {} ({}) failed: {}",
                                    attempt,
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    e
                                );
                                repair_errors.push(format!(
                                    "{} ({}) self-heal failed: {}",
                                    candidate.slot_label,
                                    candidate.client.model_name(),
                                    e
                                ));
                                if let Some(tx) = token_tx.as_ref() {
                                    let _ = tx.try_send(StreamEvent::ToolProgress {
                                        name: "app_deploy".to_string(),
                                        content: format!(
                                            "Self-heal attempt {} failed while reconstructing the deploy payload. Retrying...",
                                            attempt
                                        ),
                                        payload: None,
                                    });
                                }
                            }
                        }
                    }
                }
            }

            if !repair_succeeded {
                // Strip the broken app_deploy call — executing a known-bad payload
                // wastes time and produces the same error loop. Instead, surface the
                // failure as the assistant response so the LLM gets actionable feedback.
                let received_keys = llm_result
                    .tool_calls
                    .iter()
                    .find(|tc| tc.name == "app_deploy")
                    .and_then(|tc| tc.arguments.as_object())
                    .map(|obj| {
                        obj.keys()
                            .map(|k| format!("`{}`", k))
                            .collect::<Vec<_>>()
                            .join(", ")
                    })
                    .unwrap_or_else(|| "(no keys)".to_string());

                llm_result.tool_calls.retain(|tc| tc.name != "app_deploy");

                let final_user_message = build_deploy_repair_failure_message(
                    &repair_errors,
                    max_repair_attempts,
                    "the repair attempts timed out while waiting on the model, so I couldn't finish reconstructing the deploy payload",
                    "the model kept emitting truncated or incomplete deploy payloads, so I couldn't reconstruct a valid app bundle",
                    format!(
                        "the deployment payload was still invalid after {} repair attempt(s)",
                        max_repair_attempts
                    ),
                    &[
                        "invalid files payload",
                        "non-json response",
                        "missing `files`",
                        "empty `files`",
                        "did not change files",
                    ],
                );

                // User-facing message: clean, no JSON (avoids the raw-output sanitizer).
                let _user_message = format!(
                    "I wasn't able to deploy the app — the deployment payload was missing the required file contents after {} repair attempt(s). \
                    Please try again; I'll make sure to include all files in the correct format.",
                    max_repair_attempts
                );

                if llm_result.content.is_empty() {
                    llm_result.content = final_user_message.clone();
                } else {
                    llm_result
                        .content
                        .push_str(&format!("\n\n{}", final_user_message));
                }

                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[warn]".to_string(),
                    title: "Deploy Payload Still Invalid".to_string(),
                    detail: format!(
                        "Stripped broken app_deploy call after {} failed repair attempts. Error surfaced to conversation.",
                        max_repair_attempts
                    ),
                    step_type: "warning".to_string(),
                    data: {
                        let mut parts = Vec::new();
                        parts.push(format!("Received keys: [{}]", received_keys));
                        if !repair_errors.is_empty() {
                            parts.push(repair_errors.join(" | "));
                        }
                        Some(safe_truncate(&parts.join(" — "), 600))
                    },
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }
        }

        let llm_duration = llm_start.elapsed().as_millis() as u64;
        // Analytics: record token usage for the primary chat request (best-effort).
        self.record_llm_usage(channel, "chat", &llm_result).await;
        self.log_operational_event(operational::OperationalEvent {
            event_type: "llm_decision",
            channel,
            success: true,
            outcome: "ok",
            trace_id: Some(&trace_id),
            conversation_id: Some(&conversation_key),
            tool_name: None,
            latency_ms: Some(llm_duration),
            arguments: None,
            payload: Some(&serde_json::json!({
                "provider": llm_result.provider.as_str(),
                "model": llm_result.model.as_str(),
                "tool_calls": llm_result.tool_calls.len(),
                "response_chars": llm_result.content.chars().count(),
            })),
            strategy_version: strategy_version.as_deref(),
            policy_version: Some(policy_version.as_str()),
            prompt_version: Some(prompt_version.as_str()),
            model_slot: Some(effective_model_slot_label.as_str()),
        })
        .await;

        let initial_response = llm_result.content.clone();
        let initial_tool_calls = llm_result.tool_calls.clone();

        {
            let mut trace = trace_ref.write().await;
            trace.steps.push(ExecutionStep {
                icon: "[llm]".to_string(),
                title: "LLM Response Received".to_string(),
                detail: format!(
                    "Response length: {} chars | Tool calls: {}",
                    initial_response.len(),
                    initial_tool_calls.len()
                ),
                step_type: "success".to_string(),
                data: None,
                timestamp: chrono::Utc::now(),
                duration_ms: Some(llm_duration),
            });

            // Emit reasoning/thinking if present (from OpenRouter reasoning models, etc.)
            if let Some(ref reasoning) = llm_result.reasoning {
                trace.steps.push(ExecutionStep {
                    icon: "[think]".to_string(),
                    title: "Model Reasoning".to_string(),
                    detail: format!("{} chars", reasoning.len()),
                    step_type: "reasoning".to_string(),
                    data: Some(if reasoning.len() > 1000 {
                        format!("{}...", &reasoning[..1000])
                    } else {
                        reasoning.clone()
                    }),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }
        }

        // 6. Execute tool calls in a bounded internal loop so tool outputs
        // become reasoning context instead of raw final user output.
        let mut llm_response = llm_result;
        let mut tool_turn = 0usize;
        let mut response = llm_response.content.clone();
        let mut all_executed_tool_calls: Vec<crate::core::llm::ToolCall> = Vec::new();
        let mut preserved_tool_outputs: Vec<String> = Vec::new();
        let mut tool_loop_history = conversation_history.clone();
        let mut prior_request_scoped_tool_results: HashMap<String, String> = HashMap::new();
        let mut request_scoped_latched_results: HashMap<String, String> = HashMap::new();
        let mut cumulative_tool_batch = tool_execution::ToolExecutionBatch::default();
        let mut tool_loop_budget = ToolLoopBudgetState::new();
        let mut live_app_shell_redirect_attempts = 0usize;
        let mut existing_app_repair_redirect_attempts = 0usize;

        loop {
            let mut tool_calls = Vec::new();
            let mut skipped_duplicate_outputs: Vec<tool_execution::ToolCallOutput> = Vec::new();
            let mut skipped_due_to_request_latch = false;
            let mut current_turn_request_latch_keys: HashSet<String> = HashSet::new();
            for original_call in llm_response.tool_calls.clone() {
                let expanded_calls = if let Some(staged_plan) =
                    rewrite_generated_app_deploy_to_staged_writes(
                        &original_call,
                        &tool_calls,
                        &all_executed_tool_calls,
                    ) {
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stage]".to_string(),
                            title: "Enforcing Staged App Files".to_string(),
                            detail: format!(
                                "Materialized {} generated file{} under {} before deployment.",
                                staged_plan.file_count,
                                if staged_plan.file_count == 1 { "" } else { "s" },
                                staged_plan.staging_root
                            ),
                            step_type: "info".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "file_write".to_string(),
                            content: format!(
                                "Framework is staging {} generated file{} before deploy.",
                                staged_plan.file_count,
                                if staged_plan.file_count == 1 { "" } else { "s" }
                            ),
                            payload: Some(serde_json::json!({
                                "kind": "phase_status",
                                "phase": "generating_files",
                                "label": "Generating files",
                                "detail": format!(
                                    "Writing generated source files to {} before deployment.",
                                    staged_plan.staging_root
                                ),
                            })),
                        });
                    }
                    staged_plan.tool_calls
                } else {
                    vec![original_call.clone()]
                };

                for mut call in expanded_calls {
                    let repaired_from_recent_writes =
                        repair_app_deploy_tool_call_from_recent_writes(
                            &call,
                            &tool_calls,
                            &all_executed_tool_calls,
                        );
                    if let Some(repaired) = repaired_from_recent_writes {
                        call = repaired;
                        let repaired_file_count = call
                            .arguments
                            .get("files")
                            .and_then(|value| value.as_object())
                            .map(|files| files.len())
                            .unwrap_or(0);
                        {
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[fix]".to_string(),
                                title: "Recovered Deploy Files".to_string(),
                                detail: format!(
                                    "Filled a missing app_deploy files payload from {} recent file{} written earlier in this request.",
                                    repaired_file_count,
                                    if repaired_file_count == 1 { "" } else { "s" }
                                ),
                                step_type: "info".to_string(),
                                data: None,
                                timestamp: chrono::Utc::now(),
                                duration_ms: None,
                            });
                        }
                        if let Some(tx) = token_tx.as_ref() {
                            let _ = tx.try_send(StreamEvent::ToolProgress {
                                name: "app_deploy".to_string(),
                                content: format!(
                                    "Recovered deploy payload from {} recent file write{}.",
                                    repaired_file_count,
                                    if repaired_file_count == 1 { "" } else { "s" }
                                ),
                                payload: Some(serde_json::json!({
                                    "kind": "argument_stream",
                                    "stage": "payload_repair",
                                    "stream_key": "argument-stream:app_deploy",
                                })),
                            });
                        }
                    }
                    if let Some(request_latch_key) =
                        tool_call_request_latch_key(&call, &request_latched_actions)
                    {
                        if let Some(previous_result) =
                            request_scoped_latched_results.get(&request_latch_key)
                        {
                            skipped_due_to_request_latch = true;
                            skipped_duplicate_outputs.push(tool_execution::ToolCallOutput {
                                name: call.name.clone(),
                                content: format!(
                                    "Skipped repeated `{}` create/update request because a matching persistent object was already accepted earlier in this request.\nPrevious result: {}",
                                    call.name,
                                    safe_truncate(previous_result, 500)
                                ),
                            });
                            continue;
                        }
                        if !current_turn_request_latch_keys.insert(request_latch_key) {
                            skipped_due_to_request_latch = true;
                            skipped_duplicate_outputs.push(tool_execution::ToolCallOutput {
                                name: call.name.clone(),
                                content: format!(
                                    "Skipped repeated `{}` create/update request because the same persistent action was already requested earlier in this model turn.",
                                    call.name
                                ),
                            });
                            continue;
                        }
                    }
                    let signature = Self::tool_call_signature(&call);
                    if should_suppress_duplicate_tool_call_within_request(
                        &call,
                        &duplicate_suppression_actions,
                    ) {
                        if let Some(previous_result) =
                            prior_request_scoped_tool_results.get(&signature)
                        {
                            skipped_duplicate_outputs.push(tool_execution::ToolCallOutput {
                                name: call.name.clone(),
                                content: format!(
                                    "Skipped duplicate repeated `{}` call with identical arguments in the same request. Use the previous result instead.\nPrevious result: {}",
                                    call.name,
                                    safe_truncate(previous_result, 500)
                                ),
                            });
                            continue;
                        }
                    }
                    tool_calls.push(call);
                }
            }
            let app_deploy_already_attempted = all_executed_tool_calls
                .iter()
                .any(|call| call.name == "app_deploy")
                || tool_calls.iter().any(|call| call.name == "app_deploy");
            let existing_app_repair_already_attempted =
                all_executed_tool_calls.iter().any(|call| {
                    matches!(
                        call.name.as_str(),
                        "app_inspect" | "file_read" | "file_write" | "app_restart"
                    )
                });
            if execution_intent
                && !app_deploy_intent
                && request_looks_like_fix_or_debug(message)
                && existing_app_repair_redirect_attempts < 2
                && !existing_app_repair_already_attempted
                && recent_artifact_prompt_context
                    .as_ref()
                    .map(|ctx| ctx.artifact_type.eq_ignore_ascii_case("app"))
                    .unwrap_or(false)
                && tool_calls_look_like_existing_app_code_execute_detour(&tool_calls)
            {
                existing_app_repair_redirect_attempts += 1;
                if let Some(artifact_ctx) = recent_artifact_prompt_context.as_ref() {
                    let inspect_query = if artifact_ctx.title.trim().is_empty() {
                        artifact_ctx.artifact_id.clone()
                    } else {
                        artifact_ctx.title.clone()
                    };
                    let redirected_tool_names = tool_calls
                        .iter()
                        .map(|call| call.name.as_str())
                        .collect::<Vec<_>>()
                        .join(", ");
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[fix]".to_string(),
                            title: "Redirecting App Repair".to_string(),
                            detail: format!(
                                "Deployed-app fix request detoured into {} before inspecting the app. Running app_inspect first.",
                                redirected_tool_names
                            ),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "attempt={} | app_id={}",
                                existing_app_repair_redirect_attempts,
                                artifact_ctx.artifact_id
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_inspect".to_string(),
                            content: "Deployed app fix detected. Inspecting the live app first instead of running sandbox code."
                                .to_string(),
                            payload: None,
                        });
                    }
                    tool_calls = vec![crate::core::llm::ToolCall {
                        id: format!("repair-app-inspect-{}", tool_turn + 1),
                        name: "app_inspect".to_string(),
                        arguments: serde_json::json!({
                            "query": inspect_query,
                            "include_files": true,
                            "include_logs": true,
                            "limit": 1
                        }),
                    }];
                }
            }
            if execution_intent
                && !direct_app_deploy_intent
                && request_looks_like_fix_or_debug(message)
                && existing_app_repair_redirect_attempts < 2
                && !existing_app_repair_already_attempted
                && recent_artifact_prompt_context
                    .as_ref()
                    .map(|ctx| ctx.artifact_type.eq_ignore_ascii_case("app"))
                    .unwrap_or(false)
                && tool_calls.iter().any(|call| call.name == "app_deploy")
            {
                existing_app_repair_redirect_attempts += 1;
                if let Some(artifact_ctx) = recent_artifact_prompt_context.as_ref() {
                    let inspect_query = if artifact_ctx.title.trim().is_empty() {
                        artifact_ctx.artifact_id.clone()
                    } else {
                        artifact_ctx.title.clone()
                    };
                    let redirected_tool_names = tool_calls
                        .iter()
                        .map(|call| call.name.as_str())
                        .collect::<Vec<_>>()
                        .join(", ");
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[fix]".to_string(),
                            title: "Blocked Fresh Deploy Detour".to_string(),
                            detail: format!(
                                "Existing-app repair request detoured into {}. Redirecting back to app_inspect instead of creating a fresh deploy.",
                                redirected_tool_names
                            ),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "attempt={} | app_id={}",
                                existing_app_repair_redirect_attempts,
                                artifact_ctx.artifact_id
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_inspect".to_string(),
                            content: "Existing app repair detected. Staying in the inspect/edit/restart path instead of creating a fresh deploy."
                                .to_string(),
                            payload: None,
                        });
                    }
                    tool_calls = vec![crate::core::llm::ToolCall {
                        id: format!("repair-app-inspect-{}", tool_turn + 1),
                        name: "app_inspect".to_string(),
                        arguments: serde_json::json!({
                            "query": inspect_query,
                            "include_files": true,
                            "include_logs": true,
                            "limit": 1
                        }),
                    }];
                }
            }
            if app_deploy_intent
                && live_app_shell_redirect_attempts < 2
                && tool_calls_look_like_live_app_shell_detour(
                    &tool_calls,
                    app_deploy_already_attempted,
                )
            {
                live_app_shell_redirect_attempts += 1;
                let tool_names = tool_calls
                    .iter()
                    .map(|call| call.name.as_str())
                    .collect::<Vec<_>>()
                    .join(", ");
                {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[fix]".to_string(),
                        title: "Redirecting Shell App Build".to_string(),
                        detail: format!(
                            "Live app request detoured into {} before any deploy. Regenerating toward app_deploy.",
                            tool_names
                        ),
                        step_type: "warning".to_string(),
                        data: Some(format!(
                            "attempt={} | schedule_task_intent={}",
                            live_app_shell_redirect_attempts, schedule_task_intent
                        )),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                }
                if let Some(tx) = token_tx.as_ref() {
                    let _ = tx.try_send(StreamEvent::ToolProgress {
                        name: "app_deploy".to_string(),
                        content: "Shell-first app plan detected. Regenerating as direct deploy."
                            .to_string(),
                        payload: None,
                    });
                }

                let assistant_message = build_tool_followup_assistant_message(&llm_response);
                if !assistant_message.is_empty() {
                    tool_loop_history.push(ConversationMessage {
                        role: "assistant".to_string(),
                        content: assistant_message,
                        _timestamp: chrono::Utc::now(),
                    });
                }
                tool_loop_history.push(ConversationMessage {
                    role: "user".to_string(),
                    content: if schedule_task_intent {
                        if repo_source_requested {
                            "This is a live app repo deploy request and no app has been deployed yet. Stop using shell or more inventory checks as the primary path. Emit a valid app_deploy call with repo_url now, then emit schedule_task if recurring execution is needed.".to_string()
                        } else {
                            "This is a live app build request and no app has been deployed yet. Stop using shell or more inventory checks as the primary path. Stage the generated files with file_write under /app/data/apps/new/<slug>/... first, then continue to deploy. Emit schedule_task only after deployment if recurring execution is needed.".to_string()
                        }
                    } else if repo_source_requested {
                        "This is a live app repo deploy request and no app has been deployed yet. Stop using shell or more inventory checks as the primary path. Emit a valid app_deploy call with repo_url now.".to_string()
                    } else {
                        "This is a live app build request and no app has been deployed yet. Stop using shell or more inventory checks as the primary path. Stage the generated files with file_write under /app/data/apps/new/<slug>/... first, then continue to deploy.".to_string()
                    },
                    _timestamp: chrono::Utc::now(),
                });

                let redirect_prompt = format!(
                    "The current live-app tool plan is detouring into {} before any deploy has happened. \
Stop using `shell`, repeated `app_inspect`, `list_integrations`, and `manage_actions` as the primary path. \
Emit {} now. {}\
Do not ask for JSON. Do not claim deployment is unavailable unless `app_deploy` is missing from the scoped catalog.",
                    tool_names,
                    if repo_source_requested {
                        "`repo_url` (and optionally `repo_ref`, `repo_subdir`, `service_mode`) so AgentArk can clone and deploy the repo"
                    } else {
                        "staged `file_write` calls under `/app/data/apps/new/<slug>/...` so the app can be deployed immediately after the files land"
                    },
                    if schedule_task_intent {
                        "If recurring execution is needed after deploy, you may also emit `schedule_task`. "
                    } else {
                        ""
                    }
                );

                let redirect_start = std::time::Instant::now();
                match run_timed_llm_call_with_heartbeat(
                    &selected_llm,
                    &system_prompt,
                    &redirect_prompt,
                    &tool_loop_history,
                    &relevant_memories,
                    &available_actions,
                    token_tx.clone(),
                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                    "Replanning after shell detour",
                    true,
                    "llm",
                )
                .await
                {
                    TimedLlmCallOutcome::Success(next_response) => {
                        self.record_llm_usage(
                            channel,
                            "chat_live_app_shell_redirect",
                            &next_response,
                        )
                        .await;
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[loop]".to_string(),
                            title: "Live App Redirect Replan".to_string(),
                            detail: format!(
                                "Requested a direct deploy replan after shell detour ({}ms).",
                                redirect_start.elapsed().as_millis()
                            ),
                            step_type: "info".to_string(),
                            data: Some(format!(
                                "response_chars={} | tool_calls={}",
                                next_response.content.chars().count(),
                                next_response.tool_calls.len()
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(redirect_start.elapsed().as_millis() as u64),
                        });
                        llm_response = next_response;
                        continue;
                    }
                    TimedLlmCallOutcome::Error(e) => {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[warn]".to_string(),
                            title: "Live App Redirect Failed".to_string(),
                            detail: "Continuing with the existing tool plan after replan failure."
                                .to_string(),
                            step_type: "warning".to_string(),
                            data: Some(safe_truncate(&e.to_string(), 500)),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(redirect_start.elapsed().as_millis() as u64),
                        });
                    }
                    TimedLlmCallOutcome::TimedOut => {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[warn]".to_string(),
                            title: "Live App Redirect Timed Out".to_string(),
                            detail: "Continuing with the existing tool plan after the direct deploy replan timed out."
                                .to_string(),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "model={} | timeout_secs={}",
                                selected_llm.model_name(),
                                TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(redirect_start.elapsed().as_millis() as u64),
                        });
                    }
                }
            }
            if tool_calls.is_empty() {
                if !skipped_duplicate_outputs.is_empty() {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[loop]".to_string(),
                        title: if skipped_due_to_request_latch {
                            "Persistent Create Request Suppressed".to_string()
                        } else {
                            "Duplicate Tool Call Suppressed".to_string()
                        },
                        detail: if skipped_due_to_request_latch {
                            "Skipped repeated persistent create/update tool calls after the requested object was already accepted in this request."
                                .to_string()
                        } else {
                            "Skipped repeated side-effecting tool calls with identical arguments in the same request."
                                .to_string()
                        },
                        step_type: "warning".to_string(),
                        data: Some(format!(
                            "tools={}",
                            skipped_duplicate_outputs
                                .iter()
                                .map(|output| output.name.clone())
                                .collect::<Vec<_>>()
                                .join(", ")
                        )),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                    let tool_batch = tool_execution::ToolExecutionBatch {
                        outputs: skipped_duplicate_outputs.clone(),
                        outcomes: vec![],
                    };
                    let tool_results_for_followup = format_tool_results_for_followup(&tool_batch);
                    if tool_results_for_followup.is_empty() {
                        break;
                    }
                    tool_loop_history.push(ConversationMessage {
                        role: "user".to_string(),
                        content: build_tool_followup_user_message(
                            message,
                            &tool_results_for_followup,
                            execution_intent,
                            if skipped_due_to_request_latch {
                                Some(persistent_creation_followup_rules())
                            } else {
                                None
                            },
                        ),
                        _timestamp: chrono::Utc::now(),
                    });
                    if skipped_due_to_request_latch {
                        let synthesis_start = std::time::Instant::now();
                        match run_timed_llm_call_with_heartbeat(
                            &selected_llm,
                            &system_prompt,
                            "A persistent automation or object was already created or updated in this request. Do not create another one. Based only on the accepted result and the duplicate-suppression note, write the final user-facing status now. Mention the created or updated object, its current status, and any important caveats in plain language. Do not call tools.",
                            &tool_loop_history,
                            &relevant_memories,
                            &[],
                            token_tx.clone(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                            "Writing latched persistent-object status",
                            true,
                            "llm",
                        )
                        .await
                        {
                            TimedLlmCallOutcome::Success(synthesized) => {
                                self.record_llm_usage(
                                    channel,
                                    "chat_persistent_creation_synthesis",
                                    &synthesized,
                                )
                                .await;
                                if !synthesized.content.trim().is_empty() {
                                    response = sanitize_final_user_response(&synthesized.content);
                                } else {
                                    response = build_user_facing_tool_fallback_response(
                                        &tool_batch.combined_output(),
                                        &tool_batch,
                                        "I created or updated the requested automation and stopped duplicate follow-up attempts in the same request.",
                                    );
                                }
                            }
                            TimedLlmCallOutcome::Error(_)
                            | TimedLlmCallOutcome::TimedOut => {
                                response = build_user_facing_tool_fallback_response(
                                    &tool_batch.combined_output(),
                                    &tool_batch,
                                    "I created or updated the requested automation and stopped duplicate follow-up attempts in the same request.",
                                );
                            }
                        }
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stop]".to_string(),
                            title: "Persistent Creation Latched".to_string(),
                            detail: "Stopped the tool loop after a repeated create/update attempt because the requested persistent object was already accepted earlier in the same request."
                                .to_string(),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "synthesis_ms={} | tools={}",
                                synthesis_start.elapsed().as_millis(),
                                skipped_duplicate_outputs
                                    .iter()
                                    .map(|output| output.name.clone())
                                    .collect::<Vec<_>>()
                                    .join(", ")
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(synthesis_start.elapsed().as_millis() as u64),
                        });
                        break;
                    }
                    tool_turn += 1;
                    let stop_reason = tool_loop_budget
                        .record_duplicate_only_round()
                        .or_else(|| tool_loop_budget.stop_reason_for_completed_turns(tool_turn));
                    if let Some(stop_reason) = stop_reason {
                        response = build_user_facing_tool_fallback_response(
                            &tool_batch.combined_output(),
                            &tool_batch,
                            "I skipped repeated duplicate actions and returned the latest tool-backed response.",
                        );
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stop]".to_string(),
                            title: ToolLoopBudgetState::stop_title(stop_reason).to_string(),
                            detail: tool_loop_budget.stop_detail(stop_reason, tool_turn),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "turns={} | adaptive_budget={}",
                                tool_turn, tool_loop_budget.current_cap
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                        break;
                    }
                    match run_timed_llm_call_with_heartbeat(
                        &selected_llm,
                        &system_prompt,
                        if skipped_due_to_request_latch {
                            "A persistent automation or object was already created or updated in this request. Do not create another one. Continue with validation, inspection, or the final user-facing status only."
                        } else {
                            "Do not repeat the same tool calls. Continue with the next distinct step."
                        },
                        &tool_loop_history,
                        &relevant_memories,
                        &available_actions,
                        token_tx.clone(),
                        TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                        "Continuing after duplicate-tool suppression",
                        true,
                        "llm",
                    )
                    .await
                    {
                        TimedLlmCallOutcome::Success(next_response) => {
                            self.record_llm_usage(channel, "chat_tool_followup", &next_response)
                                .await;
                            llm_response = next_response;
                            continue;
                        }
                        TimedLlmCallOutcome::Error(_)
                        | TimedLlmCallOutcome::TimedOut => {
                            response = build_user_facing_tool_fallback_response(
                                &tool_batch.combined_output(),
                                &tool_batch,
                                "I skipped repeated duplicate actions and returned the latest tool-backed response.",
                            );
                            break;
                        }
                    }
                }
                let incomplete_existing_app_edit = execution_intent
                    && recent_artifact_prompt_context
                        .as_ref()
                        .map(|ctx| ctx.artifact_type.eq_ignore_ascii_case("app"))
                        .unwrap_or(false)
                    && tool_batch_indicates_incomplete_existing_app_edit(&cumulative_tool_batch)
                    && (llm_response.content.trim().is_empty()
                        || response_is_meta_tool_summary(&llm_response.content)
                        || response_indicates_pending_execution(&llm_response.content)
                        || looks_like_raw_structured_tool_output(&llm_response.content)
                        || looks_like_raw_source_or_markup_dump(&llm_response.content));

                if execution_intent
                    && tool_loop_budget
                        .stop_reason_for_completed_turns(tool_turn)
                        .is_none()
                    && (response_indicates_pending_execution(&llm_response.content)
                        || response_is_meta_tool_summary(&llm_response.content)
                        || incomplete_existing_app_edit)
                {
                    let assistant_message = safe_truncate(llm_response.content.trim(), 3000);
                    if !assistant_message.is_empty() {
                        tool_loop_history.push(ConversationMessage {
                            role: "assistant".to_string(),
                            content: assistant_message,
                            _timestamp: chrono::Utc::now(),
                        });
                    }
                    tool_loop_history.push(ConversationMessage {
                        role: "user".to_string(),
                        content: if incomplete_existing_app_edit {
                            "Continue executing the request now. You have only inspected the existing deployed app so far. Inspection alone is not completion for this request. Apply the requested change to the app with the needed edit/restart actions, or explain concretely why no change is required if the work is already complete.".to_string()
                        } else {
                            "Continue executing the request now. Do not stop at a diagnosis, plan, or promise of future work. Either call the next tool(s) or report the completed result if the work is already done.".to_string()
                        },
                        _timestamp: chrono::Utc::now(),
                    });
                    let continuation_start = std::time::Instant::now();
                    match run_timed_llm_call_with_heartbeat(
                        &selected_llm,
                        &system_prompt,
                        if incomplete_existing_app_edit {
                            "Continue executing the deployed-app update now. Do not stop after inspection alone."
                        } else {
                            "Continue executing the request now."
                        },
                        &tool_loop_history,
                        &relevant_memories,
                        &available_actions,
                        token_tx.clone(),
                        TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                        "Continuing execution after inspection",
                        true,
                        "llm",
                    )
                    .await
                    {
                        TimedLlmCallOutcome::Success(next_response) => {
                            self.record_llm_usage(
                                channel,
                                "chat_execution_continuation",
                                &next_response,
                            )
                            .await;
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[loop]".to_string(),
                                title: "Execution Continuation Nudge".to_string(),
                                detail: format!(
                                    "Prompted the model to continue execution after a prose-only or meta-only turn ({}ms).",
                                    continuation_start.elapsed().as_millis()
                                ),
                                step_type: "info".to_string(),
                                data: Some(format!(
                                    "response_chars={}, tool_calls={}",
                                    next_response.content.chars().count(),
                                    next_response.tool_calls.len()
                                )),
                                timestamp: chrono::Utc::now(),
                                duration_ms: Some(
                                    continuation_start.elapsed().as_millis() as u64,
                                ),
                            });
                            llm_response = next_response;
                            tool_turn += 1;
                            continue;
                        }
                        TimedLlmCallOutcome::Error(e) => {
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[warn]".to_string(),
                                title: "Execution Continuation Failed".to_string(),
                                detail: "Fell back to the latest assistant response after the continuation nudge failed."
                                    .to_string(),
                                step_type: "warning".to_string(),
                                data: Some(safe_truncate(&e.to_string(), 500)),
                                timestamp: chrono::Utc::now(),
                                duration_ms: Some(
                                    continuation_start.elapsed().as_millis() as u64,
                                ),
                            });
                        }
                        TimedLlmCallOutcome::TimedOut => {
                            let mut trace = trace_ref.write().await;
                            trace.steps.push(ExecutionStep {
                                icon: "[warn]".to_string(),
                                title: "Execution Continuation Timed Out".to_string(),
                                detail: format!(
                                    "Stopped waiting for an internal continuation response after {} seconds.",
                                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                                ),
                                step_type: "warning".to_string(),
                                data: Some(format!(
                                    "model={} | timeout_secs={}",
                                    selected_llm.model_name(),
                                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                                )),
                                timestamp: chrono::Utc::now(),
                                duration_ms: Some(
                                    continuation_start.elapsed().as_millis() as u64,
                                ),
                            });
                        }
                    }
                }
                if !llm_response.content.trim().is_empty() {
                    response = llm_response.content.clone();
                }
                break;
            }

            tracing::info!(
                "Tool calls requested: {}",
                tool_calls
                    .iter()
                    .map(|c| c.name.as_str())
                    .collect::<Vec<_>>()
                    .join(", ")
            );
            {
                let mut trace = trace_ref.write().await;
                for call in &tool_calls {
                    let (detail, data) = if call.name.eq_ignore_ascii_case("moltbook") {
                        build_moltbook_trace_request_detail(
                            call.arguments
                                .get("action")
                                .and_then(|v| v.as_str())
                                .unwrap_or("default"),
                            &call.arguments,
                        )
                    } else {
                        (
                            "Running in sandboxed environment".to_string(),
                            Some(format!(
                                "Args: {}",
                                serde_json::to_string(&call.arguments).unwrap_or_default()
                            )),
                        )
                    };
                    trace.steps.push(ExecutionStep {
                        icon: "[run]".to_string(),
                        title: format!("Executing Action: {}", call.name),
                        detail,
                        step_type: "thinking".to_string(),
                        data,
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                }
            }

            let prior_executed_tool_calls = all_executed_tool_calls.clone();
            all_executed_tool_calls.extend(tool_calls.clone());

            for call in &tool_calls {
                update_execution_plan_for_tool_start(&trace_ref, token_tx.as_ref(), &call.name)
                    .await;
            }

            let tool_start = std::time::Instant::now();
            self.advance_execution_run(
                &mut execution_run,
                &mut execution_checkpoint_seq,
                crate::core::ExecutionRunStatus::ToolDispatch,
                serde_json::json!({
                    "tool_count": tool_calls.len(),
                    "tools": tool_calls.iter().map(|call| call.name.clone()).collect::<Vec<_>>(),
                }),
            )
            .await;
            let mut execution_response = llm_response.clone();
            execution_response.tool_calls = tool_calls.clone();
            let tool_batch = match self
                .execute_tool_calls(
                    &execution_response,
                    &trace_ref,
                    token_tx.clone(),
                    tool_execution::ToolExecutionContext {
                        request_channel: channel,
                        current_turn_is_explicit_approval,
                        trace_id: Some(&trace_id),
                        conversation_id: Some(&conversation_key),
                        project_id,
                        strategy_version: strategy_version.as_deref(),
                        policy_version: Some(policy_version.as_str()),
                        prompt_version: Some(prompt_version.as_str()),
                        model_slot: Some(effective_model_slot_label.as_str()),
                    },
                )
                .await
            {
                Ok(batch) => batch,
                Err(err) => {
                    let error_text = format!("Tool execution failed: {}", err);
                    degradation_notes.push(crate::core::DegradationNote {
                        kind: "tool_dispatch".to_string(),
                        summary: "tool execution failed".to_string(),
                        detail: Some(error_text.clone()),
                    });
                    execution_run.attempted_models = attempted_models.clone();
                    self.finalize_execution_run(
                        &mut execution_run,
                        &mut execution_checkpoint_seq,
                        crate::core::ExecutionRunStatus::PlatformFailed,
                        &error_text,
                        Some(&error_text),
                        &degradation_notes,
                    )
                    .await;
                    self.persist_learning_experience(
                        &execution_run,
                        message,
                        channel,
                        Some(&conversation_key),
                        project_id,
                        Some(prompt_version.as_str()),
                        strategy_version.as_deref(),
                        Some(policy_version.as_str()),
                        Some(effective_model_slot_label.as_str()),
                    )
                    .await;
                    self.finalize_failed_trace(
                        &trace_ref,
                        "Tool Execution Failed",
                        &error_text,
                        None,
                    )
                    .await;
                    return Err(err);
                }
            };
            let tool_output_text = tool_batch.combined_output();
            degradation_notes.extend(tool_batch.degradation_notes());
            cumulative_tool_batch
                .outputs
                .extend(tool_batch.outputs.clone());
            for (index, (call, outcome)) in tool_calls
                .iter()
                .zip(tool_batch.outcomes.iter())
                .enumerate()
            {
                let tool_attempt = crate::core::ToolAttempt {
                    id: uuid::Uuid::new_v4().to_string(),
                    run_id: execution_run.id.clone(),
                    sequence_no: tool_attempt_sequence + (index as u32),
                    tool_name: call.name.clone(),
                    status: outcome.status.clone(),
                    failure_class: outcome.failure_class.clone(),
                    retryable: outcome.retryable,
                    side_effect_level: outcome.side_effect_level.clone(),
                    idempotency_key: Some(Self::tool_call_signature(call)),
                    arguments_json: call.arguments.to_string(),
                    output_json: serde_json::json!({
                        "content": outcome.content,
                        "error": outcome.error,
                    })
                    .to_string(),
                    started_at: chrono::Utc::now().to_rfc3339(),
                    completed_at: Some(chrono::Utc::now().to_rfc3339()),
                    error_text: outcome.error.clone(),
                };
                if let Err(error) = self.storage.append_tool_attempt(&tool_attempt).await {
                    tracing::warn!(
                        "Failed to persist tool attempt '{}' for run '{}': {}",
                        tool_attempt.tool_name,
                        tool_attempt.run_id,
                        error
                    );
                }
            }
            tool_attempt_sequence =
                tool_attempt_sequence.saturating_add(tool_batch.outcomes.len() as u32);
            for (call, output) in tool_calls.iter().zip(tool_batch.outputs.iter()) {
                update_execution_plan_for_tool_result(
                    &trace_ref,
                    token_tx.as_ref(),
                    &call.name,
                    tool_output_looks_successful(&output.content),
                )
                .await;
                if should_suppress_duplicate_tool_call_within_request(
                    call,
                    &duplicate_suppression_actions,
                ) || tool_result_indicates_fatal_environment_mismatch(&output.content)
                {
                    prior_request_scoped_tool_results
                        .insert(Self::tool_call_signature(call), output.content.clone());
                }
                if let Some(request_latch_key) =
                    tool_call_request_latch_key(call, &request_latched_actions)
                {
                    if tool_output_looks_successful(&output.content) {
                        request_scoped_latched_results
                            .insert(request_latch_key, output.content.clone());
                    }
                }
            }
            for output in &tool_batch.outputs {
                if tool_output_contains_embedded_result_marker(&output.content) {
                    preserved_tool_outputs.push(output.content.clone());
                }
            }
            self.persist_recent_artifact_from_tool_batch(
                &conversation_key,
                &tool_batch,
                &all_actions,
            )
            .await;
            let fallback_response = if llm_response.content.trim().is_empty() {
                tool_output_text.clone()
            } else if tool_output_text.trim().is_empty() {
                llm_response.content.clone()
            } else {
                format!("{}\n\n{}", llm_response.content, tool_output_text)
            };
            let safe_fallback_response = build_user_facing_tool_fallback_response(
                &fallback_response,
                &tool_batch,
                "I gathered tool evidence, but the final response could not be formatted cleanly.",
            );
            tracing::info!(
                "Tool execution done ({}ms), output={}chars",
                tool_start.elapsed().as_millis(),
                fallback_response.len()
            );
            let fatal_environment_mismatch = tool_batch
                .outputs
                .iter()
                .any(|output| tool_result_indicates_fatal_environment_mismatch(&output.content));
            if fatal_environment_mismatch {
                response = safe_fallback_response.clone();
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[stop]".to_string(),
                    title: "Fatal Environment Mismatch".to_string(),
                    detail:
                        "Stopped the follow-up LLM loop because tool output reported a runtime environment mismatch that the model cannot repair from chat alone."
                            .to_string(),
                    step_type: "warning".to_string(),
                    data: Some(safe_truncate(&safe_fallback_response, 500)),
                    timestamp: chrono::Utc::now(),
                    duration_ms: Some(tool_start.elapsed().as_millis() as u64),
                });
                break;
            }
            let assistant_history_message = build_tool_followup_assistant_message(&llm_response);
            if !assistant_history_message.is_empty() {
                tool_loop_history.push(ConversationMessage {
                    role: "assistant".to_string(),
                    content: assistant_history_message,
                    _timestamp: chrono::Utc::now(),
                });
            }

            let wrote_new_app_files =
                tool_calls
                    .iter()
                    .zip(tool_batch.outputs.iter())
                    .any(|(call, output)| {
                        call.name == "file_write" && tool_output_looks_successful(&output.content)
                    });
            let already_attempted_valid_app_deploy = prior_executed_tool_calls
                .iter()
                .chain(tool_calls.iter())
                .any(|call| {
                    call.name == "app_deploy" && !app_deploy_files_missing(&call.arguments)
                });
            let read_only_app_detour = !tool_calls.is_empty()
                && tool_calls.iter().all(|call| {
                    matches!(
                        call.name.as_str(),
                        "file_read"
                            | "app_inspect"
                            | "manage_actions"
                            | "list_integrations"
                            | "http_get"
                            | "page_screenshot"
                    )
                });
            if app_deploy_intent
                && !already_attempted_valid_app_deploy
                && (wrote_new_app_files || read_only_app_detour)
            {
                if let Some(mut recovered_deploy_call) =
                    synthesize_missing_app_deploy_tool_call_from_recent_writes(
                        &tool_calls,
                        &prior_executed_tool_calls,
                    )
                {
                    if let Some(args) = recovered_deploy_call.arguments.as_object_mut() {
                        args.entry("conversation_id".to_string())
                            .or_insert_with(|| serde_json::json!(conversation_key.clone()));
                    }
                    let recovered_title = recovered_deploy_call
                        .arguments
                        .get("title")
                        .and_then(|value| value.as_str())
                        .unwrap_or("App")
                        .to_string();
                    let recovered_file_count = recovered_deploy_call
                        .arguments
                        .get("files")
                        .and_then(|value| value.as_object())
                        .map(|files| files.len())
                        .unwrap_or(0);
                    {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[fix]".to_string(),
                            title: "Recovered Missing Deploy Step".to_string(),
                            detail: format!(
                                "Synthesized app_deploy from {} recent file write{} for {}.",
                                recovered_file_count,
                                if recovered_file_count == 1 { "" } else { "s" },
                                recovered_title
                            ),
                            step_type: "info".to_string(),
                            data: None,
                            timestamp: chrono::Utc::now(),
                            duration_ms: None,
                        });
                    }
                    if let Some(tx) = token_tx.as_ref() {
                        let _ = tx.try_send(StreamEvent::ToolProgress {
                            name: "app_deploy".to_string(),
                            content: if read_only_app_detour {
                                format!(
                                    "Detected deployable app files after a read-only detour. Recovering deployment from {} recent file write{}.",
                                    recovered_file_count,
                                    if recovered_file_count == 1 { "" } else { "s" }
                                )
                            } else {
                                format!(
                                    "Recovered deployment from {} recent file write{}.",
                                    recovered_file_count,
                                    if recovered_file_count == 1 { "" } else { "s" }
                                )
                            },
                            payload: None,
                        });
                    }
                    llm_response = crate::core::llm::LlmResponse {
                        content: format!(
                            "Continue by deploying the generated app files for {}.",
                            recovered_title
                        ),
                        tool_calls: vec![recovered_deploy_call],
                        reasoning: None,
                        usage: None,
                        provider: llm_response.provider.clone(),
                        model: llm_response.model.clone(),
                    };
                    continue;
                }
            }

            let tool_results_for_followup = format_tool_results_for_followup(&tool_batch);
            if tool_results_for_followup.is_empty() {
                response = safe_fallback_response.clone();
                break;
            }
            let persistent_creation_guidance = tool_calls
                .iter()
                .zip(tool_batch.outputs.iter())
                .any(|(call, output)| {
                    tool_call_request_latch_key(call, &request_latched_actions).is_some()
                        && tool_output_looks_successful(&output.content)
                });
            tool_loop_history.push(ConversationMessage {
                role: "user".to_string(),
                content: build_tool_followup_user_message(
                    message,
                    &tool_results_for_followup,
                    execution_intent,
                    if persistent_creation_guidance {
                        Some(persistent_creation_followup_rules())
                    } else {
                        None
                    },
                ),
                _timestamp: chrono::Utc::now(),
            });
            if persistent_creation_guidance {
                let synthesis_start = std::time::Instant::now();
                match run_timed_llm_call_with_heartbeat(
                    &selected_llm,
                    &system_prompt,
                    "A persistent automation or object was successfully created or updated in this turn. Do not call any more tools. Write the final user-facing status now, including what was created or updated, its current status or id, and any important caveats.",
                    &tool_loop_history,
                    &relevant_memories,
                    &[],
                    token_tx.clone(),
                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                    "Writing persistent-object completion status",
                    true,
                    "llm",
                )
                .await
                {
                    TimedLlmCallOutcome::Success(synthesized) => {
                        self.record_llm_usage(
                            channel,
                            "chat_persistent_creation_completion",
                            &synthesized,
                        )
                        .await;
                        if !synthesized.content.trim().is_empty() {
                            response = sanitize_final_user_response(&synthesized.content);
                        } else {
                            response = safe_fallback_response.clone();
                        }
                    }
                    TimedLlmCallOutcome::Error(_) | TimedLlmCallOutcome::TimedOut => {
                        response = safe_fallback_response.clone();
                    }
                }
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[stop]".to_string(),
                    title: "Persistent Creation Completed".to_string(),
                    detail: "Stopped the tool loop after a successful persistent create/update action and switched directly to final status synthesis."
                        .to_string(),
                    step_type: "success".to_string(),
                    data: Some(format!(
                        "synthesis_ms={} | tools={}",
                        synthesis_start.elapsed().as_millis(),
                        tool_calls
                            .iter()
                            .filter(|call| {
                                tool_call_request_latch_key(call, &request_latched_actions)
                                    .is_some()
                            })
                            .map(|call| call.name.clone())
                            .collect::<Vec<_>>()
                            .join(", ")
                    )),
                    timestamp: chrono::Utc::now(),
                    duration_ms: Some(synthesis_start.elapsed().as_millis() as u64),
                });
                break;
            }

            {
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[think]".to_string(),
                    title: "Reasoning From Tool Results".to_string(),
                    detail: "Model is deciding the next step after completed tool calls."
                        .to_string(),
                    step_type: "thinking".to_string(),
                    data: Some(format!(
                        "turn={}, outputs={}",
                        tool_turn + 1,
                        tool_batch.outputs.len()
                    )),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
            }
            if let Some(tx) = token_tx.as_ref() {
                let _ = tx.try_send(StreamEvent::ToolProgress {
                    name: "llm".to_string(),
                    content: format!(
                        "Reasoning from tool results with {}.",
                        selected_llm.model_name()
                    ),
                    payload: Some(serde_json::json!({
                        "kind": "tool_followup",
                        "model": selected_llm.model_name(),
                        "turn": tool_turn + 1,
                        "outputs": tool_batch.outputs.len(),
                    })),
                });
            }

            let round_progress = tool_loop_budget.observe_executed_round(&tool_calls, &tool_batch);
            if let Some(stop_reason) =
                tool_loop_budget.stop_reason_for_completed_turns(tool_turn + 1)
            {
                response = safe_fallback_response.clone();
                let synthesis_start = std::time::Instant::now();
                match run_timed_llm_call_with_heartbeat(
                    &selected_llm,
                    &system_prompt,
                    "Stop using tools. Based only on the gathered tool results, write the final user-facing answer now. If the work is already complete, summarize what was completed, where to find the result, and any important caveats in plain language. Only use diagnosis/root-cause/next-fix framing when the task is still blocked, broken, or incomplete. Do not dump raw tool output or code.",
                    &tool_loop_history,
                    &relevant_memories,
                    &[],
                    token_tx.clone(),
                    TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                    "Writing final answer from tool results",
                    true,
                    "llm",
                )
                .await
                {
                    TimedLlmCallOutcome::Success(synthesized) => {
                        self.record_llm_usage(channel, "chat_tool_synthesis", &synthesized)
                            .await;
                        if !synthesized.content.trim().is_empty() {
                            response = sanitize_final_user_response(&synthesized.content);
                        }
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stop]".to_string(),
                            title: ToolLoopBudgetState::stop_title(stop_reason).to_string(),
                            detail: tool_loop_budget.stop_detail(stop_reason, tool_turn + 1),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "synthesis_ms={} | new_signatures={} | new_outputs={} | successful_outputs={} | adaptive_budget={}",
                                synthesis_start.elapsed().as_millis(),
                                round_progress.new_signatures,
                                round_progress.new_output_fingerprints,
                                round_progress.successful_outputs,
                                tool_loop_budget.current_cap
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(synthesis_start.elapsed().as_millis() as u64),
                        });
                    }
                    TimedLlmCallOutcome::Error(e) => {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stop]".to_string(),
                            title: ToolLoopBudgetState::stop_title(stop_reason).to_string(),
                            detail: format!(
                                "{} Returned the latest tool-backed response because synthesis failed.",
                                tool_loop_budget.stop_detail(stop_reason, tool_turn + 1)
                            ),
                            step_type: "warning".to_string(),
                            data: Some(safe_truncate(&e.to_string(), 500)),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(synthesis_start.elapsed().as_millis() as u64),
                        });
                    }
                    TimedLlmCallOutcome::TimedOut => {
                        let mut trace = trace_ref.write().await;
                        trace.steps.push(ExecutionStep {
                            icon: "[stop]".to_string(),
                            title: "Tool Loop Synthesis Timed Out".to_string(),
                            detail: format!(
                                "Stopped waiting for synthesis after {} seconds and returned the latest tool-backed response.",
                                TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                            ),
                            step_type: "warning".to_string(),
                            data: Some(format!(
                                "model={} | timeout_secs={}",
                                selected_llm.model_name(),
                                TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                            )),
                            timestamp: chrono::Utc::now(),
                            duration_ms: Some(synthesis_start.elapsed().as_millis() as u64),
                        });
                    }
                }
                break;
            }

            let followup_start = std::time::Instant::now();
            match run_timed_llm_call_with_heartbeat(
                &selected_llm,
                &system_prompt,
                "Continue with the next step.",
                &tool_loop_history,
                &relevant_memories,
                &available_actions,
                token_tx.clone(),
                TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                "Reasoning from tool results",
                true,
                "llm",
            )
            .await
            {
                TimedLlmCallOutcome::Success(next_response) => {
                    let mut next_response = next_response;
                    self.record_llm_usage(channel, "chat_tool_followup", &next_response)
                        .await;
                    if next_response.tool_calls.is_empty()
                        && (looks_like_raw_structured_tool_output(&next_response.content)
                            || looks_like_raw_source_or_markup_dump(&next_response.content))
                    {
                        let synthesis_start = std::time::Instant::now();
                        match run_timed_llm_call_with_heartbeat(
                            &selected_llm,
                            &system_prompt,
                            "Write the final user-facing answer now. Do not emit tool calls. Do not dump raw JSON, HTML, or source code. Preserve any `[IMAGE_RESULT]` or `[VIDEO_RESULT]` blocks verbatim if present.",
                            &tool_loop_history,
                            &relevant_memories,
                            &[],
                            token_tx.clone(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS,
                            "Rewriting raw tool output",
                            true,
                            "llm",
                        )
                        .await
                        {
                            TimedLlmCallOutcome::Success(synthesized) => {
                                self.record_llm_usage(channel, "chat_tool_synthesis", &synthesized)
                                    .await;
                                  let mut trace = trace_ref.write().await;
                                  trace.steps.push(ExecutionStep {
                                      icon: "[refine]".to_string(),
                                      title: "Raw Tool Output Synthesized".to_string(),
                                      detail: format!(
                                          "Rewrote raw tool payload into a user-facing answer in {}ms.",
                                          synthesis_start.elapsed().as_millis()
                                      ),
                                    step_type: "info".to_string(),
                                    data: Some(format!(
                                        "raw_response_chars={}",
                                        next_response.content.chars().count()
                                    )),
                                    timestamp: chrono::Utc::now(),
                                    duration_ms: Some(
                                        synthesis_start.elapsed().as_millis() as u64,
                                    ),
                                });
                                next_response.content =
                                    sanitize_final_user_response(&synthesized.content);
                                next_response.tool_calls = synthesized.tool_calls;
                                next_response.reasoning = synthesized.reasoning;
                                next_response.usage = synthesized.usage;
                                next_response.provider = synthesized.provider;
                                next_response.model = synthesized.model;
                            }
                            TimedLlmCallOutcome::Error(e) => {
                                let mut trace = trace_ref.write().await;
                                trace.steps.push(ExecutionStep {
                                    icon: "[warn]".to_string(),
                                    title: "Structured Output Synthesis Failed".to_string(),
                                    detail:
                                        "Keeping the follow-up response because the synthesis-only pass failed."
                                            .to_string(),
                                    step_type: "warning".to_string(),
                                    data: Some(safe_truncate(&e.to_string(), 500)),
                                    timestamp: chrono::Utc::now(),
                                    duration_ms: Some(
                                        synthesis_start.elapsed().as_millis() as u64,
                                    ),
                                });
                            }
                            TimedLlmCallOutcome::TimedOut => {
                                let mut trace = trace_ref.write().await;
                                trace.steps.push(ExecutionStep {
                                    icon: "[warn]".to_string(),
                                    title: "Structured Output Synthesis Timed Out".to_string(),
                                    detail:
                                        "Kept the current follow-up response after the rewrite pass timed out."
                                            .to_string(),
                                    step_type: "warning".to_string(),
                                    data: Some(format!(
                                        "model={} | timeout_secs={}",
                                        selected_llm.model_name(),
                                        TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                                    )),
                                    timestamp: chrono::Utc::now(),
                                    duration_ms: Some(
                                        synthesis_start.elapsed().as_millis() as u64,
                                    ),
                                });
                            }
                        }
                        if next_response.tool_calls.is_empty()
                            && (looks_like_raw_structured_tool_output(&next_response.content)
                                || looks_like_raw_source_or_markup_dump(&next_response.content))
                        {
                            next_response.content = safe_fallback_response.clone();
                        }
                    }
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[loop]".to_string(),
                        title: "Tool Follow-up Reasoning".to_string(),
                        detail: format!(
                            "Follow-up turn {} completed in {}ms ({} tool calls).",
                            tool_turn + 1,
                            followup_start.elapsed().as_millis(),
                            next_response.tool_calls.len()
                        ),
                        step_type: "info".to_string(),
                        data: Some(format!(
                            "response_chars={}",
                            next_response.content.chars().count()
                        )),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                    llm_response = next_response;
                    tool_turn += 1;
                }
                TimedLlmCallOutcome::Error(e) => {
                    response = safe_fallback_response.clone();
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[warn]".to_string(),
                        title: "Tool Follow-up Failed".to_string(),
                        detail:
                            "Fell back to the latest tool-backed response after a follow-up model error."
                                .to_string(),
                        step_type: "warning".to_string(),
                        data: Some(safe_truncate(&e.to_string(), 500)),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                    break;
                }
                TimedLlmCallOutcome::TimedOut => {
                    response = build_user_facing_tool_fallback_response(
                        &tool_batch.combined_output(),
                        &tool_batch,
                        "I inspected the latest tool results, but the follow-up model timed out before it could finish the answer. Here is the latest tool-backed status. If this keeps happening on larger repair tasks, retrying with a stronger model may help.",
                    );
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[warn]".to_string(),
                        title: "Tool Follow-up Timed Out".to_string(),
                        detail: format!(
                            "Stopped waiting for the next-step model turn after {} seconds and returned the latest tool-backed response.",
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                        ),
                        step_type: "warning".to_string(),
                        data: Some(format!(
                            "model={} | turn={} | outputs={} | timeout_secs={}",
                            selected_llm.model_name(),
                            tool_turn + 1,
                            tool_batch.outputs.len(),
                            TOOL_FOLLOWUP_LLM_TIMEOUT_SECS
                        )),
                        timestamp: chrono::Utc::now(),
                        duration_ms: Some(followup_start.elapsed().as_millis() as u64),
                    });
                    break;
                }
            }
        }

        response = sanitize_final_user_response(&response);
        if let Some(summary) =
            maybe_override_with_app_deploy_success_response(&response, &cumulative_tool_batch)
        {
            response = summary;
        }
        append_preserved_tool_outputs(&mut response, &preserved_tool_outputs);
        if let Some(nudge) = profile_nudge.as_ref() {
            response.push_str("\n\n");
            response.push_str(nudge);
        }
        response = sanitize_final_user_response(&response);
        degradation_notes.extend(cumulative_tool_batch.degradation_notes());

        // 7. Generate execution proof
        let filtered_response = self.security.filter_output(&response);
        if !filtered_response.redactions.is_empty() {
            tracing::warn!(
                "Security: redacted sensitive data from output before persistence: {:?}",
                filtered_response.redactions
            );
        }
        response = filtered_response.text;

        let _persisted_proof_id = match self.proofs.generate_proof(
            message,
            &response,
            &all_executed_tool_calls,
        ) {
            Ok(proof) => {
                tracing::debug!("Execution proof: {}", proof.id);
                let persisted_id = match self.storage.insert_execution_proof(&proof).await {
                    Ok(()) => Some(proof.id.to_string()),
                    Err(err) => {
                        tracing::warn!("Failed to persist execution proof '{}': {}", proof.id, err);
                        degradation_notes.push(crate::core::DegradationNote {
                            kind: "post_process_failure".to_string(),
                            summary:
                                "Execution completed but the proof record could not be persisted."
                                    .to_string(),
                            detail: Some(err.to_string()),
                        });
                        None
                    }
                };

                {
                    let mut trace = trace_ref.write().await;
                    trace.steps.push(ExecutionStep {
                        icon: "[proof]".to_string(),
                        title: "Execution Record Saved".to_string(),
                        detail: format!("Verification ID: {}", proof.id),
                        step_type: "success".to_string(),
                        data: Some(format!(
                            "This signed record is tied to the run input, output, and tool actions.\nOpen Trace Detail to review the human-readable evidence for this run.\nSigner: {}...",
                            &self.identity.did()[..30.min(self.identity.did().len())]
                        )),
                        timestamp: chrono::Utc::now(),
                        duration_ms: None,
                    });
                    trace.proof_id = persisted_id.clone();
                }

                persisted_id
            }
            Err(err) => {
                let error_text = format!("Execution proof generation failed: {}", err);
                degradation_notes.push(crate::core::DegradationNote {
                    kind: "post_process_failure".to_string(),
                    summary: "execution proof generation failed".to_string(),
                    detail: Some(error_text.clone()),
                });
                let mut trace = trace_ref.write().await;
                trace.steps.push(ExecutionStep {
                    icon: "[warn]".to_string(),
                    title: "Execution Proof Skipped".to_string(),
                    detail:
                        "The run completed, but proof generation failed and was downgraded to a warning."
                            .to_string(),
                    step_type: "warning".to_string(),
                    data: Some(safe_truncate(&error_text, 500)),
                    timestamp: chrono::Utc::now(),
                    duration_ms: None,
                });
                trace.proof_id = None;
                None
            }
        };

        // 9. Mem0 memory extraction via durable retry queue.
        if self.config.mem0.enabled {
            self.enqueue_mem0_retry_item(message, &response, &mem0_scope)
                .await;
            let drained = if self.mem0.is_available() {
                self.flush_mem0_retry_queue(1).await
            } else {
                0
            };
            if drained == 0 {
                tracing::debug!("Mem0: queued exchange; will retry via background drain");
            }
        }

        // 10. Add assistant response to conversation history
        {
            let mut history = self.conversation_history.write().await;
            if let Some(conversation_history) = history.get_mut(&conversation_key) {
                conversation_history.push(ConversationMessage {
                    role: "assistant".to_string(),
                    content: response.clone(),
                    _timestamp: chrono::Utc::now(),
                });
            }
        }

        // Finalize trace before persisting messages that reference it.
        {
            let mut trace = trace_ref.write().await;
            let end_time = chrono::Utc::now();
            let total_duration = if let Some(start) = trace.started_at {
                (end_time - start).num_milliseconds() as u64
            } else {
                0
            };
            let marked_failed =
                mark_execution_plan_failed_from_tool_batch(&mut trace, &cumulative_tool_batch);
            if !marked_failed {
                mark_execution_plan_completed(&mut trace);
            }
            trace.completed_at = Some(end_time);
            trace.response = Some(response.clone());
            trace.steps.push(ExecutionStep {
                icon: "[ok]".to_string(),
                title: "Response Complete".to_string(),
                detail: format!(
                    "Total time: {}ms | Response: {} chars",
                    total_duration,
                    response.len()
                ),
                step_type: "success".to_string(),
                data: None,
                timestamp: end_time,
                duration_ms: Some(total_duration),
            });
        }
        self.persist_completed_trace(&trace_ref).await;

        // 11. Persist messages to database (chat persistence)
        let mut conversation_title: Option<String> = None;
        {
            let conv_id = conversation_key.clone();

            // Expose conversation ID for HTTP response
            *self.last_conversation_id.write().await = Some(conv_id.clone());
            *self.last_conversation_title.write().await = None;

            if !conv_id.is_empty() {
                // User message already persisted early (before LLM call) — only store assistant response here

                // Store assistant message
                let asst_msg = crate::storage::entities::message::Model {
                    id: uuid::Uuid::new_v4().to_string(),
                    conversation_id: conv_id.clone(),
                    role: "assistant".to_string(),
                    content: response.clone(),
                    timestamp: chrono::Utc::now().to_rfc3339(),
                    model_used: Some(effective_model_name.clone()),
                    trace_id: Some(trace_id.clone()),
                };
                if let Err(e) = self
                    .encrypted_storage
                    .insert_message_encrypted(&asst_msg)
                    .await
                {
                    tracing::warn!("Failed to persist assistant message: {}", e);
                }

                // Keep built-in episodic memory populated for fallback retrieval and consolidation.
                let episode_context = crate::memory::EpisodeContext {
                    channel: channel.to_string(),
                    timestamp: chrono::Utc::now(),
                    location: None,
                    participants: vec![],
                    project_id: project_id.map(|s| s.to_string()),
                };
                let episode_content = format!(
                    "User: {}\nAssistant: {}",
                    safe_truncate(&crate::security::redact_pii(message), 1200),
                    safe_truncate(&crate::security::redact_pii(&response), 1800),
                );
                if let Err(e) = self
                    .memory
                    .add_episode(episode_content, episode_context, 0.6, project_id)
                    .await
                {
                    tracing::warn!("Failed to store episodic memory fallback: {}", e);
                }

                // Auto-generate conversation title on first message using the LLM
                if is_new_conversation {
                    let title = self
                        .generate_conversation_title(channel, message, &response)
                        .await;
                    let _ = self
                        .storage
                        .update_conversation(&conv_id, Some(&title), Some(2), None)
                        .await;
                    *self.last_conversation_title.write().await = Some(title.clone());
                    conversation_title = Some(title);
                }
            }
        }

        let total_ms = (chrono::Utc::now() - start_time).num_milliseconds();
        tracing::info!(
            "Message processed: channel={}, total={}ms, response={}chars",
            channel,
            total_ms,
            response.len()
        );

        execution_run.attempted_models = attempted_models.clone();
        let user_outcome = if needs_clarification {
            self.execution_supervisor
                .build_clarification_outcome(&response, &attempt_records)
        } else if let Some(outcome) = self.build_response_heuristic_outcome(
            &response,
            &degradation_notes,
            &attempt_records,
            Some(&cumulative_tool_batch),
        ) {
            outcome
        } else {
            self.execution_supervisor.build_success_outcome(
                &response,
                &degradation_notes,
                &attempt_records,
            )
        };
        self.sync_pending_resilience_followup(
            &conversation_key,
            message,
            channel,
            project_id,
            &user_outcome,
        )
        .await;
        let terminal_run_status = Self::execution_run_status_for_outcome(&user_outcome);
        self.finalize_execution_run(
            &mut execution_run,
            &mut execution_checkpoint_seq,
            terminal_run_status.clone(),
            &response,
            None,
            &degradation_notes,
        )
        .await;
        self.persist_learning_experience(
            &execution_run,
            message,
            channel,
            Some(&conversation_key),
            project_id,
            Some(prompt_version.as_str()),
            strategy_version.as_deref(),
            Some(policy_version.as_str()),
            Some(effective_model_slot_label.as_str()),
        )
        .await;

        Ok(ProcessedMessage {
            response,
            conversation_id: Some(conversation_key),
            conversation_title,
            run_id: Some(execution_run.id),
            run_status: Some(terminal_run_status.as_str().to_string()),
            trace_id: Some(trace_id),
            degradation: degradation_notes,
            attempted_models,
            user_outcome: Some(user_outcome),
        })
    }

    async fn capture_user_memory_hints(
        &self,
        message: &str,
        channel: &str,
        conversation_id: Option<&str>,
        project_id: Option<&str>,
    ) {
        self.capture_user_links_as_user_data(message, channel, conversation_id, project_id)
            .await;
        self.capture_user_facts_as_memory(message, channel, conversation_id, project_id)
            .await;
        self.capture_user_facts_and_rules_with_llm(message, channel, conversation_id, project_id)
            .await;
    }

    async fn capture_user_links_as_user_data(
        &self,
        message: &str,
        channel: &str,
        conversation_id: Option<&str>,
        project_id: Option<&str>,
    ) {
        let urls = extract_http_urls(message);
        if urls.is_empty() {
            return;
        }
        for url in urls {
            if let Err(e) = self
                .storage
                .upsert_user_data_link(&url, Some(channel), conversation_id, project_id)
                .await
            {
                tracing::warn!(
                    "Failed to capture user link '{}' into user_data_items: {}",
                    url,
                    e
                );
            }
        }
    }

    async fn capture_user_facts_as_memory(
        &self,
        message: &str,
        channel: &str,
        _conversation_id: Option<&str>,
        _project_id: Option<&str>,
    ) {
        let mut facts = extract_stable_user_preferences(message);
        facts.extend(extract_explicit_user_identity_facts(message));
        if facts.is_empty() {
            return;
        }
        let mut seen = HashSet::new();
        for (key, value) in facts {
            if !seen.insert(key.clone()) {
                continue;
            }
            let confidence = if key == "user_name" { 0.98 } else { 0.92 };
            if let Err(e) = self
                .storage
                .upsert_user_preference(&key, &value, confidence, Some(channel), None)
                .await
            {
                tracing::warn!(
                    "Failed to capture user fact '{}' => '{}' into user_preferences: {}",
                    key,
                    value,
                    e
                );
            }
            if let Err(error) = crate::core::learning::sync_user_preference_to_experience_item(
                &self.storage,
                &key,
                &value,
                confidence as f64,
                "user_fact_fast_path",
            )
            .await
            {
                tracing::warn!(
                    "Failed to mirror user fact '{}' into experience graph: {}",
                    key,
                    error
                );
            }
        }
    }

    async fn capture_user_facts_and_rules_with_llm(
        &self,
        message: &str,
        channel: &str,
        conversation_id: Option<&str>,
        _project_id: Option<&str>,
    ) {
        let trimmed = message.trim();
        if trimmed.is_empty() || trimmed.chars().count() > 1_600 {
            return;
        }

        let recent_dialogue = if let Some(id) = conversation_id.filter(|id| !id.trim().is_empty()) {
            let history = self.recent_messages_for_intent_gating(id, trimmed).await;
            format_recent_dialogue_for_fast_path(&history).unwrap_or_else(|| "(none)".to_string())
        } else {
            "(none)".to_string()
        };

        let saved_facts = self
            .build_saved_user_facts_context(None)
            .await
            .unwrap_or_else(|| "## Saved User Facts\n(none)".to_string());

        let prompt = format!(
            "Recent dialogue:\n{recent_dialogue}\n\nUser message:\n{message}\n\nCurrent saved user facts:\n{saved_facts}\n\nReturn JSON only with this shape:\n{{\"facts\":[{{\"key\":\"snake_case_key\",\"value\":\"durable fact or rule value\",\"confidence\":0.95}}]}}\n\nRules:\n- Extract only durable user facts, stable preferences, workflow constraints, or operating rules worth remembering beyond this turn.\n- Do not capture one-off requests, temporary tasks, tool output, or transient errors.\n- Prefer stable snake_case keys.\n- For operating constraints, use explicit rule keys when supported by the message semantics. Examples:\n  - rule_require_explicit_approval_before_side_effects = true\n  - rule_show_plan_before_side_effects = true\n- It is okay to return an empty facts array.\n- Do not invent facts beyond the message, recent dialogue, or current saved facts.",
            recent_dialogue = recent_dialogue,
            message = trimmed,
            saved_facts = saved_facts
        );

        let learning_candidates = self.learning_llm_candidates().await;
        if learning_candidates.is_empty() {
            tracing::debug!(
                "Skipping user fact/rule LLM extraction because no learning-eligible model slot is available"
            );
            return;
        }

        let Some(resp) = self
            .supervised_internal_chat(
                channel,
                "user_fact_memory_capture",
                "user_fact_memory_capture",
                &ModelRole::Fast,
                learning_candidates,
                "You extract durable user facts and operating rules as strict JSON. Output JSON only.",
                &prompt,
                &[],
                &[],
                900,
                1,
            )
            .await
        else {
            return;
        };
        let Some(payload) = extract_json_object_from_text(&resp.content) else {
            return;
        };
        let Some(items) = payload.get("facts").and_then(|value| value.as_array()) else {
            return;
        };

        let mut seen = HashSet::new();
        for item in items {
            let Some(raw_key) = item.get("key").and_then(|value| value.as_str()) else {
                continue;
            };
            let Some(raw_value) = item.get("value").and_then(|value| value.as_str()) else {
                continue;
            };
            let Some(key) = normalize_user_fact_key(raw_key) else {
                continue;
            };
            let Some(value) = normalize_user_fact_value(raw_value) else {
                continue;
            };
            if !seen.insert((key.clone(), value.clone())) {
                continue;
            }
            let confidence = item
                .get("confidence")
                .and_then(|value| value.as_f64())
                .map(|value| value.clamp(0.0, 1.0) as f32)
                .unwrap_or_else(|| if key == "user_name" { 0.98 } else { 0.9 });
            if let Err(e) = self
                .storage
                .upsert_user_preference(&key, &value, confidence, Some(channel), None)
                .await
            {
                tracing::warn!(
                    "Failed to capture user fact/rule '{}' => '{}' into user_preferences: {}",
                    key,
                    value,
                    e
                );
            }
            if let Err(error) = crate::core::learning::sync_user_preference_to_experience_item(
                &self.storage,
                &key,
                &value,
                confidence as f64,
                "user_fact_memory_capture",
            )
            .await
            {
                tracing::warn!(
                    "Failed to mirror LLM user fact/rule '{}' into experience graph: {}",
                    key,
                    error
                );
            }
        }
    }

    async fn load_merged_user_preferences(
        &self,
        project_id: Option<&str>,
        limit: u64,
    ) -> Vec<crate::storage::entities::user_preference::Model> {
        let mut merged = self
            .storage
            .list_user_preferences(limit, 0, project_id)
            .await
            .unwrap_or_default();
        if project_id.is_none() {
            return merged;
        }

        let mut seen = merged
            .iter()
            .map(|pref| pref.key.clone())
            .collect::<HashSet<_>>();
        let global = self
            .storage
            .list_user_preferences(limit, 0, None)
            .await
            .unwrap_or_default();
        for pref in global {
            if seen.insert(pref.key.clone()) {
                merged.push(pref);
            }
        }
        merged
    }

    async fn backfill_identity_facts_from_recent_messages(
        &self,
    ) -> Vec<crate::storage::entities::user_preference::Model> {
        let recent_messages = self
            .encrypted_storage
            .get_recent_user_messages_decrypted(60)
            .await
            .unwrap_or_default();
        let mut discovered = Vec::new();
        let mut seen = HashSet::new();

        for message in recent_messages {
            for (key, value) in extract_explicit_user_identity_facts(&message.content) {
                if !seen.insert(key.clone()) {
                    continue;
                }
                match self
                    .storage
                    .upsert_user_preference(&key, &value, 0.96, Some("history_backfill"), None)
                    .await
                {
                    Ok(model) => {
                        discovered.push(model);
                        if let Err(error) =
                            crate::core::learning::sync_user_preference_to_experience_item(
                                &self.storage,
                                &key,
                                &value,
                                0.96_f64,
                                "history_backfill",
                            )
                            .await
                        {
                            tracing::warn!(
                                "Failed to mirror backfilled user fact '{}' into experience graph: {}",
                                key,
                                error
                            );
                        }
                    }
                    Err(e) => tracing::warn!(
                        "Failed to backfill user fact '{}' => '{}' from message history: {}",
                        key,
                        value,
                        e
                    ),
                }
            }
            if !discovered.is_empty() {
                break;
            }
        }

        discovered
    }

